function ScreenSession({ stage, onNavigate }: { stage: CareerStage; onNavigate?: (s: Screen) => void }) {
  const billing = useBillingCtx();
  const [avatarState, setAvatarState] = useState<AvatarState>("speaking");
  const [input, setInput] = useState("");
  const [isVoice, setIsVoice] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [elapsed, setElapsed] = useState(0);
  const [msgs, setMsgs] = useState<ChatMsg[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [sessionId, setSessionId] = useState<string | null>(null);
  const [sessionReady, setSessionReady] = useState(false);
  const [fileProcessing, setFileProcessing] = useState(false);
  const [showLiveMode, setShowLiveMode] = useState(false);
  const [sendError, setSendError] = useState<string | null>(null);
  const [lastFailedMsg, setLastFailedMsg] = useState<string | null>(null);
  const [startingNewChat, setStartingNewChat] = useState(false);
  const [pastSessions, setPastSessions] = useState<Array<{ id: string; title: string; startedAt: string; transcript: Array<{ role: string; message: string }> }>>([]);
  const [loadingHistory, setLoadingHistory] = useState(false);
  const [selectedHistory, setSelectedHistory] = useState<string | null>(null);
  const chatRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  async function loadHistory() {
    setLoadingHistory(true);
    try {
      const res = await fetch("/api/sessions", { cache: "no-store" });
      if (!res.ok) return;
      const data = await res.json().catch(() => ({})) as {
        sessions?: Array<{ id: string; title?: string; status: string; startedAt?: string; transcript?: Array<{ role: string; message: string }> }>;
      };
      const sessions = (data.sessions ?? []).filter(s => s.status === "complete" && (s.transcript ?? []).length > 0);
      setPastSessions(sessions.map(s => ({
        id: s.id,
        title: s.title ?? "Session",
        startedAt: s.startedAt ?? "",
        transcript: s.transcript ?? [],
      })));
    } catch { /* non-fatal */ } finally {
      setLoadingHistory(false);
    }
  }

  async function startNewChat() {
    if (isLoading || startingNewChat) return;
    setStartingNewChat(true);

    if (sessionId && msgs.length > 0) {
      try {
        await fetch(`/api/sessions/${sessionId}/complete`, { method: "POST" });
      } catch { /* non-fatal */ }
    }

    setSelectedHistory(null);
    setMsgs([]);
    setInput("");
    setSendError(null);
    setLastFailedMsg(null);
    setSessionReady(false);
    setAvatarState("thinking");

    let sid: string | null = null;
    try {
      const createRes = await fetch("/api/sessions", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ mode: "career", title: `${STAGE_META[stage].label} Session` }),
      });
      const created = await createRes.json().catch(() => ({})) as { id?: string };
      if (created.id) {
        sid = created.id;
        setSessionId(created.id);
      }
    } catch { /* non-fatal */ }

    try {
      await generateOpening(sid, () => false);
    } finally {
      await loadHistory();
      setStartingNewChat(false);
    }
  }

  async function startRecording() {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mimeType = MediaRecorder.isTypeSupported("audio/webm") ? "audio/webm" : "audio/ogg";
      const recorder = new MediaRecorder(stream, { mimeType });
      audioChunksRef.current = [];
      recorder.ondataavailable = e => { if (e.data.size > 0) audioChunksRef.current.push(e.data); };
      recorder.onstop = async () => {
        stream.getTracks().forEach(t => t.stop());
        const blob = new Blob(audioChunksRef.current, { type: mimeType });
        setIsRecording(false);
        if (blob.size < 1000) return;
        const form = new FormData();
        form.append("audio", blob);
        try {
          const res = await fetch("/api/zari/transcribe", { method: "POST", body: form });
          const data = await res.json().catch(() => ({})) as { text?: string };
          const text = (data.text ?? "").trim();
          if (text) void sendMessage(text);
        } catch { /* non-fatal */ }
      };
      recorder.start();
      mediaRecorderRef.current = recorder;
      setIsRecording(true);
    } catch { /* mic permission denied or unavailable */ }
  }

  function stopRecording() {
    mediaRecorderRef.current?.stop();
    mediaRecorderRef.current = null;
  }

  async function speakText(text: string) {
    if (!isVoice) return;
    try {
      if (audioRef.current) { audioRef.current.pause(); audioRef.current = null; }
      const res = await fetch("/api/zari/speak", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text }),
      });
      if (!res.ok) return;
      const blob = await res.blob();
      const url = URL.createObjectURL(blob);
      const audio = new Audio(url);
      audioRef.current = audio;
      audio.onended = () => URL.revokeObjectURL(url);
      void audio.play();
    } catch { /* non-fatal */ }
  }

  // Snapshot all section data from localStorage to give Zari full context
  function readSectionContext() {
    const ctx: Record<string, unknown> = {};

    try {
      const rs = localStorage.getItem("zari_resume_session_v2");
      if (rs) {
        const p = JSON.parse(rs) as {
          fileName?: string; resumeText?: string; reviewMode?: string;
          targetRoleInput?: string; careerLevel?: string;
          aiResult?: Record<string, unknown>;
        };
        ctx.resume = {
          fileName:       p.fileName,
          score:          (p.aiResult as {overall?: number})?.overall,
          ats:            (p.aiResult as {ats?: number})?.ats,
          impact:         (p.aiResult as {impact?: number})?.impact,
          clarity:        (p.aiResult as {clarity?: number})?.clarity,
          keyIssues:      ((p.aiResult as {bullets?: {before: string}[]})?.bullets ?? []).slice(0, 8).map(b => b.before),
          recommendation: (p.aiResult as {recommendation?: string})?.recommendation,
          excerpt:        p.resumeText?.slice(0, 1500),
          targetRole:     p.targetRoleInput,
          reviewMode:     p.reviewMode,
          careerLevel:    p.careerLevel,
        };
      }
    } catch { /* non-fatal */ }

    try {
      const vault = vaultRead();

      const liDoc = vault.filter(d => d.type === "linkedin").sort((a, b) => b.createdAt - a.createdAt)[0];
      if (liDoc) {
        ctx.linkedin = {
          name:       liDoc.name,
          score:      liDoc.meta.score ? Number(liDoc.meta.score) : undefined,
          headline:   liDoc.meta.headline,
          targetRole: liDoc.meta.targetRole,
          content:    liDoc.content.slice(0, 1500),
        };
      }

      const clDoc = vault.filter(d => d.type === "cover-letter").sort((a, b) => b.createdAt - a.createdAt)[0];
      if (clDoc) {
        ctx.coverLetter = {
          name:       clDoc.name,
          subject:    clDoc.meta.subject,
          targetRole: clDoc.meta.targetRole,
          company:    clDoc.meta.company,
          tone:       clDoc.meta.tone,
          content:    clDoc.content.slice(0, 1500),
        };
      }

      const uploads = vault.filter(d => d.type === "upload");
      if (uploads.length > 0) {
        ctx.uploads = uploads.map(d => ({ name: d.name, content: d.content.slice(0, 800) }));
      }
    } catch { /* non-fatal */ }

    return ctx;
  }

  const ERROR_PATTERNS = ["having trouble", "not fully set up", "try again in a moment", "connection issue"];

  /* ── Generate a dynamic, AI-powered opening message ── */
  async function generateOpening(sid: string | null, cancelled: () => boolean) {
    setIsLoading(true);
    setAvatarState("thinking");
    try {
      const res = await fetch("/api/zari/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: "__opening__",
          stage,
          history: [],
          sessionId: sid,
          sectionContext: readSectionContext(),
          isOpening: true,
        }),
      });
      const data = await res.json().catch(() => ({})) as { message?: string };
      const msg = data.message?.trim() ?? "";
      const isError = ERROR_PATTERNS.some(p => msg.toLowerCase().includes(p));
      if (!cancelled() && msg && !isError) {
        setMsgs([{ role: "coach", text: msg }]);
      }
      if (!cancelled()) {
        setAvatarState("speaking");
        setTimeout(() => setAvatarState("listening"), 3000);
      }
      if (!cancelled() && sid) void loadHistory();
    } catch {
      // Opening failed silently — user can still type
    } finally {
      if (!cancelled()) { setIsLoading(false); setSessionReady(true); }
    }
  }

  /* ── Load or create a live session on mount / stage change ── */
  useEffect(() => {
    setSessionReady(false);
    setMsgs([]);
    setElapsed(0);
    let dead = false;
    const cancelled = () => dead;

    async function initSession() {
      let sid: string | null = null;
      try {
        const res = await fetch("/api/sessions", { cache: "no-store" });
        const data = await res.json().catch(() => ({})) as {
          sessions?: Array<{
            id: string; status: string; mode: string;
            transcript?: Array<{ role: string; message: string }>;
          }>;
        };
        if (dead) return;
        const sessions = data.sessions ?? [];
        const live = sessions.find(s => s.status === "live");
        if (live) {
          sid = live.id;
          setSessionId(live.id);
          const transcript = (live.transcript ?? []).filter(t => {
            const txt = t.message?.trim() ?? "";
            return txt && !ERROR_PATTERNS.some(p => txt.toLowerCase().includes(p));
          });
          if (transcript.length > 0) {
            setMsgs(transcript.map(t => ({ role: t.role, text: t.message })));
            setSessionReady(true);
            setAvatarState("listening");
            return;
          }
        } else {
          const createRes = await fetch("/api/sessions", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ mode: "career", title: `${STAGE_META[stage].label} Session` }),
          });
          const created = await createRes.json().catch(() => ({})) as { id?: string };
          if (!dead && created.id) { sid = created.id; setSessionId(created.id); }
        }
      } catch { /* non-fatal */ }

      if (!dead) await generateOpening(sid, cancelled);
    }

    void initSession();
    return () => { dead = true; };
  }, [stage]); // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => { void loadHistory(); }, []); // eslint-disable-line react-hooks/exhaustive-deps
  useEffect(() => { const t = setInterval(() => setElapsed(e => e+1), 1000); return () => clearInterval(t); }, []);
  useEffect(() => { if (chatRef.current) chatRef.current.scrollTop = chatRef.current.scrollHeight; }, [msgs, isLoading]);

  const fmt = (s:number) => `${String(Math.floor(s/60)).padStart(2,"0")}:${String(s%60).padStart(2,"0")}`;

  async function sendMessage(
    text: string,
    opts?: { uploadedContent?: string; uploadedFileName?: string; skipUserMsg?: boolean; historyOverride?: ChatMsg[] }
  ) {
    const trimmed = text.trim();
    if (!trimmed || isLoading) return;

    let sid = sessionId;
    if (!sid) {
      try {
        const createRes = await fetch("/api/sessions", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ mode: "career", title: `${STAGE_META[stage].label} Session` }),
        });
        const created = await createRes.json().catch(() => ({})) as { id?: string };
        if (created.id) { sid = created.id; setSessionId(created.id); }
      } catch { /* non-fatal */ }
    }

    if (!opts?.skipUserMsg) {
      setMsgs(m => [...m, { role: "user", text: trimmed }]);
    }
    setInput("");
    setSendError(null);
    setAvatarState("thinking");
    setIsLoading(true);

    try {
      const res = await fetch("/api/zari/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: trimmed,
          stage,
          history: opts?.historyOverride ?? msgs,
          sessionId: sid,
          sectionContext: readSectionContext(),
          uploadedContent:  opts?.uploadedContent,
          uploadedFileName: opts?.uploadedFileName,
        }),
      });
      const data = await res.json().catch(() => ({})) as { message?: string; aiEnabled?: boolean; code?: string; error?: string; requiredPlanId?: string; creditUsage?: { used?: number; limit?: number } };
      if (!res.ok && handleBillingApiError(res.status, data as BillingApiErrorData, billing)) {
        if (!opts?.skipUserMsg) setMsgs(m => m.slice(0, -1));
        setIsLoading(false);
        setAvatarState("idle");
        return;
      }
      const reply = data.message?.trim() ?? "";
      const isFailed = !reply || ERROR_PATTERNS.some(p => reply.toLowerCase().includes(p));
      if (isFailed) {
        setLastFailedMsg(trimmed);
        setSendError("Couldn't reach Zari — check your connection and try again.");
        setAvatarState("idle");
      } else {
        setSendError(null);
        setLastFailedMsg(null);
        setMsgs(m => [...m, { role: "coach", text: reply }]);
        if (sid) void loadHistory();
        setAvatarState("speaking");
        void speakText(reply);
        setTimeout(() => setAvatarState("listening"), 3500);
      }
    } catch {
      setLastFailedMsg(trimmed);
      setSendError("Connection issue — check your network.");
      setAvatarState("idle");
    } finally {
      setIsLoading(false);
    }
  }

  async function handleFileUpload(file: File) {
    const name = file.name.toLowerCase();
    const docType = name.includes("cover") ? "cover letter"
      : name.includes("linkedin") ? "LinkedIn profile"
      : "resume";

    // Show the file attachment as a user message
    const fileMsg: ChatMsg = { role: "user", text: `📎 ${file.name}` };
    setMsgs(m => [...m, fileMsg]);
    setAvatarState("thinking");
    setIsLoading(true);
    setFileProcessing(true);

    try {
      const fd = new FormData();
      fd.append("file", file);
      const extractRes = await fetch("/api/zari/extract", { method: "POST", body: fd });
      const extractData = await extractRes.json().catch(() => ({})) as { text?: string };
      const extractedText = extractData.text ?? "";

      if (!extractedText) {
        setMsgs(m => [...m, { role: "coach", text: "I couldn't read that file — try uploading it again, or paste the content directly." }]);
        setAvatarState("idle");
        setIsLoading(false);
        return;
      }

      // Send to Zari with the extracted content as context
      const prompt = `I just uploaded my ${docType}. Take a look and give me your honest read — what's working, what isn't, and what's the most important thing to fix?`;
      const historyWithFile = [...msgs, fileMsg];

      await sendMessage(prompt, {
        uploadedContent: extractedText,
        uploadedFileName: file.name,
        skipUserMsg: false,
        historyOverride: historyWithFile,
      });
    } catch {
      setMsgs(m => [...m, { role: "coach", text: "Couldn't process that file — try again or paste the text directly." }]);
      setAvatarState("idle");
    } finally {
      setFileProcessing(false);
      // setIsLoading is reset inside sendMessage's finally
    }
  }

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100%", overflow:"hidden", background:"var(--z-raise)", position:"relative" }}>

      {/* ── TOP HEADER BAR ── */}
      <div style={{
        flexShrink:0, height:52,
        display:"flex", alignItems:"center", justifyContent:"space-between",
        padding:"0 20px",
        borderBottom:"1px solid var(--z-bd)",
        background:"var(--z-raise)",
      }}>
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          <span style={{ display:"inline-flex", alignItems:"center", gap:5, fontSize:11, fontWeight:700, color:"#22C55E", padding:"3px 10px", borderRadius:99, background:"rgba(34,197,94,0.1)", border:"1px solid rgba(34,197,94,0.2)" }}>
            <span style={{ width:5,height:5,borderRadius:"50%",background:"#22C55E",animation:"blink 1.1s ease-in-out infinite" }}/>
            Live
          </span>
          <span style={{ fontFamily:"monospace", fontSize:11, color:"var(--z-text3)", padding:"3px 10px", borderRadius:99, background:"var(--z-card)", boxShadow:"0 2px 20px rgba(0,0,0,0.07)", border:"1px solid var(--z-bd)" }}>{fmt(elapsed)}</span>
          <span style={{ display:"inline-flex", alignItems:"center", gap:4, fontSize:11, fontWeight:600, color:STAGE_META[stage].color, padding:"3px 9px", borderRadius:99, background:`${STAGE_META[stage].color}18`, border:`1px solid ${STAGE_META[stage].color}35` }}>{STAGE_ICONS[stage]} {STAGE_META[stage].label}</span>
        </div>
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          <button onClick={() => setShowLiveMode(true)} style={{
            display:"flex", alignItems:"center", gap:6, fontSize:12, fontWeight:700,
            color:"white", padding:"6px 14px", borderRadius:8, border:"none", cursor:"pointer",
            background:"linear-gradient(135deg,#3730a3,#2563EB)",
            boxShadow:"0 0 18px rgba(37,99,235,0.45)",
            transition:"all 0.2s",
          }}>
            <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width:13,height:13 }}><path d="M10 2a3 3 0 00-3 3v4a3 3 0 006 0V5a3 3 0 00-3-3z"/><path d="M4 9v1a6 6 0 0012 0V9"/></svg>
            Talk Live
          </button>
        </div>
      </div>

      {/* ── MAIN BODY ── */}
      <div style={{ flex:1, display:"flex", minHeight:0, overflow:"hidden" }}>

        {/* ── LEFT PANEL: always history ── */}
        <div style={{
          width:252, flexShrink:0, display:"flex", flexDirection:"column",
          borderRight:"1px solid var(--z-bd)",
          background:"var(--z-card)",
          overflow:"hidden",
        }}>
          {/* Compact avatar header */}
          <div style={{ padding:"14px 16px 12px", borderBottom:"1px solid var(--z-bd)", display:"flex", alignItems:"center", gap:10 }}>
            <ZariAvatar state={avatarState} size={36} />
            <div>
              <div style={{ fontSize:12, fontWeight:700, color:"var(--z-text)" }}>Zari</div>
              <div style={{ display:"flex", alignItems:"center", gap:4, fontSize:10.5, fontWeight:500,
                color: avatarState==="speaking"?"#60A5FA": avatarState==="listening"?"#06B6D4": avatarState==="thinking"?"#93C5FD":"var(--z-text3)" }}>
                <span style={{ width:4,height:4,borderRadius:"50%",flexShrink:0,
                  background: avatarState==="speaking"?"#60A5FA": avatarState==="listening"?"#06B6D4": avatarState==="thinking"?"#93C5FD":"var(--z-text3)",
                  animation:"blink 1.2s ease-in-out infinite" }}/>
                {avatarState==="speaking"&&"Speaking…"}{avatarState==="listening"&&"Listening…"}{avatarState==="thinking"&&"Thinking…"}{avatarState==="idle"&&"Ready"}
              </div>
            </div>
            <button onClick={() => { setIsVoice(v=>!v); if (isVoice && audioRef.current) { audioRef.current.pause(); audioRef.current = null; } }}
              title={isVoice ? "Voice replies: on" : "Voice replies: off"}
              style={{ marginLeft:"auto", width:28,height:28,borderRadius:8,border:"none",cursor:"pointer",
                background: isVoice ? "rgba(96,165,250,0.18)" : "var(--z-raise)",
                color: isVoice ? "#60A5FA" : "var(--z-text3)",
                display:"flex",alignItems:"center",justifyContent:"center", transition:"all 0.2s", flexShrink:0 }}>
              <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width:13,height:13 }}><path d="M10 2a3 3 0 00-3 3v4a3 3 0 006 0V5a3 3 0 00-3-3z"/><path d="M4 9v1a6 6 0 0012 0V9"/><line x1="10" y1="15" x2="10" y2="18"/></svg>
            </button>
          </div>

          <div style={{ padding:"10px 12px", borderBottom:"1px solid var(--z-bd2)" }}>
            <button
              onClick={() => void startNewChat()}
              disabled={isLoading || startingNewChat}
              style={{
                width:"100%",
                display:"flex",
                alignItems:"center",
                justifyContent:"center",
                gap:8,
                padding:"10px 12px",
                borderRadius:10,
                border:"1px solid rgba(37,99,235,0.28)",
                background:"var(--z-raise)",
                color:"#A5B4FC",
                fontSize:12,
                fontWeight:700,
                cursor:isLoading || startingNewChat ? "default" : "pointer",
                opacity:isLoading || startingNewChat ? 0.55 : 1,
              }}
            >
              <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" style={{ width:12,height:12 }}><path d="M8 3v10M3 8h10"/></svg>
              {startingNewChat ? "Starting..." : "New chat"}
            </button>
          </div>

          {/* History list */}
          <div style={{ padding:"10px 12px 6px", borderBottom:"1px solid var(--z-bd2)" }}>
            <p style={{ fontSize:9.5, fontWeight:700, textTransform:"uppercase", letterSpacing:"0.1em", color:"var(--z-text3)", margin:0 }}>Session History</p>
          </div>
          <div style={{ flex:1, overflowY:"auto", padding:"6px 8px" }}>
            {loadingHistory && (
              <div style={{ display:"flex", justifyContent:"center", padding:20 }}>
                <div style={{ width:16,height:16,borderRadius:"50%",border:"2px solid rgba(255,255,255,0.08)",borderTopColor:"rgba(255,255,255,0.45)",animation:"spin-slow 0.7s linear infinite" }}/>
              </div>
            )}
            {!loadingHistory && pastSessions.length === 0 && (
              <p style={{ fontSize:11.5, color:"var(--z-text3)", padding:"14px 6px", textAlign:"center", lineHeight:1.5 }}>Your past chats will appear here</p>
            )}
            {pastSessions.map(s => {
              const firstCoach = s.transcript.find(t => t.role === "coach")?.message ?? "";
              const date = s.startedAt ? new Date(s.startedAt).toLocaleDateString("en-US", { month:"short", day:"numeric" }) : "";
              return (
                <button key={s.id} onClick={() => {
                  setSelectedHistory(s.id);
                  setSessionId(s.id);
                  setSessionReady(true);
                  setSendError(null);
                  setLastFailedMsg(null);
                  setMsgs(s.transcript.map(t => ({ role: t.role, text: t.message })));
                }} style={{
                  width:"100%", textAlign:"left", padding:"9px 10px",
                  borderRadius:9, border:`1px solid ${selectedHistory === s.id ? "rgba(37,99,235,0.4)" : "transparent"}`,
                  cursor:"pointer", marginBottom:2,
                  background: selectedHistory === s.id ? "rgba(37,99,235,0.12)" : "transparent",
                  transition:"all 0.15s",
                }}>
                  <div style={{ display:"flex", justifyContent:"space-between", alignItems:"baseline", marginBottom:2 }}>
                    <p style={{ fontSize:11.5, fontWeight:600, color:"var(--z-text2)", margin:0, whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis", maxWidth:150 }}>{s.title}</p>
                    <span style={{ fontSize:9.5, color:"var(--z-text3)", flexShrink:0, marginLeft:5 }}>{date}</span>
                  </div>
                  <p style={{ fontSize:10.5, color:"var(--z-text3)", margin:0, whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>{firstCoach.slice(0,52)}{firstCoach.length>52?"…":""}</p>
                </button>
              );
            })}
          </div>
        </div>

        {/* ── CHAT PANEL ── */}
        <div style={{ flex:1, display:"flex", flexDirection:"column", minWidth:0 }}>
          {/* Messages */}
          <div ref={chatRef} style={{ flex:1, overflowY:"auto", padding:"24px 26px 8px" }}>
            {!sessionReady && msgs.length === 0 && !isLoading && (
              <div style={{ display:"flex", gap:10, marginBottom:14, animation:"bubble-appear 0.3s ease" }}>
                <div style={{ width:32,height:32,borderRadius:"50%",flexShrink:0,background:"linear-gradient(135deg,#3730a3,#2563EB)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:12,fontWeight:700,color:"white",boxShadow:"0 0 14px rgba(37,99,235,0.4)" }}>Z</div>
                <div style={{ display:"flex", alignItems:"center", gap:5, padding:"11px 16px", borderRadius:"4px 16px 16px 16px", background:"var(--z-card)", border:"1px solid var(--z-bd)" }}>
                  {[0,1,2].map(i=><div key={i} style={{ width:7,height:7,borderRadius:"50%",background:"rgba(96,165,250,0.55)",animation:`dot-bounce 1.2s ease-in-out ${i*0.2}s infinite` }}/>)}
                </div>
              </div>
            )}
            {msgs.map((msg, i) => (
              <div key={i} style={{ display:"flex", gap:10, marginBottom:14, flexDirection:msg.role==="user"?"row-reverse":"row", animation:`bubble-appear 0.3s ease ${i*0.04}s both` }}>
                <div style={{
                  width:32, height:32, borderRadius:"50%", flexShrink:0,
                  display:"flex", alignItems:"center", justifyContent:"center", fontSize:12, fontWeight:700,
                  background: msg.role==="coach" ? "linear-gradient(135deg,#3730a3,#2563EB)" : "var(--z-raise)",
                  color: msg.role==="coach" ? "white" : "var(--z-text2)",
                  boxShadow: msg.role==="coach" ? "0 0 14px rgba(37,99,235,0.4)" : "none",
                }}>
                  {msg.role==="coach"?"Z":"S"}
                </div>
                <div style={{
                  maxWidth:"72%", padding:"11px 15px", fontSize:13.5, lineHeight:1.65,
                  borderRadius: msg.role==="coach" ? "4px 16px 16px 16px" : "16px 4px 16px 16px",
                  background: msg.role==="coach" ? "var(--z-card)" : "linear-gradient(135deg,#3730a3,#2563EB)",
                  color:"var(--z-text)",
                  border: msg.role==="coach" ? "1px solid var(--z-bd)" : "none",
                  boxShadow: msg.role!=="coach" ? "0 4px 16px rgba(37,99,235,0.35)" : "none",
                }}>
                  {msg.role === "coach" ? renderMsgText(msg.text, stage, onNavigate) : msg.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div style={{ display:"flex", gap:10, marginBottom:14, animation:"bubble-appear 0.2s ease" }}>
                <div style={{ width:32,height:32,borderRadius:"50%",flexShrink:0,background:"linear-gradient(135deg,#3730a3,#2563EB)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:12,fontWeight:700,color:"white",boxShadow:"0 0 14px rgba(37,99,235,0.4)" }}>Z</div>
                <div style={{ display:"flex", alignItems:"center", gap:5, padding:"11px 16px", borderRadius:"4px 16px 16px 16px", background:"var(--z-card)", border:"1px solid var(--z-bd)" }}>
                  {[0,1,2].map(i=><div key={i} style={{ width:7,height:7,borderRadius:"50%",background:"rgba(96,165,250,0.65)",animation:`dot-bounce 1.2s ease-in-out ${i*0.2}s infinite` }}/>)}
                </div>
              </div>
            )}
          </div>

          {/* Error banner with retry */}
          {sendError && (
            <div style={{ flexShrink:0, margin:"0 24px 8px", padding:"9px 14px", borderRadius:10, background:"rgba(239,68,68,0.1)", border:"1px solid rgba(239,68,68,0.25)", display:"flex", alignItems:"center", justifyContent:"space-between", gap:10 }}>
              <span style={{ fontSize:12, color:"rgba(239,68,68,0.9)" }}>{sendError}</span>
              <button onClick={() => { setSendError(null); if (lastFailedMsg) void sendMessage(lastFailedMsg, { skipUserMsg: true }); }} style={{ fontSize:11.5, fontWeight:700, color:"#EF4444", background:"rgba(239,68,68,0.15)", border:"1px solid rgba(239,68,68,0.3)", borderRadius:7, padding:"4px 10px", cursor:"pointer", flexShrink:0 }}>
                Retry
              </button>
            </div>
          )}

          {/* Quick prompts grid */}
          <div style={{ flexShrink:0, padding:"0 26px 10px", display:"flex", gap:8, flexWrap:"wrap", justifyContent:"center" }}>
            {STAGE_PROMPTS[stage].map(p => (
              <button key={p} onClick={() => void sendMessage(p)} disabled={isLoading} style={{
                opacity: isLoading ? 0.4 : 1,
                fontSize:13, fontWeight:500, color:"var(--z-text2)",
                padding:"9px 18px", borderRadius:12,
                background:"var(--z-card)", border:"1px solid var(--z-bd)",
                cursor:"pointer", transition:"all 0.15s", lineHeight:1.4,
                boxShadow:"0 1px 4px rgba(0,0,0,0.06)",
                letterSpacing:"-0.01em",
              }}>
                {p}
              </button>
            ))}
          </div>

          {/* Input */}
          <div style={{ flexShrink:0, padding:"0 24px 20px" }}>
            <input ref={fileInputRef} type="file" accept=".pdf,.doc,.docx,.txt" style={{ display:"none" }}
              onChange={e => { const f = e.target.files?.[0]; if (f) void handleFileUpload(f); e.target.value = ""; }} />
            <div style={{
              position:"relative",
              background:"var(--z-raise)",
              border:`1.5px solid ${isRecording ? "rgba(239,68,68,0.6)" : isLoading ? "rgba(37,99,235,0.45)" : "var(--z-bd)"}`,
              borderRadius:16, overflow:"hidden",
              boxShadow: isLoading ? "0 0 24px rgba(37,99,235,0.12)" : "none",
              transition:"border-color 0.2s, box-shadow 0.2s",
            }}>
              <textarea
                style={{ width:"100%", border:"none", outline:"none", fontSize:14, color:"var(--z-text)", background:"transparent", resize:"none", padding:"13px 148px 13px 16px", fontFamily:"inherit", lineHeight:1.6, display:"block", opacity: isLoading ? 0.55 : 1 }}
                rows={3}
                placeholder={fileProcessing ? "Reading your file…" : isRecording ? "Listening… click mic to stop" : isLoading ? "Zari is thinking…" : "Ask Zari anything, attach a file, or practice out loud…"}
                value={input}
                onChange={e=>setInput(e.target.value)}
                onKeyDown={e=>{ if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();void sendMessage(input);} }}
                disabled={isLoading}
              />
              <button onClick={() => fileInputRef.current?.click()} disabled={isLoading} title="Upload resume, cover letter, or LinkedIn"
                style={{ position:"absolute", bottom:10, right:100, width:34,height:34,borderRadius:10,border:"none",cursor:isLoading?"default":"pointer", background:"var(--z-raise)", color:"var(--z-text3)", display:"flex",alignItems:"center",justifyContent:"center", transition:"all 0.15s" }}>
                <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width:15,height:15 }}><path d="M15.172 7l-6.586 6.586a2 2 0 01-2.828-2.828l6.414-6.586a4 4 0 015.656 5.656l-6.415 6.585a6 6 0 01-8.485-8.485l6.586-6.586"/></svg>
              </button>
              <button onClick={() => isRecording ? stopRecording() : void startRecording()} disabled={isLoading} title={isRecording?"Stop recording":"Speak to Zari"}
                style={{ position:"absolute", bottom:10, right:56, width:34,height:34,borderRadius:10,border:"none",cursor:isLoading?"default":"pointer", background:isRecording?"rgba(239,68,68,0.18)":"var(--z-raise)", color:isRecording?"#EF4444":"var(--z-text2)", display:"flex",alignItems:"center",justifyContent:"center", transition:"all 0.15s" }}>
                {isRecording
                  ? <span style={{ width:10,height:10,borderRadius:2,background:"#EF4444",animation:"blink 0.7s step-end infinite" }}/>
                  : <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width:15,height:15 }}><path d="M10 2a3 3 0 00-3 3v4a3 3 0 006 0V5a3 3 0 00-3-3z"/><path d="M4 9v1a6 6 0 0012 0V9"/><line x1="10" y1="15" x2="10" y2="18"/></svg>
                }
              </button>
              <button onClick={()=>void sendMessage(input)} disabled={isLoading||!input.trim()}
                style={{ position:"absolute", bottom:10, right:12, width:34,height:34,borderRadius:10,border:"none",cursor:isLoading||!input.trim()?"default":"pointer",
                  background:input.trim()&&!isLoading?"linear-gradient(135deg,#3730a3,#2563EB)":"var(--z-raise)",
                  color:input.trim()&&!isLoading?"white":"var(--z-text3)",
                  boxShadow:input.trim()&&!isLoading?"0 0 14px rgba(37,99,235,0.45)":"none",
                  display:"flex",alignItems:"center",justifyContent:"center", transition:"all 0.15s" }}>
                {isLoading
                  ? <span style={{ width:12,height:12,borderRadius:"50%",border:"2px solid rgba(255,255,255,0.15)",borderTopColor:"rgba(255,255,255,0.65)",animation:"spin-slow 0.7s linear infinite",display:"block" }}/>
                  : <svg viewBox="0 0 20 20" fill="currentColor" style={{ width:14,height:14 }}><path d="M3.105 3.105a1 1 0 011.263-.237l12 6a1 1 0 010 1.764l-12 6a1 1 0 01-1.367-1.31L4.945 10 3 4.678a1 1 0 01.105-1.573z"/></svg>
                }
              </button>
            </div>
            <p style={{ textAlign:"center", fontSize:10, color:"var(--z-text3)", marginTop:6 }}>Enter to send · Shift+Enter for newline · 📎 attach · 🎤 speak</p>
          </div>
        </div>
      </div>

      {/* Live mode overlay */}
      {showLiveMode && (
        <ZariLiveMode
          stage={stage}
          msgs={msgs}
          sessionId={sessionId}
          sectionContext={readSectionContext()}
          onClose={() => setShowLiveMode(false)}
          onNewMessages={newMsgs => setMsgs(m => [...m, ...newMsgs])}
          onNavigate={onNavigate}
        />
      )}
    </div>
  );
}

/* ═══════════════════════════════════════════════════
   ZARI LIVE MODE — immersive full-screen voice session
═══════════════════════════════════════════════════ */
function ZariLiveMode({
  stage, msgs, sessionId, sectionContext, onClose, onNewMessages, onNavigate,
}: {
  stage: CareerStage;
  msgs: ChatMsg[];
  sessionId: string | null;
  sectionContext: Record<string, unknown>;
  onClose: () => void;
  onNewMessages: (m: ChatMsg[]) => void;
  onNavigate?: (s: Screen) => void;
}) {
  type LiveState = "idle" | "listening" | "thinking" | "speaking";
  type VoiceOption = { key: string; label: string; gender: string; provider: string };
  const [liveState, setLiveState]   = useState<LiveState>("idle");
  const [transcript, setTranscript] = useState<ChatMsg[]>([]);
  const [interimText, setInterimText] = useState("");
  const [statusText, setStatusText] = useState("Tap the mic to start");
  const [started, setStarted]       = useState(false);
  const [micBlocked, setMicBlocked] = useState(false);
  const [voices, setVoices]         = useState<VoiceOption[]>([]);
  const [activeVoice, setActiveVoice] = useState("");
  const [showAllVoices, setShowAllVoices] = useState(false);
  const [attachedFile, setAttachedFile] = useState<{ name: string; content: string } | null>(null);
  const attachedFileRef = useRef<{ name: string; content: string } | null>(null); // ref so processInput always reads fresh value
  const [goActions, setGoActions] = useState<Screen[]>([]);
  const fileInputRef = useRef<HTMLInputElement | null>(null);

  useEffect(() => {
    fetch("/api/zari/voices").then(r => r.json()).then((d: { voices: VoiceOption[] }) => {
      if (!d.voices?.length) return;
      setVoices(d.voices);
      // Always use Jessica — fall back to first available if not found
      const jessica = d.voices.find(v => v.label.toLowerCase().includes("jessica")) ?? d.voices[0];
      setActiveVoice(jessica.key);
      activeVoiceRef.current = jessica.key;
    }).catch(() => {});
  }, []);

  type SR = { continuous: boolean; interimResults: boolean; lang: string; start(): void; stop(): void; onresult: ((e: { results: { length: number; [i: number]: { isFinal: boolean; [j: number]: { transcript: string } } } }) => void) | null; onerror: ((e: { error: string }) => void) | null; onend: (() => void) | null };
  const audioCtxRef     = useRef<AudioContext | null>(null);
  const sourceNodeRef   = useRef<AudioBufferSourceNode | null>(null);
  const newMsgsRef      = useRef<ChatMsg[]>([]);
  const liveStateRef    = useRef<LiveState>("idle");
  const autoLoopRef     = useRef(false);
  const recognitionRef  = useRef<SR | null>(null);
  const transcriptRef   = useRef<HTMLDivElement>(null);
  const aliveRef        = useRef(true);
  const activeVoiceRef  = useRef("");

  useEffect(() => { liveStateRef.current = liveState; }, [liveState]);
  useEffect(() => { activeVoiceRef.current = activeVoice; }, [activeVoice]);
  useEffect(() => {
    if (transcriptRef.current) transcriptRef.current.scrollTop = transcriptRef.current.scrollHeight;
  }, [transcript, interimText]);

  useEffect(() => {
    return () => {
      aliveRef.current = false;
      autoLoopRef.current = false;
      stopAll();
      if (newMsgsRef.current.length > 0) onNewMessages(newMsgsRef.current);
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  function stopAll() {
    try { sourceNodeRef.current?.stop(); } catch {}
    sourceNodeRef.current = null;
    try { recognitionRef.current?.stop(); } catch {}
    recognitionRef.current = null;
  }

  /* ── Unlock AudioContext on first user gesture ── */
  function ensureAudioCtx() {
    if (!audioCtxRef.current) {
      type AC = typeof AudioContext;
      const Ctor: AC = (window.AudioContext ?? (window as unknown as { webkitAudioContext: AC }).webkitAudioContext);
      audioCtxRef.current = new Ctor();
    }
    if (audioCtxRef.current.state === "suspended") void audioCtxRef.current.resume();
  }

  /* ── Browser SpeechSynthesis — zero-latency guaranteed fallback ── */
  function speakSynthesis(text: string): Promise<void> {
    return new Promise(resolve => {
      if (typeof window === "undefined" || !("speechSynthesis" in window)) { resolve(); return; }
      window.speechSynthesis.cancel();
      const utt = new SpeechSynthesisUtterance(text);
      utt.rate = 1.05;
      utt.onend = () => resolve();
      utt.onerror = () => resolve();
      window.speechSynthesis.speak(utt);
      // Safety net: some browsers never fire onend — don't let playChain hang forever
      setTimeout(resolve, Math.max(3000, text.length * 70));
    });
  }

  /* ── Play one ArrayBuffer through AudioContext — returns true on success ── */
  async function playBuffer(buf: ArrayBuffer): Promise<boolean> {
    const ctx = audioCtxRef.current;
    if (!ctx || !aliveRef.current) return false;
    try {
      const audioBuf = await ctx.decodeAudioData(buf.slice(0));
      if (!aliveRef.current) return false;
      await new Promise<void>(resolve => {
        const src = ctx.createBufferSource();
        src.buffer = audioBuf;
        src.connect(ctx.destination);
        src.onended = () => { sourceNodeRef.current = null; resolve(); };
        sourceNodeRef.current = src;
        src.start(0);
      });
      return true;
    } catch (e) {
      console.error("[Zari] AudioContext decode failed:", e);
      return false;
    }
  }

  /* ── Chat stream → sentence-pipelined TTS ── */
  async function processInput(text: string) {
    if (!text.trim() || !aliveRef.current) return;
    setInterimText("");
    setLiveState("thinking");
    setStatusText("Thinking…");

    const userMsg: ChatMsg = { role: "user", text };
    setTranscript(t => [...t, userMsg]);
    newMsgsRef.current = [...newMsgsRef.current, userMsg];

    let fullReply = "";
    // Promise chain ensures sentences play in order while fetching in parallel
    let playChain: Promise<void> = Promise.resolve();
    let ttsStarted = false;

    function queueSentence(sentence: string) {
      const s = sentence.trim();
      if (!s) return;
      fullReply += (fullReply ? " " : "") + s;
      // Strip {{GO:xxx}} markers before TTS — they're UI buttons, not words to speak
      const ttsText = s.replace(/\{\{GO:[a-z-]+\}\}/g, "").trim();
      if (!ttsText) return;
      const bufPromise = fetch("/api/zari/speak", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text: ttsText, voice: activeVoiceRef.current }),
      }).then(r => {
        if (!r.ok) { console.error(`[Zari] speak API ${r.status}`); return null; }
        return r.arrayBuffer();
      }).catch(e => { console.error("[Zari] speak fetch error:", e); return null; });
      if (!ttsStarted) { ttsStarted = true; setLiveState("speaking"); setStatusText("Speaking…"); }
      playChain = playChain.then(async () => {
        if (!aliveRef.current) return;
        const buf = await bufPromise;
        if (buf && aliveRef.current) {
          const ok = await playBuffer(buf);
          if (!ok && aliveRef.current) await speakSynthesis(s); // AudioContext decode failed
        } else if (aliveRef.current) {
          await speakSynthesis(s); // API TTS failed — browser voice guaranteed
        }
      });
    }

    try {
      const history = [...msgs, ...newMsgsRef.current.slice(0, -1)].slice(-14);
      const res = await fetch("/api/zari/chat", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: text, stage, history, sessionId, sectionContext, isVoice: true,
          ...(attachedFileRef.current ? { uploadedContent: attachedFileRef.current.content, uploadedFileName: attachedFileRef.current.name } : {}),
        }),
      });
      if (!res.body) throw new Error("no stream");
      const reader = res.body.getReader();
      const decoder = new TextDecoder();
      let buf = "";
      // Early-flush: fire TTS 180ms after first token arrives rather than waiting
      // for full stream — at Groq speed (750 tok/s) the model is usually done by then
      let flushTimer: ReturnType<typeof setTimeout> | null = null;
      outer: while (aliveRef.current) {
        const { done, value } = await reader.read();
        if (done) break;
        for (const line of decoder.decode(value, { stream: true }).split("\n")) {
          const p = line.trim();
          if (!p.startsWith("data:")) continue;
          const d = p.slice(5).trim();
          if (d === "[DONE]") break outer;
          try {
            type C = { choices?: Array<{ delta?: { content?: string } }> };
            const tok = (JSON.parse(d) as C).choices?.[0]?.delta?.content ?? "";
            if (tok) {
              buf += tok;
              if (!flushTimer && !ttsStarted) {
                flushTimer = setTimeout(() => {
                  flushTimer = null;
                  if (buf.trim() && !ttsStarted) { queueSentence(buf); buf = ""; }
                }, 180);
              }
            }
          } catch {}
        }
        // Also fire immediately on sentence boundary
        const m = /[.!?][)'"»]?\s+/.exec(buf);
        if (m) {
          if (flushTimer) { clearTimeout(flushTimer); flushTimer = null; }
          queueSentence(buf.slice(0, m.index + m[0].trimEnd().length));
          buf = buf.slice(m.index + m[0].length);
        }
      }
      if (flushTimer) { clearTimeout(flushTimer); flushTimer = null; }
      if (buf.trim()) queueSentence(buf); // flush remainder
    } catch {
      if (aliveRef.current) { setLiveState("idle"); setStatusText("Something went wrong — try again"); }
      return;
    }

    await playChain; // wait for all audio segments to finish
    if (!aliveRef.current) return;

    if (fullReply.trim()) {
      const coachMsg: ChatMsg = { role: "coach", text: fullReply.trim() };
      setTranscript(t => [...t, coachMsg]);
      newMsgsRef.current = [...newMsgsRef.current, coachMsg];
      // Extract any GO: navigation actions from the reply to show as tap buttons
      const matches = [...fullReply.matchAll(/\{\{GO:([a-z-]+)\}\}/g)];
      if (matches.length) setGoActions(matches.map(m => m[1] as Screen));
    }

    if (aliveRef.current && autoLoopRef.current) {
      setLiveState("idle");
      setStatusText("Your turn…");
      setTimeout(() => { if (aliveRef.current && autoLoopRef.current) void startListening(); }, 250);
    }
  }

  /* ── Continuous speech recognition — stays open, no tapping ── */
  async function startListening() {
    if (!aliveRef.current || liveStateRef.current !== "idle") return;

    const SpeechRec = (typeof window !== "undefined")
      ? (((window as unknown) as Record<string, unknown>)["SpeechRecognition"] as (new () => SR) | undefined)
        ?? (((window as unknown) as Record<string, unknown>)["webkitSpeechRecognition"] as (new () => SR) | undefined)
      : undefined;

    if (!SpeechRec) {
      setLiveState("idle");
      setStatusText("Use Chrome or Edge for live voice");
      return;
    }

    // getUserMedia forces Chrome to show its permission popup on any HTTPS origin.
    // SpeechRecognition.start() silently fires not-allowed on new preview URLs without a popup.
    if (typeof navigator !== "undefined" && navigator.mediaDevices?.getUserMedia) {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        stream.getTracks().forEach(t => t.stop());
      } catch (err) {
        if (!aliveRef.current) return;
        const denied = err instanceof Error && (err.name === "NotAllowedError" || err.name === "PermissionDeniedError" || err.name === "SecurityError");
        autoLoopRef.current = false;
        setLiveState("idle");
        setMicBlocked(denied);
        setStatusText(denied ? "Microphone blocked — see instructions below" : "Microphone unavailable");
        setInterimText("");
        return;
      }
    }

    const rec = new SpeechRec();
    rec.continuous = false;     // false = faster silence detection (lower latency)
    rec.interimResults = true;
    rec.lang = "en-US";
    recognitionRef.current = rec;

    setLiveState("listening");
    liveStateRef.current = "listening"; // sync immediately
    setStatusText("Listening…");

    rec.onresult = (e: { results: { length: number; [i: number]: { isFinal: boolean; [j: number]: { transcript: string } } } }) => {
      const last = e.results[e.results.length - 1];
      const text = last[0].transcript;
      if (last.isFinal && text.trim()) {
        setInterimText("");
        liveStateRef.current = "thinking"; // update ref BEFORE stop() triggers onend
        recognitionRef.current = null;
        try { rec.stop(); } catch {}
        void processInput(text.trim());
      } else {
        setInterimText(text);
      }
    };
    rec.onerror = (e: { error: string }) => {
      liveStateRef.current = "idle";
      if (!aliveRef.current) return;
      const err = e?.error ?? "";
      if (err === "not-allowed" || err === "audio-capture" || err === "service-not-allowed") {
        // Fatal: mic blocked or unavailable — stop the loop and tell the user
        autoLoopRef.current = false;
        setLiveState("idle");
        setMicBlocked(err === "not-allowed" || err === "service-not-allowed");
        setStatusText(err === "not-allowed" || err === "service-not-allowed" ? "Microphone blocked — see instructions below" : "Microphone unavailable");
        setInterimText("");
      } else {
        // Retryable: no-speech, network, aborted, etc. — keep the loop alive
        setLiveState("idle");
        setStatusText("Your turn…");
        setInterimText("");
        if (autoLoopRef.current) {
          setTimeout(() => { if (aliveRef.current && autoLoopRef.current) void startListening(); }, 400);
        }
      }
    };
    rec.onend = () => {
      setInterimText("");
      // Restart only if we're still in listening state (no result was captured)
      if (aliveRef.current && autoLoopRef.current && liveStateRef.current === "listening") {
        liveStateRef.current = "idle";
        setLiveState("idle");
        setTimeout(() => { if (aliveRef.current && autoLoopRef.current) void startListening(); }, 150);
      }
    };
    try { rec.start(); } catch {
      setLiveState("idle");
      setStatusText("Microphone unavailable — check permissions");
    }
  }

  function handleMicTap() {
    try { ensureAudioCtx(); } catch { /* AudioContext unavailable — speech synthesis will be used instead */ }
    if (!started) {
      setStarted(true);
      autoLoopRef.current = true;
      void startListening();
      return;
    }
    const state = liveStateRef.current; // always fresh — never stale React closure
    if (state === "idle") {
      autoLoopRef.current = true;
      void startListening();
    } else if (state === "listening") {
      // Set to idle BEFORE rec.stop() so onend guard sees "idle" and does NOT restart
      autoLoopRef.current = false;
      liveStateRef.current = "idle";
      setLiveState("idle");
      setStatusText("Tap to start");
      try { recognitionRef.current?.stop(); } catch {}
      recognitionRef.current = null;
    } else if (state === "speaking" || state === "thinking") {
      // Interrupt bot: stop all audio immediately, return to idle
      autoLoopRef.current = false;
      liveStateRef.current = "idle";
      setLiveState("idle");
      setStatusText("Tap to start");
      stopAll();
      window.speechSynthesis?.cancel();
    }
  }

  async function handleFileAttach(file: File) {
    if (!file) return;
    try {
      const fd = new FormData();
      fd.append("file", file);
      const res = await fetch("/api/zari/extract", { method: "POST", body: fd });
      const data = await res.json().catch(() => ({})) as { text?: string };
      if (data.text) {
        const doc = { name: file.name, content: data.text };
        setAttachedFile(doc);
        attachedFileRef.current = doc;
      }
    } catch { /* non-fatal */ }
  }

  function handleClose() {
    autoLoopRef.current = false;
    stopAll();
    onClose();
  }

  const ORB: Record<LiveState, { gradient: string; shadow: string; animation: string }> = {
    idle:      { gradient:"radial-gradient(circle at 32% 32%, #9a8ff5, #4f46e5 50%, #1a1756 100%)", shadow:"0 0 60px 22px rgba(79,70,229,0.32), 0 0 130px 50px rgba(67,56,202,0.12)", animation:"sphere-breathe 4s ease-in-out infinite" },
    listening: { gradient:"radial-gradient(circle at 32% 32%, #7ef3ff, #06b6d4 50%, #0c3d52 100%)", shadow:"0 0 75px 28px rgba(6,182,212,0.55), 0 0 150px 60px rgba(6,182,212,0.18)", animation:"sphere-breathe 1.1s ease-in-out infinite" },
    thinking:  { gradient:"radial-gradient(circle at 32% 32%, #d8b4fe, #8b5cf6 50%, #2e1065 100%)", shadow:"0 0 65px 24px rgba(139,92,246,0.48), 0 0 140px 55px rgba(15,118,110,0.18)", animation:"sphere-breathe 2.5s ease-in-out infinite" },
    speaking:  { gradient:"radial-gradient(circle at 32% 32%, #c7d2fe, #6366f1 42%, #1e1b4b 100%)", shadow:"0 0 95px 40px rgba(59,130,246,0.68), 0 0 190px 75px rgba(67,56,202,0.28)", animation:"sphere-breathe 0.55s ease-in-out infinite" },
  };
  const orb = ORB[liveState];

  return (
    <div style={{ position:"fixed", inset:0, zIndex:9999, display:"flex", flexDirection:"column", alignItems:"center", fontFamily:"var(--font-geist-sans,Inter,system-ui,sans-serif)", overflow:"hidden" }}>

      {/* Deep space background */}
      <div style={{ position:"absolute", inset:0, background:"radial-gradient(ellipse at 50% 15%, #12103a 0%, #07050f 55%, #000000 100%)" }}/>
      {/* Aurora blobs */}
      <div style={{ position:"absolute", top:"-10%", left:"5%", width:700, height:700, borderRadius:"50%", background:"radial-gradient(circle, rgba(67,56,202,0.28) 0%, transparent 60%)", filter:"blur(100px)", animation:"aurora-a 9s ease-in-out infinite", pointerEvents:"none" }}/>
      <div style={{ position:"absolute", bottom:"5%", right:"3%", width:580, height:580, borderRadius:"50%", background:"radial-gradient(circle, rgba(59,130,246,0.18) 0%, transparent 60%)", filter:"blur(90px)", animation:"aurora-b 12s ease-in-out infinite", pointerEvents:"none" }}/>
      <div style={{ position:"absolute", top:"50%", left:"50%", width:1000, height:500, borderRadius:"50%", background:"radial-gradient(circle, rgba(79,70,229,0.1) 0%, transparent 65%)", filter:"blur(120px)", transform:"translate(-50%,-50%)", pointerEvents:"none" }}/>
      <div style={{ position:"absolute", top:"20%", right:"10%", width:380, height:380, borderRadius:"50%", background:"radial-gradient(circle, rgba(139,92,246,0.16) 0%, transparent 60%)", filter:"blur(60px)", animation:"aurora-c 14s ease-in-out infinite", pointerEvents:"none" }}/>

      {/* Top bar */}
      <div style={{ position:"absolute", top:0, left:0, right:0, display:"flex", alignItems:"center", justifyContent:"space-between", padding:"22px 28px", zIndex:2 }}>
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          <div style={{ width:30, height:30, borderRadius:"50%", background:"linear-gradient(135deg,#4f46e5,#818cf8)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:13, fontWeight:800, color:"white", boxShadow:"0 0 22px rgba(99,102,241,0.6), 0 0 8px rgba(99,102,241,0.3)" }}>Z</div>
          <span style={{ color:"rgba(255,255,255,0.9)", fontWeight:700, fontSize:14, letterSpacing:"0.1em" }}>ZARI</span>
          <span style={{ fontSize:9, color:"rgba(255,255,255,0.28)", fontWeight:600, marginLeft:1, letterSpacing:"0.15em", textTransform:"uppercase" }}>LIVE</span>
        </div>
        <button onClick={handleClose} style={{ width:34, height:34, borderRadius:"50%", border:"1px solid rgba(255,255,255,0.1)", background:"rgba(255,255,255,0.05)", backdropFilter:"blur(10px)", color:"rgba(255,255,255,0.55)", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", transition:"all 0.2s" }}>
          <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="2" style={{ width:12, height:12 }}><path d="M4 4l12 12M16 4L4 16"/></svg>
        </button>
      </div>

      {/* ── Main content area ── */}
      <div style={{ position:"relative", zIndex:1, display:"flex", flexDirection:"column", alignItems:"center", width:"100%", height:"100%", paddingTop:80, paddingBottom:32 }}>

        {/* Orb */}
        <div style={{ position:"relative", width:210, height:210, flexShrink:0 }}>
          {liveState === "listening" && [0,1,2].map(i => (
            <div key={i} style={{ position:"absolute", top:"50%", left:"50%", width:226, height:226, borderRadius:"50%", border:`1px solid rgba(6,182,212,${0.5-i*0.14})`, animation:`listen-ripple-v2 ${2.4+i*0.85}s ease-out ${i*0.8}s infinite`, pointerEvents:"none" }}/>
          ))}
          {liveState === "thinking" && (
            <div style={{ position:"absolute", top:"50%", left:"50%", width:234, height:234, borderRadius:"50%", border:"2px solid transparent", borderTopColor:"rgba(139,92,246,0.85)", borderRightColor:"rgba(139,92,246,0.22)", animation:"spin-arc 1.1s linear infinite", pointerEvents:"none" }}/>
          )}
          {liveState === "speaking" && [0,1].map(i => (
            <div key={i} style={{ position:"absolute", top:"50%", left:"50%", width:226+i*18, height:226+i*18, borderRadius:"50%", border:"1px solid rgba(99,102,241,0.3)", animation:`ring-pulse ${1.8+i*0.6}s ease-out ${i*0.4}s infinite`, pointerEvents:"none" }}/>
          ))}
          <div style={{ position:"absolute", inset:0, borderRadius:"50%", background:orb.gradient, boxShadow:orb.shadow, animation:orb.animation, transition:"background 0.6s ease, box-shadow 0.6s ease" }}/>
        </div>

        {/* Name + waveform / status */}
        <div style={{ textAlign:"center", marginTop:20, marginBottom:8 }}>
          <p style={{ color:"rgba(255,255,255,0.92)", fontWeight:700, fontSize:22, letterSpacing:"0.18em", margin:0, textShadow:"0 0 30px rgba(139,92,246,0.4)" }}>ZARI</p>
          <div style={{ height:28, display:"flex", alignItems:"center", justifyContent:"center", marginTop:6 }}>
            {liveState === "speaking" ? (
              <div style={{ display:"flex", gap:3.5, alignItems:"flex-end", height:22 }}>
                {[0,1,2,3,4,5,6].map(i => (
                  <div key={i} style={{ width:3, borderRadius:2, background:`rgba(${i<3?"165,180,252":"129,140,248"},${0.5+i*0.06})`, animation:`bar-eq ${0.42+i*0.06}s ease-in-out ${i*0.07}s infinite` }}/>
                ))}
              </div>
            ) : (
              <p style={{ color:"rgba(255,255,255,0.38)", fontSize:12, fontWeight:500, margin:0, letterSpacing:"0.06em" }}>{statusText}</p>
            )}
          </div>
        </div>

        {/* Transcript glass panel */}
        <div style={{ width:"100%", maxWidth:580, flex:1, minHeight:0, display:"flex", flexDirection:"column", padding:"0 20px", marginTop:4 }}>
          <div
            ref={transcriptRef}
            style={{
              flex:1, minHeight:0, overflowY:"auto", display:"flex", flexDirection:"column", gap:10,
              padding:"14px 16px 10px",
              background: transcript.length > 0 || interimText ? "rgba(255,255,255,0.03)" : "transparent",
              backdropFilter: transcript.length > 0 || interimText ? "blur(12px)" : "none",
              borderRadius:20,
              border: transcript.length > 0 || interimText ? "1px solid rgba(255,255,255,0.07)" : "none",
              scrollbarWidth:"none",
              transition:"background 0.4s ease, border-color 0.4s ease",
            }}
          >
            {transcript.length === 0 && !interimText && (
              <p style={{ textAlign:"center", color:"rgba(255,255,255,0.15)", fontSize:13, margin:"auto 0", letterSpacing:"0.02em" }}>
                {started ? "Say something…" : "Tap the mic below to begin"}
              </p>
            )}
            {transcript.slice(-8).map((m, i) => (
              <div key={i} style={{ display:"flex", flexDirection:"column", alignItems:m.role==="user"?"flex-end":"flex-start", animation:"bubble-appear 0.25s ease" }}>
                <span style={{ fontSize:9.5, fontWeight:600, letterSpacing:"0.08em", color:"rgba(255,255,255,0.22)", marginBottom:3, paddingLeft:m.role==="user"?0:4, paddingRight:m.role==="user"?4:0, textTransform:"uppercase" }}>
                  {m.role === "user" ? "You" : "Zari"}
                </span>
                <div style={{
                  maxWidth:"82%", padding:"11px 15px",
                  borderRadius:m.role==="user" ? "18px 4px 18px 18px" : "4px 18px 18px 18px",
                  background: m.role==="user"
                    ? "rgba(255,255,255,0.10)"
                    : "rgba(99,102,241,0.30)",
                  border: `1px solid ${m.role==="user" ? "rgba(255,255,255,0.13)" : "rgba(129,140,248,0.35)"}`,
                  color:"rgba(255,255,255,0.92)",
                  fontSize:14, lineHeight:1.65,
                  boxShadow: m.role==="coach" ? "0 2px 20px rgba(99,102,241,0.12)" : "none",
                }}>
                  {m.text.replace(/\{\{GO:[a-z-]+\}\}/g, "").trim()}
                </div>
              </div>
            ))}
            {interimText && (
              <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", animation:"bubble-appear 0.15s ease" }}>
                <span style={{ fontSize:9.5, fontWeight:600, letterSpacing:"0.08em", color:"rgba(255,255,255,0.18)", marginBottom:3, paddingRight:4, textTransform:"uppercase" }}>You</span>
                <div style={{ maxWidth:"82%", padding:"11px 15px", borderRadius:"18px 4px 18px 18px", background:"rgba(255,255,255,0.06)", border:"1px solid rgba(255,255,255,0.09)", color:"rgba(255,255,255,0.45)", fontSize:14, fontStyle:"italic", lineHeight:1.65 }}>
                  {interimText}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Mic permission guide */}
        {micBlocked && (
          <div style={{ width:"100%", maxWidth:420, margin:"10px 20px 0", padding:"18px 22px", borderRadius:14, background:"rgba(239,68,68,0.1)", border:"1px solid rgba(239,68,68,0.25)", backdropFilter:"blur(12px)" }}>
            <p style={{ color:"#FCA5A5", fontWeight:700, fontSize:13, margin:"0 0 8px" }}>Microphone access is blocked</p>
            <ol style={{ color:"rgba(255,255,255,0.65)", fontSize:12, margin:0, paddingLeft:18, lineHeight:2.1 }}>
              <li>Click the <strong style={{ color:"rgba(255,255,255,0.9)" }}>lock icon</strong> in the address bar</li>
              <li>Click <strong style={{ color:"rgba(255,255,255,0.9)" }}>Site settings</strong></li>
              <li>Set <strong style={{ color:"rgba(255,255,255,0.9)" }}>Microphone</strong> to <strong style={{ color:"rgba(255,255,255,0.9)" }}>Allow</strong></li>
              <li>Reload and tap the mic again</li>
            </ol>
            <button onClick={() => { setMicBlocked(false); autoLoopRef.current = false; setStarted(false); }} style={{ marginTop:10, fontSize:11, color:"rgba(255,255,255,0.35)", background:"none", border:"none", cursor:"pointer", padding:0, textDecoration:"underline" }}>Dismiss</button>
          </div>
        )}

        {/* GO: action chips */}
        {goActions.length > 0 && onNavigate && (
          <div style={{ display:"flex", gap:6, flexWrap:"wrap", justifyContent:"center", marginTop:12, padding:"0 20px" }}>
            {goActions.map(s => (
              <button key={s} onClick={() => { setGoActions([]); onClose(); onNavigate(s); }} style={{
                padding:"7px 16px", borderRadius:99, border:"1px solid rgba(99,102,241,0.5)",
                background:"rgba(99,102,241,0.18)", backdropFilter:"blur(8px)",
                color:"rgba(199,210,254,0.95)", fontSize:12, fontWeight:600, cursor:"pointer",
                transition:"all 0.15s", boxShadow:"0 2px 12px rgba(99,102,241,0.15)",
              }}>
                {navCtaLabel(stage, s)}
              </button>
            ))}
            <button onClick={() => setGoActions([])} style={{ padding:"7px 14px", borderRadius:99, border:"1px solid rgba(255,255,255,0.08)", background:"transparent", color:"rgba(255,255,255,0.3)", fontSize:12, cursor:"pointer" }}>dismiss</button>
          </div>
        )}

        {/* Bottom controls: mic + attach */}
        <div style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:12, marginTop:16, flexShrink:0 }}>

          {/* Mic button */}
          <button
            onClick={handleMicTap}
            disabled={liveState === "thinking"}
            style={{
              width:76, height:76, borderRadius:"50%", border:"none",
              cursor: liveState==="thinking" ? "not-allowed" : "pointer",
              background: liveState==="listening"
                ? "radial-gradient(circle at 35% 35%, rgba(252,165,165,1), rgba(239,68,68,0.9))"
                : liveState==="speaking"
                ? "radial-gradient(circle at 35% 35%, rgba(165,180,252,0.5), rgba(99,102,241,0.3))"
                : "radial-gradient(circle at 35% 35%, rgba(129,140,248,1), rgba(79,70,229,0.9))",
              boxShadow: liveState==="listening"
                ? "0 0 0 8px rgba(239,68,68,0.12), 0 0 0 16px rgba(239,68,68,0.06), 0 0 40px rgba(239,68,68,0.55)"
                : liveState==="idle" || liveState==="thinking"
                ? "0 0 0 8px rgba(99,102,241,0.12), 0 0 0 16px rgba(99,102,241,0.05), 0 0 40px rgba(99,102,241,0.45)"
                : "0 0 0 8px rgba(99,102,241,0.08), 0 0 24px rgba(99,102,241,0.25)",
              display:"flex", alignItems:"center", justifyContent:"center",
              transition:"all 0.3s ease",
              animation: liveState==="listening" ? "sphere-breathe 1.2s ease-in-out infinite" : "none",
            }}
          >
            {liveState === "listening"
              ? <div style={{ width:18, height:18, borderRadius:4, background:"white" }}/>
              : liveState === "thinking"
              ? <span style={{ width:18, height:18, borderRadius:"50%", border:"2.5px solid rgba(255,255,255,0.2)", borderTopColor:"white", display:"block", animation:"spin-slow 0.75s linear infinite" }}/>
              : liveState === "speaking"
              ? <svg viewBox="0 0 20 20" fill="none" stroke="rgba(255,255,255,0.5)" strokeWidth="1.8" style={{ width:24, height:24 }}><path d="M10 2a3 3 0 00-3 3v4a3 3 0 006 0V5a3 3 0 00-3-3z"/><path d="M4 9v1a6 6 0 0012 0V9"/><line x1="10" y1="15" x2="10" y2="18"/></svg>
              : <svg viewBox="0 0 20 20" fill="none" stroke="white" strokeWidth="1.8" style={{ width:26, height:26 }}><path d="M10 2a3 3 0 00-3 3v4a3 3 0 006 0V5a3 3 0 00-3-3z"/><path d="M4 9v1a6 6 0 0012 0V9"/><line x1="10" y1="15" x2="10" y2="18"/></svg>
            }
          </button>

          <p style={{ color:"rgba(255,255,255,0.3)", fontSize:11, margin:0, letterSpacing:"0.05em", fontWeight:500 }}>
            {liveState==="listening" ? "listening · tap to stop" : liveState==="speaking" ? "tap to interrupt" : liveState==="thinking" ? "thinking…" : started ? "hands-free · auto-resumes" : "tap to start"}
          </p>

          {/* Attach file */}
          <div style={{ display:"flex", alignItems:"center", gap:7 }}>
            <input ref={fileInputRef} type="file" accept=".pdf,.doc,.docx,.txt" style={{ display:"none" }}
              onChange={e => { const f = e.target.files?.[0]; if (f) void handleFileAttach(f); e.target.value = ""; }}
            />
            <button onClick={() => fileInputRef.current?.click()} style={{
              display:"flex", alignItems:"center", gap:6, padding:"6px 14px", borderRadius:99,
              border:"1px solid rgba(255,255,255,0.1)", background:"rgba(255,255,255,0.04)",
              backdropFilter:"blur(8px)", color:"rgba(255,255,255,0.4)", fontSize:11.5, fontWeight:500,
              cursor:"pointer", transition:"all 0.15s", letterSpacing:"0.02em",
            }}>
              <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.6" style={{ width:12, height:12 }}>
                <path d="M2 12V4a1 1 0 011-1h6l3 3v6a1 1 0 01-1 1H3a1 1 0 01-1-1z"/><path d="M9 3v3h3"/>
              </svg>
              {attachedFile ? attachedFile.name.slice(0, 20) + (attachedFile.name.length > 20 ? "…" : "") : "Attach file"}
            </button>
            {attachedFile && (
              <button onClick={() => { setAttachedFile(null); attachedFileRef.current = null; }} style={{ width:20, height:20, borderRadius:"50%", border:"1px solid rgba(255,255,255,0.1)", background:"rgba(255,255,255,0.05)", color:"rgba(255,255,255,0.4)", cursor:"pointer", fontSize:11, display:"flex", alignItems:"center", justifyContent:"center" }}>×</button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════
   SCREEN: RESUME REVIEW — drag-drop upload + full analysis
═══════════════════════════════════════════════════ */
type ResumeStep = "choose"|"job"|"upload"|"paste"|"analyzing"|"results";
type CareerLevel = "entry"|"mid"|"senior"|"executive";

type ResumeScores = { overall: number; ats: number; impact: number; clarity: number };
type ResumeBullet = { before: string; after: string; reason: string; oldScore: number; newScore: number; difficulty?: "easy"|"medium"|"hard" };
type ResumeSection = { label: string; text: string; score: number; originalText?: string; rationale?: string[] };
type ResumeFinding = { type: "critical"|"warn"|"ok"; category?: string; text: string };
type ResumeKeyword = { word: string; found: boolean; importance: "required"|"preferred"; skillType?: "technical"|"soft"|"tool"|"certification"|"domain"; context?: string };
type ResumeSectionScore = { name: string; present: boolean; score: number; verdict: string };
type ResumeWordIssue = { word: string; count: number; type: "repetition"|"filler"|"weak_verb"|"cliche"; suggestion: string };
type ResumeQuickWin = { title: string; action: string; effort: string; impact: "high"|"medium"; tab: "overview"|"bullets"|"rewrite"|"keywords"; bulletRef?: string };
type ResumeBulletStats = { total: number; withMetrics: number; withStrongVerbs: number; weak: number };
type ResumeAnalysis = ResumeScores & {
  findings: ResumeFinding[];
  bullets: ResumeBullet[];
  recommendation: string;
  rewrittenSections: ResumeSection[];
  keywords?: ResumeKeyword[];
  previousScores?: ResumeScores | null;
  tailoredScore?: number;
  bulletStats?: ResumeBulletStats;
  sectionScores?: ResumeSectionScore[];
  quickWins?: ResumeQuickWin[];
  wordIssues?: ResumeWordIssue[];
};
type ResumeHistoryEntry = {
  id: string; filename: string; submittedAt: string;
  mode: string; targetRole?: string;
  scores: ResumeScores;
};
type MagicWriteMode = "refine"|"describe"|"variations";
type MagicWriteState = {
  mode: MagicWriteMode;
  input: string;
  results: string[];
  loading: boolean;
  copied: number | null;
};

/* ─── Resume HTML generator: produces a print-ready styled HTML document ─── */
function escHtml(s: string) {
  return s.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");
}

function generateResumeHtml(text: string, footerNote = "", showPrintHint = false): string {
  // Strip browser print artifacts that get baked into PDFs printed from the browser
  // e.g. "4/21/26, 11:08 PM Resume", "about:blank 1/3", standalone "Resume" title line
  text = text.split("\n").filter(line => {
    const t = line.trim();
    if (/^\d{1,2}\/\d{1,2}\/\d{2,4},\s+\d+:\d+\s+(?:AM|PM)/i.test(t)) return false;
    if (/^about:blank/i.test(t)) return false;
    if (/^\d+\/\d+$/.test(t)) return false;
    return true;
  }).join("\n");

  // Strip raw Markdown and broken Unicode that can leak through AI output
  text = text
    .replace(/\*\*([^*]+)\*\*/g, "$1")
    .replace(/__([^_]+)__/g, "$1")
    .replace(/\*([^*\n]+)\*/g, "$1")
    .replace(/[­﻿​‌‍⁠￰-￿]/g, "")
    .replace(/[‐-―−]/g, "-");

  // ── Regexes ──────────────────────────────────────────────────
  const BULLET_RE    = /^[•\-\*\u2022►▸→]\s/;
  const DATE_RE      = /\b(Jan(?:uary)?|Feb(?:ruary)?|Mar(?:ch)?|Apr(?:il)?|May|Jun(?:e)?|Jul(?:y)?|Aug(?:ust)?|Sep(?:tember)?|Oct(?:ober)?|Nov(?:ember)?|Dec(?:ember)?|\d{4})\b.{0,40}\b(20\d{2}|19\d{2}|Present|Current|Now)\b/i;
  // Matches a trailing date range at the end of a long line, e.g.:
  // "Foundation Finance Company Sr. DevOps Manager July 2025 - Present"
  const TRAILING_DATE_RE = /^(.{8,}?)\s{2,}((?:Jan(?:uary)?|Feb(?:ruary)?|Mar(?:ch)?|Apr(?:il)?|May|Jun(?:e)?|Jul(?:y)?|Aug(?:ust)?|Sep(?:tember)?|Oct(?:ober)?|Nov(?:ember)?|Dec(?:ember)?)\s+\d{4}(?:\s*[-–—]\s*(?:(?:Jan(?:uary)?|Feb(?:ruary)?|Mar(?:ch)?|Apr(?:il)?|May|Jun(?:e)?|Jul(?:y)?|Aug(?:ust)?|Sep(?:tember)?|Oct(?:ober)?|Nov(?:ember)?|Dec(?:ember)?)\s+)?\d{0,4}(?:Present|Current|Now)?)?)\s*$/i;
  const CONTACT_RE   = /@|\(\d{3}\)|\d{3}[\-.\s]\d{3}[\-.\s]\d{4}|linkedin\.com|github\.com/i;
  const SKILL_CAT_RE = /^[A-Za-z][A-Za-z\s&]{2,35}:\s+\S/;
  const NAME_RE      = /^[A-Z][A-Z\s\.]{3,39}[A-Z]$/;

  // Known section titles — matched case-insensitively
  const KNOWN_SECTIONS = [
    "PROFESSIONAL SUMMARY","SUMMARY","OBJECTIVE","PROFILE","ABOUT",
    "SKILLS","TECHNICAL SKILLS","CORE COMPETENCIES","KEY SKILLS","AREAS OF EXPERTISE",
    "PROFESSIONAL EXPERIENCE","EXPERIENCE","EMPLOYMENT HISTORY","WORK EXPERIENCE",
    "EDUCATION","ACADEMIC BACKGROUND",
    "CERTIFICATIONS","CERTIFICATION","LICENSES","LICENSURE",
    "PROJECTS","AWARDS","ACHIEVEMENTS","ACCOMPLISHMENTS",
    "VOLUNTEER","COMMUNITY","INTERESTS","ACTIVITIES","REFERENCES","PUBLICATIONS","CONTACT",
  ];

  // Canonical section render order (matches substring of title)
  const SECTION_ORDER = [
    "SUMMARY","OBJECTIVE","PROFILE","ABOUT",
    "COMPETENCIES","SKILL","EXPERTISE",
    "EXPERIENCE","EMPLOYMENT","WORK",
    "EDUCATION","ACADEMIC",
    "CERTIFICATION","LICENSE",
    "PROJECT","AWARD","ACHIEVEMENT","ACCOMPLISHMENT",
    "VOLUNTEER","COMMUNITY","INTEREST","ACTIVIT","REFERENCE","PUBLICATION","CONTACT",
  ];

  const SECTION_VOCAB = /\b(EXPERIENCE|EDUCATION|CERTIFICATION|LICENSE|SKILL|SUMMARY|OBJECTIVE|AWARD|PROJECT|VOLUNTEER|REFERENCE|PUBLICATION|EMPLOYMENT|HISTORY|WORK|ACADEMIC|BACKGROUND|COMPETENC|EXPERTISE|INTEREST|ACTIVIT|COMMUNITY|CONTACT|PROFILE|ABOUT)\b/;

  const isSectionHeader = (t: string): boolean => {
    if (!t) return false;
    const u = t.toUpperCase().trim();
    // Exact match against known section keywords
    if (KNOWN_SECTIONS.includes(u)) return true;
    // General ALL-CAPS: must contain a recognised section word (prevents names & job titles matching)
    return /^[A-Z][A-Z\s&\/\-]{2,49}$/.test(u)
      && u.split(/\s+/).length <= 5
      && !/\d/.test(u)
      && !/\bPRESENT\b|\bCURRENT\b/.test(u)
      && SECTION_VOCAB.test(u);
  };

  const sectionRank = (title: string): number => {
    const u = title.toUpperCase();
    for (let i = 0; i < SECTION_ORDER.length; i++) {
      if (u.includes(SECTION_ORDER[i])) return i;
    }
    return 999;
  };

  // ── Phase 1: split into header + sections ──────────────────
  interface Sec { title: string; lines: string[]; }
  const headerLines: string[] = [];
  const sections: Sec[] = [];
  let cur: Sec | null = null;
  let inHeader = true;

  for (const raw of text.split("\n")) {
    const t = raw.trim();
    // Drop ASCII separator lines (====, ----, ____) — HTML uses CSS section borders
    if (/^[=\-_]{4,}$/.test(t)) continue;
    if (isSectionHeader(t)) {
      inHeader = false;
      cur = { title: t, lines: [] };
      sections.push(cur);
    } else if (inHeader) {
      if (t) headerLines.push(t);
    } else if (cur) {
      cur.lines.push(t);
    }
  }

  // ── Phase 2: sort sections into canonical order ────────────
  sections.sort((a, b) => sectionRank(a.title) - sectionRank(b.title));

  // ── Phase 3: render section content lines ─────────────────
  // autoBullet: experience/work sections auto-wrap body paragraphs as <li>
  // isEdu: education sections get bold school / italic degree formatting
  function renderLines(lines: string[], autoBullet = false, isEdu = false): string {
    // Pre-join: if a line doesn't end in sentence punctuation and the NEXT line
    // starts with lowercase, merge them (handles PDF-wrapped long sentences).
    const joined: string[] = [];
    for (let i = 0; i < lines.length; i++) {
      const t = lines[i].trim();
      if (!t) { joined.push(""); continue; }
      let combined = t;
      while (
        i + 1 < lines.length &&
        !/[.!?]$/.test(combined) &&
        lines[i + 1].trim().length > 0 &&
        /^[a-z]/.test(lines[i + 1].trim())
      ) {
        i++;
        combined += " " + lines[i].trim();
      }
      joined.push(combined);
    }

    let html = "";
    let inList = false;
    // pending: either a company/title label, or "__date__<dateStr>" when a date
    // line appears before its company name (common in this PDF's extraction order).
    let pending: string | null = null;
    let afterJobEntry = false;
    let inJobBlock = false;
    // Education state: tracks whether we're expecting a school name or degree name
    let eduState: "school" | "degree" = "school";
    let inEduList = false;

    const openJobBlock  = () => { if (!inJobBlock) { html += '<div class="job-block">\n'; inJobBlock = true; } };
    const closeJobBlock = () => { if (inJobBlock)  { html += '</div>\n'; inJobBlock = false; } };
    const closeList = () => { if (inList) { html += "</ul>\n"; inList = false; closeJobBlock(); } };
    const closeEduList = () => { if (inEduList) { if (eduState === "degree") { html += `</li>\n`; eduState = "school"; } html += "</ul>\n"; inEduList = false; } };
    const flushPending = (date?: string) => {
      if (pending === null) return;
      const isDatePending = pending.startsWith("__date__");
      if (isDatePending) {
        // Stored date waiting for a company name that never came — emit standalone
        html += `<p class="date-standalone">${escHtml(pending.slice(8))}</p>\n`;
      } else if (date) {
        closeJobBlock(); openJobBlock();
        html += `<div class="job-hdr"><span class="company">${escHtml(pending)}</span><span class="date-r">${escHtml(date)}</span></div>\n`;
        afterJobEntry = true;
      } else {
        html += `<p class="bold-line">${escHtml(pending)}</p>\n`;
        afterJobEntry = true;
      }
      pending = null;
    };

    for (const t of joined) {
      if (!t) {
        if (isEdu) {
          // Between edu entries: close unclosed entry but keep list open for next entry
          if (eduState === "degree") { html += `</li>\n`; eduState = "school"; }
        } else {
          closeList(); flushPending();
        }
        html += "<br>\n";
        continue;
      }

      // Drop ASCII separator lines — HTML uses CSS section borders
      if (/^[=\-_]{4,}$/.test(t)) { closeList(); flushPending(); continue; }

      // ── Education: bullet list with bold school + italic degree ─────────
      if (isEdu) {
        const stripped = t.replace(/^[•\u2022►▸→\-*]\s*/, "").trim();
        if (!stripped) continue;
        if (eduState === "school") {
          if (!inEduList) { html += '<ul class="education-list">\n'; inEduList = true; }
          html += `  <li><strong>${escHtml(stripped)}</strong>`;
          eduState = "degree";
        } else {
          html += `<br><em>${escHtml(stripped)}</em></li>\n`;
          eduState = "school";
        }
        continue;
      }

      // ── Job title misformatted as bullet: only when no title is already buffered (pending===null) ──
      if (!inList && afterJobEntry && pending === null && /^[•\u2022►▸→]/.test(t)) {
        const titleText = t.replace(/^[•\u2022►▸→\-*]\s*/, "");
        if (titleText.length < 90 && titleText.split(/\s+/).length <= 10) {
          flushPending();
          html += `<p class="bold-line">${escHtml(titleText)}</p>\n`;
          afterJobEntry = false; // prevent next real bullet from also being caught
          continue;
        }
      }

      // Bullet: char-only (no space required) OR hyphen/asterisk with space
      if (/^[•\u2022►▸→]/.test(t) || /^[-*]\s/.test(t)) {
        flushPending();
        if (!inList) { html += "<ul>\n"; inList = true; afterJobEntry = false; }
        html += `  <li>${escHtml(t.replace(/^[•\u2022►▸→\-*]\s*/, ""))}</li>\n`;
        continue;
      }
      closeList();

      if (CONTACT_RE.test(t) && t.length < 160) {
        flushPending(); html += `<p class="contact">${escHtml(t)}</p>\n`; continue;
      }

      if (SKILL_CAT_RE.test(t) && t.length < 200) {
        flushPending();
        const ci = t.indexOf(":");
        html += `<p class="skill-line"><strong>${escHtml(t.slice(0, ci))}:</strong>${escHtml(t.slice(ci + 1))}</p>\n`;
        continue;
      }

      // Long single-line entry: "Company Title  Month Year - Year/Present"
      // Two or more spaces between title and date (common in PDF text extraction)
      if (t.length >= 30 && TRAILING_DATE_RE.test(t) && !BULLET_RE.test(t)) {
        const m = t.match(TRAILING_DATE_RE)!;
        closeList();
        flushPending();
        closeJobBlock(); openJobBlock();
        html += `<div class="job-hdr"><span class="company">${escHtml(m[1].trim())}</span><span class="date-r">${escHtml(m[2].trim())}</span></div>\n`;
        afterJobEntry = true;
        continue;
      }

      if (DATE_RE.test(t) && t.length < 90) {
        if (pending !== null && !pending.startsWith("__date__")) {
          // Company name is buffered → emit job-hdr (company left, date right)
          flushPending(t);
        } else {
          // Date arrives before company name → store it, wait for company on next line
          flushPending(); // flush any leftover date-pending first
          pending = `__date__${t}`;
        }
        continue;
      }

      // Short line without trailing sentence punctuation → company name or job title.
      // Lines ending in period/comma are sentence tails and must NOT be bolded.
      if (t.length < 80 && t.split(/\s+/).length <= 7 && !/[.,:;]$/.test(t)) {
        if (pending && pending.startsWith("__date__")) {
          // A date was waiting — this short line IS the company name → job-hdr
          const savedDate = pending.slice(8);
          html += `<div class="job-hdr"><span class="company">${escHtml(t)}</span><span class="date-r">${escHtml(savedDate)}</span></div>\n`;
          pending = null;
          afterJobEntry = true;
        } else {
          flushPending();
          pending = t;
        }
        continue;
      }

      // Auto-bullet: in experience sections, body paragraphs after a job entry → <li>
      if (autoBullet && afterJobEntry) {
        flushPending();
        if (!inList) { html += "<ul>\n"; inList = true; }
        html += `  <li>${escHtml(t)}</li>\n`;
        continue;
      }

      flushPending();
      html += `<p>${escHtml(t)}</p>\n`;
    }
    closeEduList();
    closeList();
    flushPending();
    closeJobBlock();
    return html;
  }

  // ── Phase 4: render header ─────────────────────────────────
  let headerHtml = "";
  for (const t of headerLines) {
    if (
      NAME_RE.test(t) &&
      t.split(/\s+/).length >= 2 &&
      t.split(/\s+/).length <= 6 &&
      !/\b(EXPERIENCE|EDUCATION|SKILLS|SUMMARY|CERTIFICATIONS?|EMPLOYMENT|PROFESSIONAL|OBJECTIVE)\b/i.test(t)
    ) {
      headerHtml += `<p class="name">${escHtml(t)}</p>\n`;
    } else {
      headerHtml += `<p class="contact">${escHtml(t)}</p>\n`;
    }
  }

  // ── Phase 5: assemble ──────────────────────────────────────
  let body = headerHtml;
  for (const sec of sections) {
    body += `<div class="sec-hdr">${escHtml(sec.title.toUpperCase())}</div>\n`;
    const isExpSec = /experience|employment|work/i.test(sec.title);
    const isEduSec = /education|academic/i.test(sec.title);
    body += renderLines(sec.lines, isExpSec, isEduSec);
  }

  const footer = footerNote ? `\n<p class="footer">${escHtml(footerNote)}</p>` : "";

  return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<title> </title>
<style>
  *,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
  @page{size:letter;margin:0.70in 0.75in 0.75in 0.75in}
  html,body{background:#fff}
  body{font-family:Arial,Calibri,Aptos,Helvetica,sans-serif;font-size:10pt;line-height:1.15;color:#000}
  @media screen{body{padding:0.70in 0.75in 0.75in 0.75in;max-width:8.5in;margin:0 auto}}
  @media print{body{margin:0;padding:0;max-width:none}}
  .name{font-size:26pt;font-weight:700;text-align:center;letter-spacing:0.5pt;text-transform:uppercase;margin-bottom:3pt}
  .contact{text-align:center;font-size:10pt;line-height:1.2;color:#000;margin-bottom:2pt}
  .sec-hdr{font-weight:700;text-align:center;border-top:1.5px solid #000;border-bottom:1.5px solid #000;padding:3pt 0;margin:9pt 0 5pt;letter-spacing:0.5pt;text-transform:uppercase;font-size:12pt;break-after:avoid;page-break-after:avoid}
  .job-block{margin-top:7pt;margin-bottom:7pt;break-inside:avoid;page-break-inside:avoid}
  .job-hdr{display:flex;justify-content:space-between;align-items:baseline;font-weight:700;break-after:avoid;page-break-after:avoid}
  .company{font-size:10pt;text-align:left}
  .date-r{font-size:10pt;font-weight:400;white-space:nowrap;margin-left:8pt}
  .date-standalone{font-size:10pt;margin-bottom:2pt}
  .bold-line{font-weight:600;margin-top:1pt;margin-bottom:3pt;font-size:10pt;break-after:avoid;page-break-after:avoid}
  .skill-line{margin-bottom:2pt;line-height:1.15;font-size:10pt}
  ul{margin:0 0 0 14pt;padding:0;list-style-type:disc;orphans:3;widows:3}
  li{margin-bottom:2pt;padding-left:2pt;line-height:1.15;orphans:3;widows:3}
  p{margin-bottom:2pt;line-height:1.15;orphans:3;widows:3}
  .education-entry{margin-bottom:3pt;break-inside:avoid;page-break-inside:avoid}
  ul.education-list{margin:2pt 0 0 14pt;padding:0;list-style-type:disc}
  ul.education-list li{margin-bottom:6pt;break-inside:avoid;page-break-inside:avoid;line-height:1.4}
  .certifications{margin-top:2pt}
  br{display:block;margin:2pt 0;content:""}
  .footer{margin-top:20pt;font-size:8.5pt;color:#aaa;text-align:center;border-top:1px solid #eee;padding-top:6pt}
  @media print{.footer{display:none}.no-print,.no-print *{display:none!important;visibility:hidden!important}#resume{display:block!important;visibility:visible!important}body{background:white!important}}
</style>
</head>
<body>
${showPrintHint ? `<div class="no-print" id="zari-print-guide" style="position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.72);display:flex;align-items:center;justify-content:center;font-family:Arial,sans-serif"><div style="background:#fff;border-radius:14px;padding:30px 34px;max-width:420px;width:90vw;box-shadow:0 24px 80px rgba(0,0,0,0.4);text-align:center"><p style="font-size:18px;font-weight:700;margin:0 0 6px;color:#111">Save Resume as PDF</p><p style="font-size:12.5px;color:#555;margin:0 0 18px;line-height:1.5">Follow these steps to remove the browser header/footer from your PDF:</p><ol style="text-align:left;font-size:13px;color:#222;margin:0 0 22px;padding-left:20px;line-height:2"><li>Click <strong>Print / Save as PDF</strong> below</li><li>Set Destination to <strong>Save as PDF</strong></li><li>Expand <strong>More settings</strong></li><li>Uncheck <strong>Headers and footers</strong></li><li>Click <strong>Save</strong></li></ol><button onclick="document.getElementById('zari-print-guide').style.display='none';window.print()" style="width:100%;padding:13px;background:#2563EB;color:#fff;border:none;border-radius:8px;font-size:14px;font-weight:700;cursor:pointer;letter-spacing:-0.01em">Print / Save as PDF &rarr;</button></div></div>` : ""}
<div id="resume">\n${body}${footer}\n</div>
</body>
</html>`;
}

// ── Structured resume data returned by the AI (template approach) ────────────
type ResumeStructuredData = {
  name: string;
  phone?: string;
  email?: string;
  location?: string;
  summary?: string;
  skills: Array<{ category: string; items: string[] }>;
  experience: Array<{ company: string; dates: string; title: string; bullets: string[] }>;
  education: Array<{ school: string; degree: string }>;
  certifications: string[];
};

/** Serialize structured data back to plain text (used for re-analysis). */
function serializeToPlainText(d: ResumeStructuredData): string {
  const lines: string[] = [];
  lines.push(d.name);
  const contact = [d.phone, d.email, d.location].filter(Boolean).join(" · ");
  if (contact) lines.push(contact);
  lines.push("");
  if (d.summary) { lines.push("PROFESSIONAL SUMMARY"); lines.push(d.summary); lines.push(""); }
  if (d.skills.length) {
    lines.push("SKILLS");
    d.skills.forEach(s => lines.push(`${s.category}: ${s.items.join(", ")}`));
    lines.push("");
  }
  if (d.experience.length) {
    lines.push("PROFESSIONAL EXPERIENCE");
    d.experience.forEach(e => {
      lines.push(`${e.company}  ${e.dates}`);
      lines.push(e.title);
      e.bullets.forEach(b => lines.push(`• ${b}`));
      lines.push("");
    });
  }
  if (d.education.length) {
    lines.push("EDUCATION");
    d.education.forEach(e => { lines.push(`• ${e.school}`); lines.push(`  ${e.degree}`); lines.push(""); });
  }
  if (d.certifications.length) { lines.push("CERTIFICATIONS"); lines.push(d.certifications.join(" • ")); }
  return lines.join("\n").trim();
}

/** Render structured resume data into a locked HTML template.
 *  The AI produces content; this function owns ALL layout decisions. */
function renderResumeTemplate(d: ResumeStructuredData, showPrintHint = false): string {
  const e = escHtml;
  const contact = [d.phone, d.email, d.location].filter(Boolean).map(s => e(s!)).join(" &middot; ");

  const skillsHtml = d.skills.map(s =>
    `<p class="skills-line"><span class="skills-cat">${e(s.category)}:</span> ${s.items.map(e).join(", ")}</p>`
  ).join("");

  const expHtml = d.experience.map(ex => `
<div class="job-block">
  <div class="job-header"><span class="company">${e(ex.company)}</span><span class="dates">${e(ex.dates)}</span></div>
  <div class="job-title">${e(ex.title)}</div>
  <ul class="bullets">${ex.bullets.map(b => `<li>${e(b)}</li>`).join("")}</ul>
</div>`).join("\n");

  const eduHtml = d.education.map(ed => `
<div class="edu-entry">
  <div class="edu-school">${e(ed.school)}</div>
  <div class="edu-degree">${e(ed.degree)}</div>
</div>`).join("\n");

  const certsHtml = d.certifications.length
    ? `<div class="section-header">CERTIFICATIONS</div><p class="certs">${d.certifications.map(e).join(" &bull; ")}</p>`
    : "";

  const printGuide = showPrintHint
    ? `<div class="no-print" id="zari-print-guide" style="position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.72);display:flex;align-items:center;justify-content:center;font-family:Arial,sans-serif"><div style="background:#fff;border-radius:14px;padding:30px 34px;max-width:420px;width:90vw;box-shadow:0 24px 80px rgba(0,0,0,0.4);text-align:center"><p style="font-size:18px;font-weight:700;margin:0 0 6px;color:#111">Save Resume as PDF</p><p style="font-size:12.5px;color:#555;margin:0 0 18px;line-height:1.5">Follow these steps to remove browser headers/footers from your PDF:</p><ol style="text-align:left;font-size:13px;color:#222;margin:0 0 22px;padding-left:20px;line-height:2"><li>Set Destination to <strong>Save as PDF</strong></li><li>Click <strong>More settings</strong></li><li>Uncheck <strong>Headers and footers</strong></li><li>Click <strong>Save</strong></li></ol><button onclick="document.getElementById('zari-print-guide').style.display='none';window.print()" style="width:100%;padding:13px;background:#2563EB;color:#fff;border:none;border-radius:8px;font-size:14px;font-weight:700;cursor:pointer">Print / Save as PDF &rarr;</button></div></div>`
    : "";

  return `<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<title></title>
<style>
@page { size: letter; margin: 0.75in 0.80in; }
*,*::before,*::after{box-sizing:border-box}
body{font-family:Calibri,Arial,sans-serif;font-size:10.5pt;color:#111;margin:0;padding:0;line-height:1.35}
#resume{padding:0}
.name{font-size:17pt;font-weight:900;text-transform:uppercase;text-align:center;letter-spacing:0.07em;margin-bottom:3pt}
.contact{text-align:center;font-size:9.5pt;color:#444;margin-bottom:14pt}
.section-header{display:flex;align-items:center;font-size:10pt;font-weight:900;text-transform:uppercase;letter-spacing:0.1em;color:#222;margin:13pt 0 5pt;white-space:nowrap}
.section-header::before,.section-header::after{content:'';flex:1;border-top:1pt solid #999}
.section-header::before{margin-right:7pt}
.section-header::after{margin-left:7pt}
.summary{font-size:10.5pt;line-height:1.5;margin:0}
.skills-line{margin:0 0 2pt;font-size:10pt;line-height:1.5}
.skills-cat{font-weight:700}
.job-block{margin-bottom:8pt;break-inside:avoid;page-break-inside:avoid}
.job-header{display:flex;justify-content:space-between;align-items:baseline}
.company{font-weight:700;font-size:10.5pt}
.dates{font-size:10pt;color:#333;white-space:nowrap;padding-left:8pt}
.job-title{font-style:italic;font-size:10.5pt;margin:1pt 0 3pt}
.bullets{margin:2pt 0 0 16pt;padding:0}
.bullets li{margin-bottom:2.5pt;line-height:1.42}
.edu-entry{margin-bottom:5pt;break-inside:avoid;page-break-inside:avoid}
.edu-school{font-weight:700;font-size:10.5pt}
.edu-degree{font-style:italic;font-size:10pt;color:#333;margin-top:1pt}
.certs{font-size:10pt;margin:0;line-height:1.5}
@media print{.no-print,.no-print *{display:none!important;visibility:hidden!important}#resume{display:block!important}}
</style>
</head>
<body>
${printGuide}
<div id="resume">
<div class="name">${e(d.name)}</div>
${contact ? `<div class="contact">${contact}</div>` : ""}
${d.summary ? `<div class="section-header">PROFESSIONAL SUMMARY</div><p class="summary">${e(d.summary)}</p>` : ""}
${d.skills.length ? `<div class="section-header">SKILLS</div>${skillsHtml}` : ""}
${d.experience.length ? `<div class="section-header">PROFESSIONAL EXPERIENCE</div>${expHtml}` : ""}
${d.education.length ? `<div class="section-header">EDUCATION</div>${eduHtml}` : ""}
${certsHtml}
</div>
</body>
</html>`;
}

const RESUME_SESSION_KEY = "zari_resume_session_v2";
const RESUME_PDF_KEY     = "zari_resume_pdf_v2";
function loadResumeSession(): { resumeText:string; fileName:string; aiResult:ResumeAnalysis; reviewMode:"general"|"targeted"; targetRoleInput:string; careerLevel:CareerLevel } | null {
  try {
    const raw = localStorage.getItem(RESUME_SESSION_KEY);
    if (!raw) return null;
    const s = JSON.parse(raw) as { resumeText:string; fileName:string; aiResult:ResumeAnalysis; reviewMode:"general"|"targeted"; targetRoleInput:string; careerLevel:CareerLevel; savedAt:string };
    // Expire sessions older than 7 days
    if (Date.now() - new Date(s.savedAt).getTime() > 7 * 86400_000) { localStorage.removeItem(RESUME_SESSION_KEY); return null; }
    return s;
  } catch { return null; }
}

type PromotionReadinessVerdict = "Ready now" | "Close, but not airtight" | "Needs more proof" | "Too early";
type PromotionAuditTab = "overview" | "gaps" | "plan" | "conversation" | "examples";

type PromotionReadinessResult = {
  readinessScore: number;
  verdict: PromotionReadinessVerdict;
  summary: string;
  realityCheck: string;
  scoreReason: string;
  dimensions: Array<{ label: string; score: number; reason: string }>;
  rationale: string[];
  strengths: string[];
  gaps: Array<{ area: string; why: string; nextStep: string }>;
  managerQuestions: string[];
  nextMoves: string[];
  conversationPairs?: Array<{ theyMightSay: string; yourResponse: string }>;
  quickWins: Array<{ title: string; body: string; jumpTo: PromotionAuditTab }>;
  evidenceChecklist: string[];
  exampleEvidence: string[];
  managerPitchExample: string;
  actionPlan: Array<{ label: string; action: string }>;
  riskFlags: string[];
};

type PromotionReadinessForm = {
  currentTitle: string;
  desiredTitle: string;
  timeInRole: string;
  roleDescription: string;
  rubricClarity: string;
  recentProjects: string;
  scopeLevel: string;
  impactLevel: string;
  reviewSignal: string;
  reviewSummary: string;
  managerSupport: string;
  visibilityLevel: string;
  blockers: string;
};

type PromotionReadinessOption = {
  value: string;
  label: string;
  description: string;
};

