/* ═══════════════════════════════════════════════════
   SCREEN: COVER LETTER
═══════════════════════════════════════════════════ */
function ScreenCoverLetter({ stage, active = false, onNavigate }: { stage: CareerStage; active?: boolean; onNavigate?: (s: string) => void }) {
  const billing = useBillingCtx();
  if (stage === "promotion")  return <FeatureGate featureName="zari_promotion_doc"><ScreenPromotionDocument active={active} onNavigate={onNavigate} /></FeatureGate>;
  if (stage === "salary")     return <FeatureGate featureName="zari_negotiation_email"><ScreenSalaryNegotiationEmail /></FeatureGate>;
  if (stage === "leadership") return <FeatureGate stage="leadership"><ScreenExecOutreach /></FeatureGate>;

  const CL_KEY = "zari_cl_session_v1";
  type TailoringNote = { decision: string; impact: string };
  type KeyStrength   = { strength: string; evidence: string };
  type CLResult = { subject: string; coverLetter: string; tailoringNotes?: (TailoringNote|string)[]; keyStrengths?: (KeyStrength|string)[]; openingHook?: string };
  type CLSaved = { step: number; profileText: string; profileFile: string; jobDesc: string; company: string; targetRole: string; candidateName: string; tone: string; result: CLResult | null; editedLetter: string; stage: CareerStage };
  const _clSaved = lsGet<CLSaved>(CL_KEY);
  // Only restore if the saved session is for the same stage
  const _cl = _clSaved?.stage === stage ? _clSaved : null;
  const [step,          setStep]          = useState<1|2|3>((_cl?.step as 1|2|3) ?? 1);
  const [profileText,   setProfileText]   = useState(_cl?.profileText ?? "");
  const [profileFile,   setProfileFile]   = useState(_cl?.profileFile ?? "");
  const [profileDrag,   setProfileDrag]   = useState(false);
  const profileInputRef = useRef<HTMLInputElement>(null);
  const [jobDesc,       setJobDesc]       = useState(_cl?.jobDesc ?? "");
  const [jdMode,        setJdMode]        = useState<"paste"|"url">("paste");
  const [jobUrl,        setJobUrl]        = useState("");
  const [fetchingUrl,   setFetchingUrl]   = useState(false);
  const [urlFetchErr,   setUrlFetchErr]   = useState("");
  const [company,       setCompany]       = useState(_cl?.company ?? "");
  const [targetRole,    setTargetRole]    = useState(_cl?.targetRole ?? "");
  const [candidateName, setCandidateName] = useState(_cl?.candidateName ?? "");
  const [tone,          setTone]          = useState<"professional"|"conversational"|"enthusiastic">((_cl?.tone as "professional"|"conversational"|"enthusiastic") ?? "professional");
  const [generating,    setGenerating]    = useState(false);
  const [result,        setResult]        = useState<CLResult | null>(_cl?.result ?? null);
  const [editMode,      setEditMode]      = useState(false);
  const [editedLetter,  setEditedLetter]  = useState(_cl?.editedLetter ?? "");
  const [copied,        setCopied]        = useState(false);
  const [error,         setError]         = useState("");
  const [showDlMenu,    setShowDlMenu]    = useState(false);
  type CLSnap = { id:string; subject:string; company:string; targetRole:string; tone:string; stage:string; coverLetter:string; tailoringNotes?:{decision:string;impact:string}[]; keyStrengths?:{strength:string;evidence:string}[]; openingHook?:string; createdAt:string };
  const CL_HISTORY_KEY = "zari_cl_history_v1";
  const [clHistory,     setClHistory]     = useState<CLSnap[]>(() => {
    try { return JSON.parse(localStorage.getItem(CL_HISTORY_KEY) ?? "[]") as CLSnap[]; } catch { return []; }
  });
  const [clMainTab,     setClMainTab]     = useState<"letter"|"history">("letter");

  // Load Cover Letter snapshot history: localStorage hydrates immediately, server merges on top
  useEffect(() => {
    fetch("/api/zari/cover-letter/snapshots").then(r=>r.json()).then((d:{snapshots?:CLSnap[]}) => {
      if (d.snapshots && d.snapshots.length > 0) {
        setClHistory(d.snapshots);
        try { localStorage.setItem(CL_HISTORY_KEY, JSON.stringify(d.snapshots)); } catch { /* storage full */ }
      }
    }).catch(()=>{});
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Persist session whenever meaningful state changes
  useEffect(() => {
    if (profileText || jobDesc || result) {
      lsSet(CL_KEY, { step, profileText, profileFile, jobDesc, company, targetRole, candidateName, tone, result, editedLetter, stage });
    }
  }, [step, profileText, jobDesc, company, targetRole, candidateName, tone, result, editedLetter]); // eslint-disable-line react-hooks/exhaustive-deps

  // Restore previous cover letter session when server state syncs on login
  useEffect(() => {
    const onSynced = () => {
      if (result || profileText) return;
      const synced = lsGet<CLSaved>(CL_KEY);
      if (!synced || synced.stage !== stage) return;
      if (synced.result) {
        setStep(3); setProfileText(synced.profileText ?? ""); setProfileFile(synced.profileFile ?? "");
        setJobDesc(synced.jobDesc ?? ""); setCompany(synced.company ?? "");
        setTargetRole(synced.targetRole ?? ""); setCandidateName(synced.candidateName ?? "");
        setTone((synced.tone as "professional"|"conversational"|"enthusiastic") ?? "professional");
        setResult(synced.result); setEditedLetter(synced.editedLetter ?? "");
      } else if (synced.profileText || synced.jobDesc) {
        setStep((synced.step as 1|2|3) ?? 1); setProfileText(synced.profileText ?? "");
        setJobDesc(synced.jobDesc ?? ""); setCompany(synced.company ?? "");
        setTargetRole(synced.targetRole ?? ""); setCandidateName(synced.candidateName ?? "");
        setTone((synced.tone as "professional"|"conversational"|"enthusiastic") ?? "professional");
      }
    };
    window.addEventListener("zari-state-synced", onSynced);
    return () => window.removeEventListener("zari-state-synced", onSynced);
  }, [result, profileText, stage]); // eslint-disable-line react-hooks/exhaustive-deps


  async function handleUpload(file: File) {
    setProfileFile(file.name);
    try {
      const fd = new FormData(); fd.append("file", file);
      const res = await fetch("/api/zari/extract", { method:"POST", body:fd });
      const data = await res.json().catch(() => ({})) as { text?: string };
      if (data.text) setProfileText(data.text); else setProfileFile("");
    } catch { setProfileFile(""); }
  }

  async function fetchJd() {
    if (!jobUrl.trim()) return;
    setFetchingUrl(true); setUrlFetchErr("");
    try {
      const res = await fetch("/api/zari/fetch-url", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ url:jobUrl.trim() }) });
      const data = await res.json().catch(() => ({})) as { text?: string; error?: string };
      if (data.text) { setJobDesc(data.text); setUrlFetchErr(""); }
      else setUrlFetchErr(data.error ?? "Couldn't extract text — paste instead.");
    } catch { setUrlFetchErr("Couldn't reach that URL — paste instead."); }
    setFetchingUrl(false);
  }

  async function generate() {
    if (generating) return;
    setGenerating(true); setError(""); setResult(null);
    try {
      const res = await fetch("/api/zari/cover-letter", {
        method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ profileText, jobDescription:jobDesc, company, targetRole, tone, candidateName }),
      });
      const data = await res.json().catch(() => null) as { subject?: string; coverLetter?: string; tailoringNotes?: (TailoringNote|string)[]; keyStrengths?: (KeyStrength|string)[]; openingHook?: string; error?: string } | null;
      if (data?.coverLetter) {
        const newResult = { subject:data.subject ?? "", coverLetter:data.coverLetter, tailoringNotes:data.tailoringNotes, keyStrengths:data.keyStrengths, openingHook:data.openingHook };
        setResult(newResult); setEditedLetter(data.coverLetter);
        lsSet(CL_KEY, { step, profileText, profileFile, jobDesc, company, targetRole, candidateName, tone, result: newResult, editedLetter: data.coverLetter, stage });
        // Save to doc vault
        vaultSave({ type:"cover-letter", name:data.subject||targetRole||"Cover Letter", content:data.coverLetter, meta:{ subject:data.subject??"", targetRole, company, tone, stage } });
        // Save to cover letter snapshot history
        const clSnapPayload = { subject: data.subject ?? "", company, targetRole, tone, stage, coverLetter: data.coverLetter, tailoringNotes: (data.tailoringNotes ?? []).map(n => typeof n === "string" ? { decision: n, impact: "" } : n as { decision: string; impact: string }), keyStrengths: (data.keyStrengths ?? []).map(s => typeof s === "string" ? { strength: s, evidence: "" } : s as { strength: string; evidence: string }), openingHook: data.openingHook ?? "" };
        const localSnap: CLSnap = { id: `cl_local_${Date.now()}`, ...clSnapPayload, createdAt: new Date().toISOString() };
        setClHistory(prev => {
          const next = [localSnap, ...prev].slice(0, 10);
          try { localStorage.setItem(CL_HISTORY_KEY, JSON.stringify(next)); } catch { /* storage full */ }
          return next;
        });
        fetch("/api/zari/cover-letter/snapshots", { method:"POST", headers:{"Content-Type":"application/json"}, body: JSON.stringify(clSnapPayload) }).then(r=>r.json()).then((d:{id?:string}) => { if (d.id) setClHistory(prev => { const next = prev.map(s => s.id === localSnap.id ? { ...s, id: d.id! } : s); try { localStorage.setItem(CL_HISTORY_KEY, JSON.stringify(next)); } catch { /* ignore */ } return next; }); }).catch(()=>{}); }
      else if (!handleBillingApiError(res.status, data as BillingApiErrorData, billing)) setError(data?.error ?? "Generation failed — try again.");
    } catch { setError("Something went wrong — try again."); }
    setGenerating(false);
  }

  function copy() {
    const text = editMode ? editedLetter : (result?.coverLetter ?? "");
    navigator.clipboard.writeText(text).then(() => { setCopied(true); setTimeout(() => setCopied(false), 2000); });
  }
  function getLetterText() { return editMode ? editedLetter : (result?.coverLetter ?? ""); }
  function safeName() { return (targetRole || "cover_letter").replace(/\s+/g,"_"); }

  function buildLetterHtml(forPrint: boolean) {
    const text = getLetterText();
    const subject = result?.subject ?? "Cover Letter";
    const esc = (s: string) => s.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");

    if (forPrint) {
      const lines = text.split("\n");
      const closingKw = ["best regards","sincerely","warm regards","kind regards","respectfully"];
      let closingIdx = -1;
      for (let i = lines.length - 1; i >= 0; i--) {
        if (closingKw.some(k => lines[i].toLowerCase().includes(k))) { closingIdx = i; break; }
      }
      const bodyLines    = closingIdx > -1 ? lines.slice(0, closingIdx) : lines;
      const closingLines = closingIdx > -1 ? lines.slice(closingIdx)    : [];

      const bodyHtml = bodyLines.map(l =>
        l.trim() ? "<p>" + esc(l) + "</p>" : "<div class=\"gap\"></div>"
      ).join("");

      const sigHtml = closingLines.filter(l => l.trim()).map((l, i) =>
        i === 0
          ? "<p class=\"closing\">" + esc(l) + "</p>"

          : "<div class=\"sig\">" + esc(l) + "</div>"
      ).join("");

      const today = new Date().toLocaleDateString("en-US", { month:"long", day:"numeric", year:"numeric" });
      const gfont = "https://fonts.googleapis.com/css2?family=Dancing+Script:wght@600&display=swap";

      return [
        "<!DOCTYPE html><html><head>",
        "<meta charset=\"UTF-8\">",
        "<title>", esc(subject), "</title>",
        "<link rel=\"stylesheet\" href=\"", gfont, "\">",
        "<style>",
        "@page{margin:0;size:A4;}",
        "*{margin:0;padding:0;box-sizing:border-box;}",
        "body{font-family:Georgia,'Times New Roman',serif;font-size:10.5pt;line-height:1.68;color:#1a1a1a;padding:2.4cm 3.2cm 2.2cm;}",
        ".meta{margin-bottom:0.55cm;}",
        ".subject-label{font-size:7.5pt;font-weight:700;color:#999;letter-spacing:0.14em;text-transform:uppercase;margin-bottom:0.12cm;}",
        ".subject-val{font-size:11pt;font-weight:700;color:#111;margin-bottom:0.18cm;}",
        ".date{font-size:9pt;color:#aaa;}",
        ".divider{height:1px;background:#e8e8e8;margin:0.45cm 0 0.55cm;}",
        "p{margin-bottom:0.32cm;}",
        ".gap{height:0.18cm;}",
        ".closing{margin-top:0.55cm;margin-bottom:0.05cm;}",
        ".sig{font-family:'Dancing Script','Brush Script MT',cursive;font-size:26pt;color:#1a1a1a;line-height:1.2;margin-top:0.1cm;}",
        "@media print{@page{margin:0;size:A4;}body{padding:2.4cm 3.2cm 2.2cm;}}",
        "</style>",
        "<scr" + "ipt>",
        "window.onload=function(){",
        "  if(document.fonts&&document.fonts.ready){",
        "    document.fonts.ready.then(function(){setTimeout(function(){window.print();},200);});",
        "  } else { setTimeout(function(){window.print();},600); }",
        "};",
        "</scr" + "ipt>",
        "</head><body>",
        "<div class=\"meta\">",
        "<div class=\"subject-label\">Cover Letter</div>",
        "<div class=\"subject-val\">", esc(subject), "</div>",
        "<div class=\"date\">", today, "</div>",
        "</div>",
        "<div class=\"divider\"></div>",
        bodyHtml,
        sigHtml,
        "</body></html>",
      ].join("");
    }

    // Word (.doc) version
    const lines = text.split("\n").map(l =>
      l.trim() ? "<p>" + esc(l) + "</p>" : "<p style=\"margin:0;height:9pt\"></p>"
    ).join("");
    return [
      "<!DOCTYPE html><html><head>",
      "<meta charset=\"UTF-8\">",
      "<style>body{font-family:Calibri,Arial,sans-serif;font-size:11pt;line-height:1.6;margin:2.5cm;}p{margin:0 0 9pt;}</style>",
      "</head><body>", lines, "</body></html>",
    ].join("");
  }

  function downloadWord() {
    const blob = new Blob([buildLetterHtml(false)], { type:"application/msword" });
    const a = document.createElement("a"); a.href = URL.createObjectURL(blob);
    a.download = safeName() + ".doc"; a.click();
  }

  function downloadPdf() {
    const win = window.open("","_blank");
    if (!win) return;
    win.document.write(buildLetterHtml(true));
    win.document.close();
  }

  const STEP_TITLES    = ["Your background", "Job description", "Customize"];
  const STEP_SUBTITLES = [
    "Paste your resume or LinkedIn profile — Zari uses this to write in your voice.",
    "The job posting gives Zari the context to tailor every sentence.",
    "Add the company, role, and the tone that fits the culture.",
  ];

  // ── Show result page once generated ──
  if (result || generating) return (
    <div style={{ height:"100%", overflow:"auto", background:"var(--z-raise)" }}>
      {/* Page header */}
      <div style={{ background:"var(--z-card)", borderBottom:"1px solid var(--z-bd)", padding:"16px 28px" }}>
        <div style={{ display:"flex", alignItems:"center", gap:12 }}>
          <div style={{ width:32, height:32, borderRadius:10, background:"rgba(16,185,129,0.18)", border:"1px solid rgba(16,185,129,0.35)", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
            <svg viewBox="0 0 24 24" fill="none" stroke="#34D399" strokeWidth="1.8" style={{ width:16,height:16 }}><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/><polyline points="10 9 9 9 8 9"/></svg>
          </div>
          <div style={{ flex:1 }}>
            <h1 style={{ fontSize:18, fontWeight:900, color:"var(--z-text)", letterSpacing:"-0.02em", margin:0 }}>Cover Letter</h1>
            <p style={{ fontSize:13, color:"var(--z-text3)", margin:0 }}>AI-tailored letter written in your voice from your background.</p>
          </div>
          <div style={{ display:"flex", gap:8, alignItems:"center" }}>
            <div style={{ display:"flex", background:"var(--z-raise)", border:"1px solid var(--z-bd)", borderRadius:9, padding:3, gap:2 }}>
              {(["letter","history"] as const).map(t => (
                <button key={t} onClick={()=>setClMainTab(t)} style={{ fontSize:12, fontWeight:600, padding:"5px 14px", borderRadius:6, border:"none", background:clMainTab===t?"var(--z-card)":"transparent", color:clMainTab===t?"var(--z-text)":"var(--z-text3)", cursor:"pointer", transition:"all 0.15s", textTransform:"capitalize", boxShadow:clMainTab===t?"0 1px 4px rgba(0,0,0,0.08)":"none" }}>
                  {t === "history" ? `History${clHistory.length > 0 ? ` (${clHistory.length})` : ""}` : "Letter"}
                </button>
              ))}
            </div>
            <button onClick={()=>{ setResult(null); setGenerating(false); setStep(1); setClMainTab("letter"); }}
              style={{ padding:"7px 16px", borderRadius:8, background:"var(--z-raise)", border:"1px solid var(--z-bd)", color:"var(--z-text2)", fontSize:12.5, fontWeight:600, cursor:"pointer" }}>
              New letter
            </button>
          </div>
        </div>
      </div>
      <div style={{ padding:"24px 32px 48px" }}>
        {/* ── Cover Letter History tab ── */}
        {clMainTab === "history" && !generating && (
          <div>
            {clHistory.length === 0 ? (
              <div style={{ display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", minHeight:300, gap:12 }}>
                <div style={{ width:48, height:48, borderRadius:14, background:"var(--z-card)", border:"1px solid var(--z-bd)", display:"flex", alignItems:"center", justifyContent:"center" }}>
                  <svg viewBox="0 0 24 24" fill="none" stroke="var(--z-text3)" strokeWidth="1.6" style={{width:22,height:22}}><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg>
                </div>
                <p style={{ fontSize:14, fontWeight:600, color:"var(--z-text2)", margin:0 }}>No past letters yet</p>
                <p style={{ fontSize:13, color:"var(--z-text3)", margin:0 }}>Your generated cover letters will appear here.</p>
                <button onClick={()=>setClMainTab("letter")} style={{ fontSize:13, fontWeight:700, padding:"9px 22px", borderRadius:10, border:"none", background:"#2563EB", color:"white", cursor:"pointer", marginTop:4 }}>Write a letter →</button>
              </div>
            ) : (
              <div style={{ display:"flex", flexDirection:"column", gap:0 }}>
                <div style={{ marginBottom:20 }}>
                  <h2 style={{ fontSize:20, fontWeight:900, color:"var(--z-text)", letterSpacing:"-0.03em", margin:"0 0 4px" }}>Past Cover Letters</h2>
                  <p style={{ fontSize:13, color:"var(--z-text3)", margin:0 }}>Your last {clHistory.length} generated letter{clHistory.length!==1?"s":""}</p>
                </div>
                <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
                {clHistory.map((snap, idx) => {
                  const wordCount = snap.coverLetter.trim().split(/\s+/).length;
                  const d = new Date(snap.createdAt);
                  const dateStr = d.toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"});
                  const timeStr = d.toLocaleTimeString("en-US",{hour:"numeric",minute:"2-digit"});
                  const isLatest = idx === 0;
                  const toneMap: Record<string,{color:string;bg:string;border:string;label:string}> = {
                    professional:  { color:"#2563EB", bg:"rgba(37,99,235,0.08)",  border:"rgba(37,99,235,0.25)",  label:"Professional"  },
                    conversational:{ color:"#7C3AED", bg:"rgba(124,58,237,0.08)", border:"rgba(124,58,237,0.25)", label:"Conversational" },
                    enthusiastic:  { color:"#D97706", bg:"rgba(217,119,6,0.08)",  border:"rgba(217,119,6,0.25)",  label:"Enthusiastic"  },
                  };
                  const tm = toneMap[snap.tone] ?? toneMap.professional;
                  const excerpt = snap.coverLetter.replace(/\s+/g," ").trim().slice(0, 180);
                  return (
                    <div key={snap.id} style={{ background:"var(--z-card)", border:`1px solid ${isLatest ? tm.color+"55" : "var(--z-bd)"}`, borderRadius:18, overflow:"hidden", boxShadow: isLatest ? `0 0 0 1px ${tm.color}18, 0 6px 28px rgba(0,0,0,0.09)` : "0 2px 10px rgba(0,0,0,0.05)", transition:"box-shadow 0.15s" }}>
                      {/* Top accent stripe */}
                      <div style={{ height:3, background:`linear-gradient(90deg,${tm.color},${tm.color}88)` }}/>
                      <div style={{ padding:"20px 22px" }}>
                        {/* Header row */}
                        <div style={{ display:"flex", alignItems:"flex-start", gap:12, marginBottom:12 }}>
                          {/* Letter icon */}
                          <div style={{ width:40, height:40, borderRadius:12, background:tm.bg, border:`1px solid ${tm.border}`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, marginTop:2 }}>
                            <svg viewBox="0 0 20 20" fill="none" stroke={tm.color} strokeWidth="1.8" style={{width:18,height:18}}><path d="M17 4H3a1 1 0 00-1 1v10a1 1 0 001 1h14a1 1 0 001-1V5a1 1 0 00-1-1z"/><path d="M1 5l9 7 9-7"/></svg>
                          </div>
                          <div style={{ flex:1, minWidth:0 }}>
                            <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:5, flexWrap:"wrap" }}>
                              {isLatest && <span style={{ fontSize:9, fontWeight:800, color:tm.color, background:tm.bg, border:`1px solid ${tm.border}`, padding:"2px 8px", borderRadius:99, textTransform:"uppercase", letterSpacing:"0.06em", flexShrink:0 }}>Latest</span>}
                              <span style={{ fontSize:15, fontWeight:800, color:"var(--z-text)", letterSpacing:"-0.02em", lineHeight:1.3 }}>{snap.subject || "Cover Letter"}</span>
                            </div>
                            <div style={{ display:"flex", gap:6, flexWrap:"wrap", alignItems:"center" }}>
                              <span style={{ fontSize:11, fontWeight:700, color:tm.color, background:tm.bg, border:`1px solid ${tm.border}`, padding:"2px 9px", borderRadius:99, textTransform:"capitalize" }}>{tm.label} tone</span>
                              {snap.targetRole && <span style={{ fontSize:11.5, color:"var(--z-text2)", fontWeight:600 }}>{snap.targetRole}</span>}
                              {snap.company && <span style={{ fontSize:11.5, color:"var(--z-text3)" }}>· {snap.company}</span>}
                            </div>
                          </div>
                          <div style={{ flexShrink:0, textAlign:"right" }}>
                            <div style={{ fontSize:20, fontWeight:900, color:tm.color, letterSpacing:"-0.03em", lineHeight:1 }}>{wordCount}</div>
                            <div style={{ fontSize:10, color:"var(--z-text3)", fontWeight:600, marginTop:2 }}>words</div>
                          </div>
                        </div>
                        {/* Excerpt */}
                        <p style={{ fontSize:12.5, color:"var(--z-text2)", lineHeight:1.65, margin:"0 0 14px", display:"-webkit-box", WebkitLineClamp:2, WebkitBoxOrient:"vertical" as const, overflow:"hidden" }}>{excerpt}{excerpt.length < snap.coverLetter.trim().length ? "…" : ""}</p>
                        {/* Footer row */}
                        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:12, flexWrap:"wrap" }}>
                          <span style={{ fontSize:11.5, color:"var(--z-text3)" }}>{dateStr} · {timeStr}</span>
                          <div style={{ display:"flex", gap:8, flexShrink:0 }}>
                            <button
                              onClick={() => { navigator.clipboard.writeText(snap.coverLetter); }}
                              style={{ fontSize:12, fontWeight:600, padding:"6px 12px", borderRadius:9, border:"1px solid var(--z-bd)", background:"var(--z-raise)", color:"var(--z-text2)", cursor:"pointer", display:"flex", alignItems:"center", gap:5 }}>
                              <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.8" style={{width:12,height:12}}><rect x="5" y="2" width="9" height="11" rx="1.5"/><path d="M3 4H2a1 1 0 00-1 1v9a1 1 0 001 1h9a1 1 0 001-1v-1"/></svg>
                              Copy
                            </button>
                            <button
                              onClick={() => {
                                const blob = new Blob([snap.coverLetter], { type:"text/plain" });
                                const a = document.createElement("a"); a.href = URL.createObjectURL(blob);
                                a.download = `cover_letter_${(snap.targetRole||snap.subject||"letter").replace(/\s+/g,"_")}_${dateStr.replace(/\s/g,"_")}.txt`; a.click();
                              }}
                              style={{ fontSize:12, fontWeight:600, padding:"6px 12px", borderRadius:9, border:"1px solid var(--z-bd)", background:"var(--z-raise)", color:"var(--z-text2)", cursor:"pointer", display:"flex", alignItems:"center", gap:5 }}>
                              <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.8" style={{width:12,height:12}}><path d="M8 3v7M5 7l3 3 3-3"/><path d="M2 12h12"/></svg>
                              Download
                            </button>
                            <button
                              onClick={() => {
                                setResult({ subject:snap.subject, coverLetter:snap.coverLetter, tailoringNotes:snap.tailoringNotes, keyStrengths:snap.keyStrengths, openingHook:snap.openingHook }); setEditedLetter(snap.coverLetter);
                                setCompany(snap.company); setTargetRole(snap.targetRole); setTone(snap.tone as "professional"|"conversational"|"enthusiastic");
                                setClMainTab("letter");
                              }}
                              style={{ fontSize:12, fontWeight:700, padding:"6px 16px", borderRadius:9, border:`1px solid ${tm.color}`, background:tm.bg, color:tm.color, cursor:"pointer" }}>
                              View letter →
                            </button>
                          </div>
                        </div>
                      </div>
                    </div>
                  );
                })}
                </div>
              </div>
            )}
          </div>
        )}
        {clMainTab === "letter" && generating ? (
          <div style={{ background:"var(--z-card)", borderRadius:20, padding:"72px 32px", textAlign:"center", boxShadow:"0 8px 40px rgba(0,0,0,0.09)", border:"1px solid var(--z-bd)" }}>
            <div style={{ display:"flex", gap:8, justifyContent:"center", marginBottom:20 }}>
              {[0,1,2].map(i=><div key={i} style={{ width:11,height:11,borderRadius:"50%",background:"#2563EB",animation:`dot-bounce 1.2s ease-in-out ${i*0.2}s infinite`,  }}/>)}
            </div>
            <p style={{ fontSize:17, fontWeight:800, color:"var(--z-text)", marginBottom:8, letterSpacing:"-0.02em" }}>Zari is writing your letter…</p>
            <p style={{ fontSize:13.5, color:"var(--z-text3)" }}>Tailoring every sentence to your background and the role</p>
          </div>
        ) : clMainTab === "letter" && result && (
          <>
            {/* ── Hero header ── */}
            <div style={{ background:"var(--z-card)", borderRadius:14, padding:"22px 28px", marginBottom:20, border:"1px solid var(--z-bd)", borderTop:"3px solid #059669", position:"relative", overflow:"hidden" }}>
              <div style={{ position:"absolute", top:-40, right:-20, width:160, height:160, background:"radial-gradient(circle,rgba(5,150,105,0.08) 0%,transparent 70%)", pointerEvents:"none" }}/>
              <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:16, flexWrap:"wrap", position:"relative" }}>
                <div>
                  <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:8 }}>
                    <span style={{ fontSize:9.5, fontWeight:800, color:"#059669", background:"rgba(5,150,105,0.1)", border:"1px solid rgba(5,150,105,0.25)", padding:"2px 9px", borderRadius:99, textTransform:"uppercase", letterSpacing:"0.08em" }}>Letter Ready</span>
                    <span style={{ fontSize:9.5, fontWeight:700, color:"var(--z-text3)", background:"var(--z-raise)", border:"1px solid var(--z-bd)", padding:"2px 9px", borderRadius:99, textTransform:"capitalize" }}>{tone} tone</span>
                    {!editMode && result.coverLetter && (
                      <span style={{ fontSize:9.5, fontWeight:700, color:"var(--z-text3)", background:"var(--z-raise)", border:"1px solid var(--z-bd)", padding:"2px 9px", borderRadius:99 }}>~{result.coverLetter.trim().split(/\s+/).length} words</span>
                    )}
                  </div>
                  <p style={{ fontSize:17, fontWeight:800, color:"var(--z-text)", letterSpacing:"-0.025em", margin:0 }}>{result.subject || "Cover Letter"}</p>
                  {(company||targetRole) && (
                    <p style={{ fontSize:12.5, color:"var(--z-text2)", marginTop:4 }}>
                      {[targetRole, company].filter(Boolean).join(" · ")}
                    </p>
                  )}
                </div>
                <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
                  <button onClick={()=>{ setResult(null); setStep(1); }} style={{ fontSize:12, fontWeight:600, padding:"7px 14px", borderRadius:9, border:"1px solid var(--z-bd)", background:"var(--z-raise)", color:"var(--z-text2)", cursor:"pointer" }}>← Start over</button>
                  <button onClick={()=>setEditMode(e=>!e)} style={{ fontSize:12, fontWeight:600, padding:"7px 14px", borderRadius:9, border:`1px solid ${editMode?"#2563EB":"var(--z-bd)"}`, background:editMode?"#EFF6FF":"var(--z-raise)", color:editMode?"#2563EB":"var(--z-text2)", cursor:"pointer" }}>{editMode?"Preview":"Edit"}</button>
                  <button onClick={copy} style={{ fontSize:12, fontWeight:600, padding:"7px 14px", borderRadius:9, border:"1px solid var(--z-bd)", background:"var(--z-raise)", color:copied?"#2563EB":"var(--z-text2)", cursor:"pointer", transition:"all 0.2s" }}>{copied?"✓ Copied":"Copy"}</button>
                  <div style={{ position:"relative" }}>
                    <button onClick={()=>setShowDlMenu(m=>!m)} style={{ fontSize:12, fontWeight:700, padding:"7px 18px", borderRadius:9, border:"1px solid var(--z-bd)", background:"#2563EB", color:"white", cursor:"pointer", display:"flex", alignItems:"center", gap:6 }}>
                      Download
                      <svg viewBox="0 0 10 6" fill="none" stroke="currentColor" strokeWidth="2" style={{width:10,height:10,transition:"transform 0.15s",transform:showDlMenu?"rotate(180deg)":"rotate(0deg)"}}><path d="M1 1l4 4 4-4"/></svg>
                    </button>
                    {showDlMenu && (
                      <div style={{ position:"absolute", top:"calc(100% + 6px)", right:0, background:"var(--z-raise)", border:"1px solid var(--z-bd)", borderRadius:12, boxShadow:"0 12px 40px rgba(0,0,0,0.15)", overflow:"hidden", minWidth:150, zIndex:99 }}>
                        <button onClick={()=>{ downloadPdf(); setShowDlMenu(false); }} style={{ width:"100%", padding:"11px 16px", border:"none", background:"transparent", textAlign:"left", fontSize:13, fontWeight:600, color:"var(--z-text)", cursor:"pointer", display:"flex", alignItems:"center", gap:9, borderBottom:"1px solid var(--z-bd2)" }}>
                          <svg viewBox="0 0 16 16" fill="none" stroke="#DC2626" strokeWidth="1.6" style={{width:15,height:15,flexShrink:0}}><rect x="2" y="1" width="10" height="13" rx="1.5"/><path d="M5 5h4M5 7.5h4M5 10h2.5"/><path d="M10 1v3h2" strokeLinejoin="round"/></svg>
                          PDF
                        </button>
                        <button onClick={()=>{ downloadWord(); setShowDlMenu(false); }} style={{ width:"100%", padding:"11px 16px", border:"none", background:"transparent", textAlign:"left", fontSize:13, fontWeight:600, color:"var(--z-text)", cursor:"pointer", display:"flex", alignItems:"center", gap:9 }}>
                          <svg viewBox="0 0 16 16" fill="none" stroke="#2563EB" strokeWidth="1.6" style={{width:15,height:15,flexShrink:0}}><rect x="2" y="1" width="10" height="13" rx="1.5"/><path d="M5 5h4M5 7.5h4M5 10h4"/><path d="M10 1v3h2" strokeLinejoin="round"/></svg>
                          Word
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>

            {/* ── AI Tailoring Insights ── */}
            {(result.tailoringNotes?.length || result.keyStrengths?.length) && (
              <div style={{ display:"grid", gap:14, marginBottom:20 }}>
                {result.tailoringNotes?.length ? (
                  <div style={{ background:"var(--z-card)", borderRadius:14, border:"1px solid var(--z-bd)", borderLeft:"4px solid #2563EB", padding:"18px 20px" }}>
                    <p style={{ fontSize:10.5, fontWeight:800, color:"#2563EB", textTransform:"uppercase", letterSpacing:"0.1em", margin:"0 0 14px" }}>What Zari tailored</p>
                    <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
                      {result.tailoringNotes.map((rawNote, i) => {
                        const note: TailoringNote = typeof rawNote === "string"
                          ? { decision: rawNote, impact: "" }
                          : rawNote as TailoringNote;
                        return (
                          <div key={i} style={{ borderRadius:11, background:"var(--z-raise)", border:"1px solid var(--z-bd)", overflow:"hidden" }}>
                            <div style={{ padding:"11px 13px 9px", display:"flex", gap:9, alignItems:"flex-start" }}>
                              <span style={{ fontSize:10, fontWeight:800, color:"#2563EB", background:"rgba(37,99,235,0.1)", border:"1px solid rgba(37,99,235,0.2)", borderRadius:99, width:20, height:20, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, marginTop:1 }}>{i+1}</span>
                              <p style={{ fontSize:13, fontWeight:700, color:"var(--z-text)", lineHeight:1.65, margin:0 }}>{note.decision}</p>
                            </div>
                            {note.impact && (
                              <div style={{ padding:"7px 13px 11px", borderTop:"1px solid var(--z-bd)", background:"rgba(37,99,235,0.03)" }}>
                                <p style={{ fontSize:12, color:"var(--z-text2)", lineHeight:1.65, margin:0 }}>{note.impact}</p>
                              </div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ) : null}
                {result.keyStrengths?.length ? (
                  <div style={{ background:"var(--z-card)", borderRadius:14, border:"1px solid var(--z-bd)", borderLeft:"4px solid #059669", padding:"18px 20px" }}>
                    <p style={{ fontSize:10.5, fontWeight:800, color:"#059669", textTransform:"uppercase", letterSpacing:"0.1em", margin:"0 0 14px" }}>Strengths highlighted</p>
                    <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
                      {result.keyStrengths.map((rawS, i) => {
                        const s: KeyStrength = typeof rawS === "string"
                          ? { strength: rawS, evidence: "" }
                          : rawS as KeyStrength;
                        return (
                          <div key={i} style={{ borderRadius:11, background:"var(--z-raise)", border:"1px solid var(--z-bd)", overflow:"hidden" }}>
                            <div style={{ padding:"11px 13px 9px", display:"flex", gap:9, alignItems:"flex-start" }}>
                              <div style={{ flexShrink:0, width:20, height:20, borderRadius:999, background:"rgba(5,150,105,0.1)", border:"1px solid rgba(5,150,105,0.25)", display:"flex", alignItems:"center", justifyContent:"center", marginTop:1 }}>
                                <svg viewBox="0 0 10 10" fill="none" stroke="#059669" strokeWidth="2.5" style={{ width:8,height:8 }}><path d="M1.5 5l2.5 2.5L8.5 2"/></svg>
                              </div>
                              <p style={{ fontSize:13, fontWeight:700, color:"var(--z-text)", lineHeight:1.65, margin:0 }}>{s.strength}</p>
                            </div>
                            {s.evidence && (
                              <div style={{ padding:"7px 13px 11px", borderTop:"1px solid var(--z-bd)", background:"rgba(5,150,105,0.03)" }}>
                                <p style={{ fontSize:12, color:"var(--z-text2)", lineHeight:1.65, margin:0, fontStyle:"italic" }}>{s.evidence}</p>
                              </div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ) : null}
              </div>
            )}
            {/* ── No-insights notice (history letter saved before insights were persisted) ── */}
            {!result.tailoringNotes?.length && !result.keyStrengths?.length && !result.openingHook && (
              <div style={{ background:"var(--z-card)", borderRadius:12, border:"1px solid var(--z-bd)", borderLeft:"3px solid #2563EB", padding:"13px 18px", marginBottom:20, display:"flex", gap:12, alignItems:"center" }}>
                <svg viewBox="0 0 16 16" fill="none" stroke="#2563EB" strokeWidth="1.8" style={{ width:15,height:15,flexShrink:0 }}><circle cx="8" cy="8" r="7"/><path d="M8 5v3M8 10.5v.5" strokeLinecap="round"/></svg>
                <p style={{ fontSize:12.5, color:"var(--z-text2)", margin:0, lineHeight:1.5 }}>
                  AI tailoring insights — the decisions Zari made and key strengths highlighted — are available on newly generated letters. Generate a new letter to see the full analysis.
                </p>
              </div>
            )}

            {/* ── Opening hook highlight ── */}
            {result.openingHook && (
              <div style={{ background:"rgba(37,99,235,0.03)", borderRadius:12, border:"1px solid rgba(37,99,235,0.15)", padding:"14px 18px", marginBottom:20, display:"flex", gap:12, alignItems:"flex-start" }}>
                <svg viewBox="0 0 16 16" fill="none" stroke="#2563EB" strokeWidth="1.8" style={{ width:14,height:14,flexShrink:0,marginTop:2 }}><path d="M2 3h12M2 7h8M2 11h10"/></svg>
                <div>
                  <span style={{ fontSize:10, fontWeight:800, color:"#2563EB", textTransform:"uppercase", letterSpacing:"0.08em", display:"block", marginBottom:5 }}>Opening hook</span>
                  <p style={{ fontSize:13, color:"var(--z-text2)", lineHeight:1.65, fontStyle:"italic", margin:0 }}>&ldquo;{result.openingHook}&rdquo;</p>
                </div>
              </div>
            )}

            {/* ── Letter paper document ── */}
            <div style={{ background:"var(--z-raise)", borderRadius:10, boxShadow:"0 8px 40px rgba(0,0,0,0.4)", border:"1px solid var(--z-bd)", overflow:"hidden" }}>
              <div style={{ padding:"52px 56px 56px", fontFamily:"Georgia,'Times New Roman',serif" }}>
                {editMode ? (
                  <textarea style={{ width:"100%", minHeight:560, border:"1.5px solid #D9DFF0", borderRadius:10, padding:"16px", fontSize:14, lineHeight:1.9, color:"var(--z-text)", outline:"none", resize:"vertical", fontFamily:"Georgia,'Times New Roman',serif", boxSizing:"border-box" }}
                    value={editedLetter} onChange={e=>setEditedLetter(e.target.value)}/>
                ) : (
                  <div style={{ fontSize:14, lineHeight:1.95, color:"var(--z-text)", fontFamily:"inherit", whiteSpace:"pre-wrap" }}>{result.coverLetter}</div>
                )}
              </div>
            </div>
          </>
        )}
        {error && <p style={{ fontSize:13, color:"#DC2626", textAlign:"center", marginTop:16 }}>{error} <button onClick={()=>void generate()} style={{ background:"none", border:"none", color:"#2563EB", fontWeight:600, cursor:"pointer", fontSize:13 }}>Try again</button></p>}
      </div>
    </div>
  );

  // ── Setup wizard ──
  const CL_STEP_CTX = [
    { icon:"file",   label:"Your background", desc:"Zari writes in your voice — the more context you give it about your background, the more personalized your letter.", tips:["Paste your resume or LinkedIn About section","A full background lets Zari match your tone and story","Upload a PDF if that's easier than pasting"] },
    { icon:"target", label:"Job description", desc:"The job posting is the brief. Zari tailors every sentence to the specific role, not a generic version of the letter.", tips:["Paste the full posting for the best match","Use the URL fetcher if you have a link","Longer postings give Zari more to work with"] },
    { icon:"edit",   label:"Customize", desc:"Role details and tone shape the letter's opening, sign-off, and overall register — small inputs, big impact.", tips:["Add the company name so Zari uses it naturally","Your name appears in the closing signature","Pick the tone that fits the company's culture"] },
  ];
  const clCtx = CL_STEP_CTX[step - 1];

  return (
    <div style={{ height:"100%", overflow:"auto", background:"var(--z-raise)" }}>
      <input ref={profileInputRef} type="file" accept=".pdf,.docx,.txt" style={{ display:"none" }}
        onChange={e=>{ const f=e.target.files?.[0]; if(f) { void handleUpload(f); } e.target.value=""; }}/>

      {/* Page header */}
      <div style={{ background:"var(--z-card)", borderBottom:"1px solid var(--z-bd)", padding:"16px 28px" }}>
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:20, flexWrap:"wrap" }}>
          <div>
            <h1 style={{ fontSize:22, fontWeight:800, color:"var(--z-text)", letterSpacing:"-0.03em", margin:"0 0 4px" }}>Cover Letter</h1>
            <p style={{ fontSize:13, color:"var(--z-text2)", margin:0 }}>AI-tailored letter written in your voice.</p>
          </div>
          {/* Step progress bar */}
          <div style={{ display:"flex", alignItems:"center" }}>
            {([1,2,3] as const).map(s => (
              <div key={s} style={{ display:"flex", alignItems:"center" }}>
                <div style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:5 }}>
                  <div style={{ width:28, height:28, borderRadius:"50%", border:`1.5px solid ${s <= step ? "#2563EB" : "var(--z-bd)"}`, background:s < step ? "#2563EB" : "var(--z-card)", display:"flex", alignItems:"center", justifyContent:"center", transition:"all 0.2s" }}>
                    {s < step
                      ? <svg viewBox="0 0 12 12" fill="none" stroke="white" strokeWidth="2.5" style={{width:11,height:11}}><polyline points="2,6 5,9 10,3"/></svg>
                      : <span style={{ fontSize:11, fontWeight:700, color:s === step ? "#2563EB" : "var(--z-text3)" }}>{s}</span>
                    }
                  </div>
                  <span style={{ fontSize:10, fontWeight:600, color:s === step ? "#2563EB" : "var(--z-text3)", letterSpacing:"0.04em", whiteSpace:"nowrap" }}>{CL_STEP_CTX[s-1].label}</span>
                </div>
                {s < 3 && <div style={{ width:36, height:1, background:s < step ? "#2563EB" : "var(--z-bd)", margin:"0 6px", marginBottom:18 }}/>}
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Two-column body */}
      <div style={{ padding:"24px 32px 48px", display:"grid", gridTemplateColumns:"1fr 300px", gap:28, alignItems:"start" }}>

        {/* LEFT: form */}
        <div style={{ background:"var(--z-card)", border:"1px solid var(--z-bd)", borderRadius:20, padding:"28px 28px 24px", boxShadow:"0 2px 20px rgba(0,0,0,0.07)" }}>
          <div style={{ marginBottom:24 }}>
            <h2 style={{ fontSize:20, fontWeight:900, color:"var(--z-text)", letterSpacing:"-0.03em", margin:"0 0 6px" }}>{STEP_TITLES[step-1]}</h2>
            <p style={{ fontSize:13.5, color:"var(--z-text2)", lineHeight:1.6, margin:0 }}>{STEP_SUBTITLES[step-1]}</p>
          </div>

          {/* ── Step 1: Background ── */}
          {step === 1 && (
            <div style={{ display:"flex", flexDirection:"column", gap:16 }}>
              {/* Feature list */}
              <div style={{ borderRadius:12, background:"var(--z-card)", border:"1px solid var(--z-bd)", padding:"16px 20px" }}>
                <div style={{ fontSize:10.5, fontWeight:700, color:"var(--z-text3)", letterSpacing:"0.08em", textTransform:"uppercase", marginBottom:10 }}>What Zari writes for you</div>
                <div style={{ display:"flex", flexDirection:"column", gap:7 }}>
                  {["Written in your actual voice","Tailored to the specific role","Ready to send in minutes"].map((text,i) => (
                    <div key={i} style={{ display:"flex", alignItems:"center", gap:8 }}>
                      <svg viewBox="0 0 10 10" fill="none" stroke="#2563EB" strokeWidth="2" style={{width:12,height:12,flexShrink:0}}><path d="M1.5 5l2.5 2.5 4.5-4.5"/></svg>
                      <span style={{ fontSize:13, color:"var(--z-text2)", fontWeight:500 }}>{text}</span>
                    </div>
                  ))}
                </div>
              </div>

              {profileFile ? (
                <div style={{ background:"var(--z-card)", border:"1px solid var(--z-bd)", borderRadius:14, padding:"16px 20px", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
                  <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                    <div style={{ width:40, height:40, borderRadius:10, background:"var(--z-raise)", border:"1px solid var(--z-bd)", display:"flex", alignItems:"center", justifyContent:"center" }}>
                      <svg viewBox="0 0 20 20" fill="none" stroke="var(--z-text2)" strokeWidth="2" style={{ width:18,height:18 }}><path d="M13 2H5a1.5 1.5 0 00-1.5 1.5v13A1.5 1.5 0 005 18h10a1.5 1.5 0 001.5-1.5V6L13 2z"/><polyline points="4,11 7,14 11,9"/></svg>
                    </div>
                    <div>
                      <p style={{ fontSize:14, fontWeight:700, color:"var(--z-text)", margin:0 }}>{profileFile}</p>
                      <p style={{ fontSize:11.5, color:"#16A34A", margin:0, fontWeight:600 }}>✓ Uploaded successfully</p>
                    </div>
                  </div>
                  <label style={{ fontSize:12, fontWeight:600, color:"var(--z-text2)", cursor:"pointer", padding:"7px 16px", borderRadius:10, border:"1px solid var(--z-bd)", background:"var(--z-card)", boxShadow:"0 2px 8px rgba(0,0,0,0.06)", flexShrink:0 }}>
                    Replace<input type="file" accept=".pdf,.docx,.txt" style={{ display:"none" }} onChange={e=>{ const f=e.target.files?.[0]; if(f) void handleUpload(f); e.target.value=""; }}/>
                  </label>
                </div>
              ) : (
                <>
                  <div
                    onClick={()=>profileInputRef.current?.click()}
                    onDragOver={e=>{ e.preventDefault(); setProfileDrag(true); }}
                    onDragLeave={()=>setProfileDrag(false)}
                    onDrop={e=>{ e.preventDefault(); setProfileDrag(false); const f=e.dataTransfer.files?.[0]; if(f) void handleUpload(f); }}
                    style={{ background:profileDrag?"var(--z-raise)":"var(--z-card)", border:`1.5px dashed ${profileDrag?"#2563EB":"var(--z-bd)"}`, borderRadius:14, padding:"36px 24px", cursor:"pointer", textAlign:"center", transition:"all 0.15s" }}>
                    <div style={{ width:44, height:44, borderRadius:12, background:"var(--z-raise)", border:"1px solid var(--z-bd)", display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 14px" }}>
                      <svg viewBox="0 0 24 24" fill="none" stroke="var(--z-text2)" strokeWidth="1.8" style={{ width:20,height:20 }}><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="12" y1="18" x2="12" y2="12"/><polyline points="9 15 12 18 15 15"/></svg>
                    </div>
                    <p style={{ fontSize:15, fontWeight:700, color:"var(--z-text)", marginBottom:5, letterSpacing:"-0.02em" }}>{profileDrag ? "Drop your file here" : "Upload your resume or LinkedIn PDF"}</p>
                    <p style={{ fontSize:12.5, color:"var(--z-text2)", marginBottom:14 }}>Drag and drop, or click to browse</p>
                    <span style={{ fontSize:13, fontWeight:700, padding:"9px 22px", borderRadius:10, background:"#2563EB", color:"white", border:"none" }}>Choose file · PDF, DOCX, TXT</span>
                  </div>
                  <p style={{ textAlign:"center", fontSize:12, color:"var(--z-text3)", margin:0 }}>— or paste your background below —</p>
                  <textarea
                    style={{ width:"100%", minHeight:120, border:"1.5px solid var(--z-bd)", borderRadius:14, padding:"13px 16px", fontSize:14, color:"var(--z-text)", outline:"none", resize:"vertical", fontFamily:"inherit", boxSizing:"border-box", background:"var(--z-raise)", lineHeight:1.65, transition:"border-color 0.15s" }}
                    placeholder="Paste your resume text, LinkedIn About section, or a summary of your background…"
                    value={profileText} onChange={e=>setProfileText(e.target.value)}
                  />
                </>
              )}
              <button onClick={()=>setStep(2)} disabled={!profileText.trim() && !profileFile}
                style={{ width:"100%", fontSize:14.5, fontWeight:700, padding:"14px", borderRadius:14, border:"none", background:(profileText.trim()||profileFile)?"#2563EB":"var(--z-raise)", color:(profileText.trim()||profileFile)?"white":"var(--z-text3)", cursor:(profileText.trim()||profileFile)?"pointer":"default", boxShadow:"none", transition:"all 0.2s", letterSpacing:"-0.01em" }}>
                Continue →
              </button>
            </div>
          )}

          {/* ── Step 2: Job description ── */}
          {step === 2 && (
            <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
              <div style={{ border:"1px solid var(--z-bd)", borderRadius:14, padding:16 }}>
                <div style={{ display:"flex", background:"var(--z-raise)", borderRadius:8, padding:2, marginBottom:14, width:"fit-content" }}>
                  {(["paste","url"] as const).map(m => (
                    <button key={m} onClick={()=>{ setJdMode(m); setUrlFetchErr(""); }} style={{ fontSize:12, fontWeight:600, padding:"6px 16px", borderRadius:6, border:"none", background:jdMode===m?"var(--z-card)":"transparent", color:jdMode===m?"var(--z-text)":"var(--z-text2)", cursor:"pointer", transition:"all 0.15s" }}>
                      {m === "paste" ? "Paste text" : "Job URL"}
                    </button>
                  ))}
                </div>
                {jdMode === "paste" ? (
                  <textarea
                    style={{ width:"100%", minHeight:200, border:"1px solid var(--z-bd)", borderRadius:10, padding:"13px 16px", fontSize:14, color:"var(--z-text)", outline:"none", resize:"vertical", fontFamily:"inherit", boxSizing:"border-box", background:"var(--z-raise)", lineHeight:1.65, transition:"border-color 0.15s" }}
                    placeholder="Paste the full job posting…"
                    value={jobDesc} onChange={e=>setJobDesc(e.target.value)}
                  />
                ) : (
                  <div>
                    <div style={{ display:"flex", gap:8 }}>
                      <input type="url" value={jobUrl} onChange={e=>{ setJobUrl(e.target.value); setUrlFetchErr(""); }} onKeyDown={e=>{ if(e.key==="Enter") void fetchJd(); }}
                        placeholder="https://jobs.lever.co/… or LinkedIn, Greenhouse, etc."
                        style={{ flex:1, border:"1px solid var(--z-bd)", borderRadius:10, padding:"13px 16px", fontSize:14, color:"var(--z-text)", outline:"none", fontFamily:"inherit", background:"var(--z-raise)", transition:"border-color 0.15s" }}/>
                      <button onClick={()=>void fetchJd()} disabled={fetchingUrl||!jobUrl.trim()}
                        style={{ padding:"11px 20px", borderRadius:10, border:"none", background:jobUrl.trim()&&!fetchingUrl?"#10B981":"var(--z-raise)", color:jobUrl.trim()&&!fetchingUrl?"white":"var(--z-text3)", fontSize:13, fontWeight:700, cursor:jobUrl.trim()&&!fetchingUrl?"pointer":"default", flexShrink:0 }}>
                        {fetchingUrl ? "…" : "Fetch"}
                      </button>
                    </div>
                    {urlFetchErr && <p style={{ fontSize:12, color:"#FCA5A5", marginTop:8, marginBottom:0 }}>{urlFetchErr} <button onClick={()=>setJdMode("paste")} style={{ background:"none", border:"none", color:"#A5B4FC", fontWeight:600, cursor:"pointer", fontSize:12, padding:0 }}>Switch to paste</button></p>}
                    {jobDesc && !urlFetchErr && <p style={{ fontSize:12, color:"#4ADE80", marginTop:8, marginBottom:0 }}>✓ Fetched — {jobDesc.length.toLocaleString()} chars</p>}
                  </div>
                )}
              </div>
              <div style={{ display:"flex", gap:10 }}>
                <button onClick={()=>setStep(1)} style={{ padding:"14px 20px", borderRadius:14, border:"1px solid var(--z-bd)", background:"transparent", color:"var(--z-text2)", fontSize:14, fontWeight:600, cursor:"pointer" }}>← Back</button>
                <button onClick={()=>setStep(3)} disabled={!jobDesc.trim()}
                  style={{ flex:1, fontSize:14.5, fontWeight:700, padding:"14px", borderRadius:14, border:"none", background:jobDesc.trim()?"#2563EB":"var(--z-raise)", color:jobDesc.trim()?"white":"var(--z-text3)", cursor:jobDesc.trim()?"pointer":"default", boxShadow:"none", transition:"all 0.2s" }}>
                  Continue →
                </button>
              </div>
            </div>
          )}

          {/* ── Step 3: Customize ── */}
          {step === 3 && (
            <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
              <div style={{ border:"1px solid var(--z-bd)", borderRadius:14, padding:18, display:"flex", flexDirection:"column", gap:12 }}>
                <p style={{ fontSize:11, fontWeight:700, textTransform:"uppercase", letterSpacing:"0.07em", color:"var(--z-text3)", margin:0 }}>Role details (optional)</p>
                <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
                  <input value={company} onChange={e=>setCompany(e.target.value)} placeholder="Company name"
                    style={{ border:"1px solid var(--z-bd)", borderRadius:10, padding:"13px 16px", fontSize:14, color:"var(--z-text)", outline:"none", fontFamily:"inherit", background:"var(--z-raise)", transition:"border-color 0.15s" }}/>
                  <input value={targetRole} onChange={e=>setTargetRole(e.target.value)} placeholder="Target role"
                    style={{ border:"1px solid var(--z-bd)", borderRadius:10, padding:"13px 16px", fontSize:14, color:"var(--z-text)", outline:"none", fontFamily:"inherit", background:"var(--z-raise)", transition:"border-color 0.15s" }}/>
                </div>
                <input value={candidateName} onChange={e=>setCandidateName(e.target.value)} placeholder="Your name (for the signature)"
                  style={{ border:"1px solid var(--z-bd)", borderRadius:10, padding:"13px 16px", fontSize:14, color:"var(--z-text)", outline:"none", fontFamily:"inherit", background:"var(--z-raise)", width:"100%", boxSizing:"border-box", transition:"border-color 0.15s" }}/>
              </div>
              <div style={{ border:"1px solid var(--z-bd)", borderRadius:14, padding:18 }}>
                <p style={{ fontSize:11, fontWeight:700, textTransform:"uppercase", letterSpacing:"0.07em", color:"var(--z-text3)", marginBottom:12 }}>Tone</p>
                <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
                  {([
                    { id:"professional"   as const, label:"Professional",  desc:"Formal, confident, results-oriented — every sentence earns its place" },
                    { id:"conversational" as const, label:"Conversational", desc:"Warm and direct — reads like a smart person talking, not a template" },
                    { id:"enthusiastic"   as const, label:"Enthusiastic",   desc:"Energetic and genuine — shows real excitement for this specific role" },
                  ]).map(t => (
                    <button key={t.id} onClick={()=>setTone(t.id)}
                      style={{ padding:"14px 16px", borderRadius:12, border:`1.5px solid ${tone===t.id?"#10B981":"var(--z-bd)"}`, background:tone===t.id?"rgba(16,185,129,0.12)":"var(--z-raise)", cursor:"pointer", textAlign:"left", transition:"all 0.15s", display:"flex", alignItems:"center", gap:12 }}>
                      <div style={{ width:18, height:18, borderRadius:"50%", border:`2px solid ${tone===t.id?"#10B981":"var(--z-bd)"}`, background:tone===t.id?"#10B981":"transparent", flexShrink:0, display:"flex", alignItems:"center", justifyContent:"center" }}>
                        {tone===t.id && <div style={{ width:6, height:6, borderRadius:"50%", background:"rgba(255,255,255,0.9)" }}/>}
                      </div>
                      <div>
                        <div style={{ fontSize:13.5, fontWeight:700, color:"var(--z-text)", marginBottom:2 }}>{t.label}</div>
                        <div style={{ fontSize:11.5, color:"var(--z-text3)", lineHeight:1.4 }}>{t.desc}</div>
                      </div>
                    </button>
                  ))}
                </div>
              </div>
              <div style={{ display:"flex", gap:10 }}>
                <button onClick={()=>setStep(2)} style={{ padding:"14px 20px", borderRadius:14, border:"1px solid var(--z-bd)", background:"transparent", color:"var(--z-text2)", fontSize:14, fontWeight:600, cursor:"pointer" }}>← Back</button>
                <button onClick={()=>void generate()}
                  style={{ flex:1, fontSize:14.5, fontWeight:700, padding:"14px", borderRadius:14, border:"none", background:"#2563EB", color:"white", cursor:"pointer", boxShadow:"none", transition:"all 0.2s" }}>
                  Write my cover letter →
                </button>
              </div>
            </div>
          )}
        </div>

        {/* RIGHT: sticky sidebar */}
        <div style={{ position:"sticky", top:24, display:"flex", flexDirection:"column", gap:14 }}>
          <div style={{ background:"var(--z-card)", border:"1px solid var(--z-bd)", borderRadius:20, padding:"22px 22px 20px", boxShadow:"0 2px 20px rgba(0,0,0,0.07)" }}>
            <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:14 }}>
              {zIcon(clCtx.icon, "#34D399")}
              <div style={{ fontSize:12, fontWeight:800, color:"#34D399", letterSpacing:"0.04em" }}>{clCtx.label.toUpperCase()}</div>
            </div>
            <p style={{ fontSize:13, color:"var(--z-text2)", lineHeight:1.72, margin:"0 0 16px" }}>{clCtx.desc}</p>
            <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
              {clCtx.tips.map((tip, i) => (
                <div key={i} style={{ display:"flex", gap:9, alignItems:"flex-start" }}>
                  <div style={{ width:4, height:4, borderRadius:"50%", background:"rgba(52,211,153,0.6)", flexShrink:0, marginTop:6 }}/>
                  <span style={{ fontSize:12.5, color:"var(--z-text2)", lineHeight:1.6 }}>{tip}</span>
                </div>
              ))}
            </div>
          </div>
          {/* Setup progress */}
          <div style={{ background:"var(--z-card)", border:"1px solid var(--z-bd)", borderRadius:16, padding:"16px 18px" }}>
            <p style={{ fontSize:11, fontWeight:700, color:"var(--z-text3)", letterSpacing:"0.06em", textTransform:"uppercase", marginBottom:12 }}>Your answers so far</p>
            {[
              { label:"Background", done:!!(profileText.trim()||profileFile) },
              { label:"Job description", done:!!jobDesc.trim() },
              { label:"Customize", done:step===3 },
            ].map((item, i) => (
              <div key={i} style={{ display:"flex", alignItems:"center", gap:10, marginBottom:i<2?10:0 }}>
                <div style={{ width:18, height:18, borderRadius:"50%", border:`1.5px solid ${item.done?"#4ADE80":"var(--z-bd)"}`, background:item.done?"rgba(74,222,128,0.15)":"transparent", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                  {item.done && <svg viewBox="0 0 12 12" fill="none" stroke="#4ADE80" strokeWidth="2.5" style={{width:9,height:9}}><polyline points="2,6 5,9 10,3"/></svg>}
                </div>
                <span style={{ fontSize:12.5, color:item.done?"var(--z-text)":"var(--z-text3)" }}>{item.label}</span>
              </div>
            ))}
          </div>
        </div>

      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════
   SCREEN: ACTION PLAN
═══════════════════════════════════════════════════ */
type PlanTask = { text: string; cat: string; pri: string };

function ScreenPromotionRoadmap({ onNavigate, active = false }: { onNavigate: (s: string) => void; active?: boolean }) {
  const [done, setDone] = useState<Set<number>>(new Set());
  const [aiTasks, setAiTasks] = useState<PlanTask[] | null>(null);
  const [aiCoachNote, setAiCoachNote] = useState<string | null>(null);
  const [planLoading, setPlanLoading] = useState(false);
  const [docs, setDocs] = useState<DocEntry[]>([]);
  const [autoContext, setAutoContext] = useState("");
  const theme = PROMOTION_THEMES.roadmap;

  useEffect(() => {
    setDocs(vaultReadForStage("promotion"));
    const onVaultUpdate = () => setDocs(vaultReadForStage("promotion"));
    window.addEventListener("vault-updated", onVaultUpdate);
    return () => window.removeEventListener("vault-updated", onVaultUpdate);
  }, []);

  const hasResume = docs.some(d => d.type === "resume");
  const hasLI = docs.some(d => d.type === "linkedin");
  const hasCL = docs.some(d => d.type === "cover-letter");
  const readyCount = [hasResume, hasLI, hasCL].filter(Boolean).length;
  const isReady = readyCount >= 1;
  const roadmapContextKey = JSON.stringify(docs
    .filter(d => d.type === "resume" || d.type === "linkedin" || d.type === "cover-letter")
    .map(d => ({
      id: d.id,
      type: d.type,
      createdAt: d.createdAt,
      targetRole: d.meta.targetRole ?? "",
      targetLevel: d.meta.targetLevel ?? "",
      readinessScore: d.meta.readinessScore ?? d.meta.score ?? "",
      verdict: d.meta.verdict ?? "",
    })));

  const SECTION_CARDS = [
    { key:"resume", label:"Reality Check", desc:"Find out if you genuinely have a case right now.", color:"var(--z-text2)", done:hasResume },
    { key:"cover-letter", label:"Build the Case", desc:"Turn your wins into the docs that move this forward.", color:"#10B981", done:hasCL },
    { key:"linkedin", label:"Get Allies", desc:"Map who matters and make the right asks.", color:"#3B82F6", done:hasLI },
  ];

  useEffect(() => {
    if (!active || !isReady || planLoading) return;
    if (roadmapContextKey && autoContext === roadmapContextKey) return;

    const cached = readPromotionCache<{ tasks: PlanTask[]; coachNote: string | null }>("promotion-roadmap");
    if (cached && cached.contextKey === roadmapContextKey && cached.payload.tasks?.length) {
      setDone(new Set());
      setAiTasks(cached.payload.tasks);
      setAiCoachNote(cached.payload.coachNote ?? null);
      setAutoContext(roadmapContextKey);
      return;
    }

    setDone(new Set());
    setAiTasks(null);
    setAiCoachNote(null);
    setPlanLoading(true);
    setAutoContext(roadmapContextKey);
    const resumeDoc = docs.find(d => d.type === "resume");
    const liDoc = docs.find(d => d.type === "linkedin");
    const clDoc = docs.find(d => d.type === "cover-letter");
    fetch("/api/zari/plan", {
      method: "POST",
      headers: { "Content-Type":"application/json" },
      body: JSON.stringify({
        stage: "promotion",
        resumeSnippet: resumeDoc ? resumeDoc.content.slice(0, 600) : "",
        liHeadline: liDoc ? (liDoc.meta.headline || "") : "",
        liScore: liDoc ? (liDoc.meta.score || "") : "",
        resumeScore: resumeDoc ? (resumeDoc.meta.readinessScore || resumeDoc.meta.score || "") : "",
        readinessVerdict: resumeDoc ? (resumeDoc.meta.verdict || "") : "",
        targetRole: resumeDoc?.meta.desiredTitle || resumeDoc?.meta.targetRole || clDoc?.meta.targetLevel || clDoc?.meta.targetRole || liDoc?.meta.targetLevel || "",
        completedSections: [
          hasResume ? STAGE_NAV_LABELS.promotion.resume : "",
          hasLI ? STAGE_NAV_LABELS.promotion.linkedin : "",
          hasCL ? STAGE_NAV_LABELS.promotion["cover-letter"] : "",
        ].filter(Boolean),
      }),
    })
      .then(r => r.json())
      .then((data: { tasks?: PlanTask[]; coachNote?: string }) => {
        if (data.tasks?.length) {
          setAiTasks(data.tasks);
          setAiCoachNote(data.coachNote ?? null);
          writePromotionCache("promotion-roadmap", {
            contextKey: roadmapContextKey,
            payload: {
              tasks: data.tasks,
              coachNote: data.coachNote ?? null,
            },
          });
        }
      })
      .catch(() => {})
      .finally(() => setPlanLoading(false));
  }, [active, isReady, planLoading, roadmapContextKey, autoContext, aiTasks, docs, hasResume, hasLI, hasCL]);

  if (!isReady) {
    return (
      <div style={promotionPageStyle(theme)}>
        <div style={{ padding:"24px 32px 48px", position:"relative" }}>
          <div style={promotionHeroStyle(theme)}>
            <div style={{ position:"absolute", inset:0, background:"radial-gradient(circle at 84% 18%, rgba(251,207,232,0.18), transparent 28%)", animation:"aurora-pulse 8s ease-in-out infinite", pointerEvents:"none" }}/>
            <div style={promotionHeroGridStyle()}>
              <div style={{ position:"relative" }}>
                <div style={{ ...promotionEyebrowStyle(theme), marginBottom:8 }}>The Sequence</div>
                <h1 style={promotionHeroTitleStyle(760)}>Run at least one section — then Zari can sequence what comes next.</h1>
                <p style={promotionHeroBodyStyle(720)}>
                  After Reality Check, Build the Case, or Get Allies, Zari sequences what to do next based on what it learned about your situation.
                </p>
              </div>
              <PromotionHeroSpotlight
                theme={theme}
                label="How it works"
                title="Case first. Support second. Timing last."
                items={[
                  "Start with what's real before guessing what to do.",
                  "Sequence the work so the ask isn't premature.",
                  "Turn scattered activity into a deliberate cycle.",
                ]}
                footer="The sequence only gets useful once there's signal to work from."
              />
            </div>
          </div>

          <div style={{ display:"grid", gap:12, marginBottom:18 }}>
            {SECTION_CARDS.map((card, i) => (
              <button key={card.key} onClick={() => card.done ? undefined : onNavigate(card.key)} style={{ ...promotionPanelStyle(theme, true), padding:"17px 18px", display:"flex", alignItems:"center", gap:14, textAlign:"left", cursor:card.done ? "default" : "pointer" }}>
                <div style={{ width:42, height:42, borderRadius:14, background:card.done ? "rgba(16,185,129,0.14)" : `${card.color}18`, color:card.done ? "#059669" : card.color, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                  {card.done
                    ? <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="2.2" style={{width:18,height:18}}><path d="M4 10l4 4 8-8"/></svg>
                    : <span style={{ fontSize:13, fontWeight:900 }}>{i + 1}</span>}
                </div>
                <div style={{ flex:1 }}>
                  <div style={{ fontSize:14, fontWeight:800, color:"var(--z-text)", marginBottom:4 }}>{card.label}</div>
                  <div style={{ fontSize:12.5, color:"var(--z-text2)", lineHeight:1.6 }}>{card.desc}</div>
                </div>
                {card.done && <span style={{ fontSize:10.5, fontWeight:800, color:"#059669", letterSpacing:"0.08em", textTransform:"uppercase" }}>Ready</span>}
              </button>
            ))}
          </div>

          <div style={promotionPanelStyle(theme)}>
            <div style={{ fontSize:13.5, color:"var(--z-text2)", lineHeight:1.75 }}>
              The more sections you complete, the sharper and more specific the sequence gets.
            </div>
          </div>
        </div>
      </div>
    );
  }

  const TASKS = aiTasks ?? STAGE_TASKS.promotion;
  const pct = TASKS.length ? Math.round((done.size / TASKS.length) * 100) : 0;

  const CAT_COLORS: Record<string, { color: string; accent: string }> = {
    Case:        { color:"#0891B2", accent:"rgba(8,145,178,0.12)" },
    Docs:        { color:"#10B981", accent:"rgba(16,185,129,0.12)" },
    Feedback:    { color:"#DC2626", accent:"rgba(220,38,38,0.12)" },
    Sponsorship: { color:"#3B82F6", accent:"rgba(59,130,246,0.12)" },
    Visibility:  { color:"#7C3AED", accent:"rgba(124,58,237,0.12)" },
    Session:     { color:"#64748B", accent:"rgba(100,116,139,0.1)" },
    Milestone:   { color:"#D97706", accent:"rgba(217,119,6,0.12)" },
  };

  const TIMELINE_GROUPS = [
    {
      id:"high",
      label:"Do this week",
      sublabel:"Highest leverage first",
      accent:"#F43F5E",
      headerBg:"linear-gradient(135deg, #4C0519 0%, #881337 100%)",
      ringColor:"#F43F5E",
      barColor:"#F43F5E",
      icon:<svg viewBox="0 0 20 20" fill="none" style={{width:16,height:16}}><path d="M10 2l1.5 4.5H16l-3.7 2.7 1.4 4.3L10 11l-3.7 2.5 1.4-4.3L4 6.5h4.5L10 2z" stroke="#F43F5E" strokeWidth="1.5" fill="rgba(244,63,94,0.2)" strokeLinejoin="round"/></svg>,
    },
    {
      id:"med",
      label:"Do this month",
      sublabel:"Build support and fill gaps",
      accent:"#F59E0B",
      headerBg:"linear-gradient(135deg, #451A03 0%, #78350F 100%)",
      ringColor:"#F59E0B",
      barColor:"#F59E0B",
      icon:<svg viewBox="0 0 20 20" fill="none" style={{width:16,height:16}}><rect x="3" y="4" width="14" height="13" rx="2" stroke="#F59E0B" strokeWidth="1.5" fill="rgba(245,158,11,0.15)"/><path d="M3 8h14M8 2v4M12 2v4" stroke="#F59E0B" strokeWidth="1.5" strokeLinecap="round"/></svg>,
    },
    {
      id:"low",
      label:"When it's time",
      sublabel:"Timing and asks once proof aligns",
      accent:"#818CF8",
      headerBg:"linear-gradient(135deg, #1E1B4B 0%, #312E81 100%)",
      ringColor:"#818CF8",
      barColor:"#818CF8",
      icon:<svg viewBox="0 0 20 20" fill="none" style={{width:16,height:16}}><path d="M2 15c3-5 6-7 8-7s5 2 8 7" stroke="#818CF8" strokeWidth="1.5" strokeLinecap="round" fill="rgba(129,140,248,0.12)"/><path d="M10 8V5M4 12L2 11M16 12l2-1" stroke="#818CF8" strokeWidth="1.5" strokeLinecap="round"/></svg>,
    },
  ] as const;

  return (
    <div style={promotionPageStyle(theme)}>
      <div style={{ padding:"24px 32px 48px", position:"relative" }}>

        {/* ── Hero: dark immersive banner ── */}
        <div style={{ borderRadius:24, background:"linear-gradient(135deg, #0F1525 0%, #1A1040 60%, #0F1525 100%)", border:"1px solid rgba(255,255,255,0.08)", padding:"32px 36px", marginBottom:20, position:"relative", overflow:"hidden" }}>
          {/* Ambient glows */}
          <div style={{ position:"absolute", top:-40, right:-40, width:220, height:220, borderRadius:"50%", background:"radial-gradient(circle, rgba(251,113,133,0.18) 0%, transparent 70%)", pointerEvents:"none" }}/>
          <div style={{ position:"absolute", bottom:-60, left:60, width:200, height:200, borderRadius:"50%", background:"radial-gradient(circle, rgba(139,92,246,0.12) 0%, transparent 70%)", pointerEvents:"none" }}/>

          <div style={{ display:"flex", alignItems:"center", gap:32, flexWrap:"wrap", position:"relative" }}>
            {/* Ring */}
            <div style={{ position:"relative", width:120, height:120, flexShrink:0 }}>
              <svg viewBox="0 0 120 120" style={{ position:"absolute", inset:0, width:"100%", height:"100%", transform:"rotate(-90deg)" }}>
                <circle cx="60" cy="60" r="50" fill="none" stroke="rgba(255,255,255,0.07)" strokeWidth="10"/>
                <circle cx="60" cy="60" r="50" fill="none" stroke="#FB7185" strokeWidth="10" strokeLinecap="round"
                  strokeDasharray={`${(pct/100)*314} 314`}
                  style={{ filter:"drop-shadow(0 0 8px rgba(251,113,133,0.5))", transition:"stroke-dasharray 0.6s ease" }}/>
              </svg>
              <div style={{ position:"absolute", inset:0, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center" }}>
                <div style={{ fontSize:30, fontWeight:900, color:"white", letterSpacing:"-0.05em", lineHeight:1 }}>{pct}%</div>
                <div style={{ fontSize:9.5, color:"rgba(255,255,255,0.45)", fontWeight:700, textTransform:"uppercase", letterSpacing:"0.1em", marginTop:4 }}>done</div>
              </div>
            </div>

            {/* Title + stats */}
            <div style={{ flex:1, minWidth:200 }}>
              <div style={{ fontSize:10.5, fontWeight:800, color:"rgba(251,113,133,0.8)", textTransform:"uppercase", letterSpacing:"0.12em", marginBottom:8 }}>The Sequence</div>
              <h1 style={{ fontSize:26, fontWeight:900, color:"white", letterSpacing:"-0.03em", lineHeight:1.15, margin:"0 0 16px", fontFamily:PROMOTION_DISPLAY_FONT }}>
                The sequence, based on where you actually are.
              </h1>
              <div style={{ display:"flex", gap:10, flexWrap:"wrap" }}>
                {[
                  { label:"Completed", value:done.size, color:"#4ADE80" },
                  { label:"Remaining", value:TASKS.length - done.size, color:"#FB7185" },
                  { label:"Sections", value:`${readyCount}/3`, color:"#818CF8" },
                ].map(s => (
                  <div key={s.label} style={{ borderRadius:12, background:"rgba(255,255,255,0.06)", border:"1px solid rgba(255,255,255,0.1)", padding:"10px 16px", textAlign:"center", minWidth:80 }}>
                    <div style={{ fontSize:22, fontWeight:900, color:s.color, letterSpacing:"-0.04em", lineHeight:1 }}>{s.value}</div>
                    <div style={{ fontSize:10, fontWeight:700, color:"rgba(255,255,255,0.4)", textTransform:"uppercase", letterSpacing:"0.08em", marginTop:4 }}>{s.label}</div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>

        {planLoading && (
          <div style={{ borderRadius:14, background:"var(--z-card)", border:"1px solid var(--z-bd)", marginBottom:18, display:"flex", alignItems:"center", gap:12, padding:"16px 18px" }}>
            <span style={{ width:16, height:16, borderRadius:"50%", border:"2.5px solid var(--z-bd)", borderTopColor:"#FB7185", animation:"spin-slow 0.7s linear infinite", display:"block", flexShrink:0 }}/>
            <span style={{ fontSize:13.5, color:"var(--z-text2)", fontWeight:700 }}>Zari is putting the sequence together…</span>
          </div>
        )}

        {/* Zari's take — premium gradient card */}
        <div style={{ borderRadius:18, background:"linear-gradient(135deg, rgba(124,58,237,0.08) 0%, rgba(37,99,235,0.05) 100%)", border:"1px solid rgba(124,58,237,0.2)", borderLeft:"4px solid #1459CC", padding:"22px 26px", marginBottom:18 }}>
          <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:12 }}>
            <div style={{ width:28, height:28, borderRadius:8, background:"linear-gradient(135deg, #7C3AED, #3B82F6)", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
              <span style={{ fontSize:12, fontWeight:900, color:"white" }}>Z</span>
            </div>
            <div style={{ fontSize:10.5, fontWeight:800, color:"#1459CC", textTransform:"uppercase", letterSpacing:"0.12em" }}>Zari&apos;s take</div>
          </div>
          <p style={{ fontSize:15.5, color:"var(--z-text)", lineHeight:1.82, margin:0, fontWeight:500 }}>
            {aiCoachNote ?? "Start with the highest-leverage tasks. The goal is to tighten the case first, then build support, then time the ask so the decision feels inevitable rather than premature."}
          </p>
        </div>

        {/* Section status pills */}
        <div style={{ display:"flex", gap:8, marginBottom:24, flexWrap:"wrap" }}>
          {SECTION_CARDS.map(card => (
            <button key={card.key} onClick={() => onNavigate(card.key)}
              style={{ display:"flex", alignItems:"center", gap:6, padding:"7px 13px", borderRadius:999,
                border:`1px solid ${card.done ? "#059669" : "var(--z-bd)"}`,
                background:card.done ? "rgba(5,150,105,0.1)" : "var(--z-card)",
                color:card.done ? "#059669" : "var(--z-text2)",
                cursor:"pointer", fontSize:12.5, fontWeight:700, transition:"all 0.15s" }}>
              {card.done
                ? <svg viewBox="0 0 12 12" fill="none" stroke="currentColor" strokeWidth="2.4" style={{width:10,height:10}}><path d="M1.5 6l3 3 6-6"/></svg>
                : <svg viewBox="0 0 12 12" fill="none" stroke="currentColor" strokeWidth="2" style={{width:10,height:10}}><circle cx="6" cy="6" r="4.5"/></svg>}
              {card.label}
            </button>
          ))}
        </div>

        {/* Timeline groups */}
        <div style={{ display:"grid", gap:20 }}>
          {TIMELINE_GROUPS.map(group => {
            const groupTasks = TASKS.map((t, i) => ({ ...t, idx: i })).filter(t => t.pri === group.id);
            if (!groupTasks.length) return null;
            const groupDone = groupTasks.filter(t => done.has(t.idx)).length;
            const groupPct = groupTasks.length ? Math.round((groupDone / groupTasks.length) * 100) : 0;
            return (
              <div key={group.id} style={{ borderRadius:20, background:"var(--z-card)", border:"1px solid var(--z-bd)", overflow:"hidden", boxShadow:"0 4px 20px rgba(0,0,0,0.07)" }}>
                {/* Group header */}
                <div style={{ background:group.headerBg, padding:"18px 22px", display:"flex", alignItems:"center", justifyContent:"space-between", gap:12, flexWrap:"wrap" }}>
                  <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                    <div style={{ width:32, height:32, borderRadius:9, background:"rgba(255,255,255,0.1)", border:"1px solid rgba(255,255,255,0.15)", display:"flex", alignItems:"center", justifyContent:"center" }}>
                      {group.icon}
                    </div>
                    <div>
                      <div style={{ fontSize:10.5, fontWeight:800, color:"rgba(255,255,255,0.55)", textTransform:"uppercase", letterSpacing:"0.12em", marginBottom:2 }}>{group.label}</div>
                      <div style={{ fontSize:17, fontWeight:800, color:"white", letterSpacing:"-0.02em", lineHeight:1.1 }}>{group.sublabel}</div>
                    </div>
                  </div>
                  <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                    <div style={{ fontSize:13, fontWeight:800, color:"rgba(255,255,255,0.6)" }}>{groupDone}/{groupTasks.length}</div>
                    <div style={{ width:90, height:6, borderRadius:999, background:"rgba(255,255,255,0.15)", overflow:"hidden" }}>
                      <div style={{ width:`${groupPct}%`, height:"100%", borderRadius:999, background:group.barColor, transition:"width 0.4s ease", filter:`drop-shadow(0 0 4px ${group.barColor}88)` }}/>
                    </div>
                    <div style={{ fontSize:13, fontWeight:900, color:"white" }}>{groupPct}%</div>
                  </div>
                </div>

                {/* Tasks */}
                <div style={{ padding:"14px 16px", display:"grid", gap:8 }}>
                  {groupTasks.map(task => {
                    const isDone = done.has(task.idx);
                    const cc = CAT_COLORS[task.cat] ?? { color:"#64748B", accent:"rgba(100,116,139,0.1)" };
                    return (
                      <button
                        key={task.idx}
                        onClick={() => setDone(d => { const next = new Set(d); next.has(task.idx) ? next.delete(task.idx) : next.add(task.idx); return next; })}
                        style={{ display:"flex", alignItems:"flex-start", gap:12, border:`1px solid ${isDone ? group.accent+"44" : "var(--z-bd)"}`, borderLeft:`3px solid ${isDone ? group.accent : "var(--z-bd)"}`, borderRadius:12, padding:"13px 15px", background:isDone ? `${group.accent}08` : "var(--z-raise)", textAlign:"left", cursor:"pointer", transition:"all 0.18s", opacity:isDone ? 0.65 : 1 }}
                      >
                        <div style={{ width:22, height:22, borderRadius:7, border:`2px solid ${isDone ? group.accent : "var(--z-bd)"}`, background:isDone ? group.accent : "transparent", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, marginTop:1, transition:"all 0.18s" }}>
                          {isDone && <svg viewBox="0 0 12 12" fill="none" style={{width:9,height:9}}><path d="M1.5 6l3 3 6-6" stroke="white" strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                        </div>
                        <div style={{ flex:1 }}>
                          <p style={{ fontSize:13.5, color:isDone ? "var(--z-text3)" : "var(--z-text)", textDecoration:isDone ? "line-through" : "none", lineHeight:1.65, margin:0, transition:"all 0.18s" }}>{task.text}</p>
                        </div>
                        <span style={{ flexShrink:0, fontSize:10, fontWeight:800, padding:"3px 8px", borderRadius:999, background:isDone ? "transparent" : cc.accent, color:isDone ? "var(--z-text3)" : cc.color, border:`1px solid ${isDone ? "var(--z-bd)" : cc.color+"33"}`, whiteSpace:"nowrap", marginTop:2 }}>{isDone ? "Done" : task.cat}</span>
                      </button>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

function ScreenPlan({ stage, onNavigate, active = false }: { stage: CareerStage; onNavigate: (s: string) => void; active?: boolean }) {
  const billing = useBillingCtx();
  if (stage === "promotion")    return <FeatureGate featureName="zari_promotion_readiness"><ScreenPromotionRoadmap onNavigate={onNavigate} active={active} /></FeatureGate>;
  if (stage === "career-change") return <FeatureGate featureName="zari_pivot_analysis"><ScreenCareerChangePlan onNavigate={onNavigate} active={active} /></FeatureGate>;

  const [done,        setDone]        = useState<Set<number>>(new Set());
  const [aiTasks,     setAiTasks]     = useState<PlanTask[] | null>(null);
  const [aiCoachNote, setAiCoachNote] = useState<string | null>(null);
  const [planLoading, setPlanLoading] = useState(false);
  const [docs,        setDocs]        = useState<DocEntry[]>([]);

  useEffect(() => {
    setDocs(vaultReadForStage(stage));
    const onVaultUpdate = () => setDocs(vaultReadForStage(stage));
    window.addEventListener("vault-updated", onVaultUpdate);
    return () => window.removeEventListener("vault-updated", onVaultUpdate);
  }, [stage]);

  const hasResume  = docs.some(d => d.type === "resume");
  const hasLI      = docs.some(d => d.type === "linkedin");
  const hasCL      = docs.some(d => d.type === "cover-letter");
  const readyCount = [hasResume, hasLI, hasCL].filter(Boolean).length;
  const isReady    = readyCount >= 1;

  const SECTION_CARDS = [
    { type:"resume"       as DocType, key:"resume",       label:"Resume Review",   desc:"Analyze your resume — Zari scores it and finds gaps", color:"var(--z-text2)", bg:"#F0FDFA", done:hasResume },
    { type:"linkedin"     as DocType, key:"linkedin",     label:"LinkedIn Profile", desc:"Review your profile and get an overall LinkedIn score", color:"#0A66C2", bg:"#EFF6FF", done:hasLI },
    { type:"cover-letter" as DocType, key:"cover-letter", label:"Cover Letter",     desc:"Generate a tailored cover letter for a specific role",  color:"#059669", bg:"#ECFDF5", done:hasCL },
  ];

  useEffect(() => {
    if (!isReady) return;
    setDone(new Set());
    setAiTasks(null);
    setAiCoachNote(null);
    setPlanLoading(true);
    const resumeDoc = docs.find(d => d.type === "resume");
    const liDoc     = docs.find(d => d.type === "linkedin");
    const clDoc     = docs.find(d => d.type === "cover-letter");
    fetch("/api/zari/plan", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        stage,
        resumeSnippet:   resumeDoc ? resumeDoc.content.slice(0,600) : "",
        liHeadline:      liDoc     ? (liDoc.meta.headline||"") : "",
        liScore:         liDoc     ? (liDoc.meta.score||"")    : "",
        resumeScore:     resumeDoc ? (resumeDoc.meta.score||"")    : "",
        targetRole:      resumeDoc?.meta.targetRole || clDoc?.meta.targetRole || "",
        completedSections: [
          hasResume ? STAGE_NAV_LABELS[stage].resume : "",
          hasLI ? STAGE_NAV_LABELS[stage].linkedin : "",
          hasCL ? STAGE_NAV_LABELS[stage]["cover-letter"] : "",
        ].filter(Boolean),
      }),
    })
      .then(async r => {
        const data = await r.json().catch(() => null) as ({ tasks?: PlanTask[]; coachNote?: string } & BillingApiErrorData) | null;
        if (!r.ok) { handleBillingApiError(r.status, data as BillingApiErrorData, billing); return; }
        if (data?.tasks?.length) { setAiTasks(data.tasks); setAiCoachNote((data as {coachNote?:string}).coachNote ?? null); }
      })
      .catch(() => {})
      .finally(() => setPlanLoading(false));
  }, [stage, isReady, docs.map(d=>d.id).join(",")]); // eslint-disable-line react-hooks/exhaustive-deps

  // ── Empty state: not enough context ──
  if (!isReady) return (
    <div style={{ height:"100%", overflow:"auto", background:"var(--z-raise)" }}>
      {/* Page header */}
      <div style={{ background:"var(--z-card)", borderBottom:"1px solid var(--z-bd)", padding:"16px 28px" }}>
        <h1 style={{ fontSize:22, fontWeight:800, color:"var(--z-text)", letterSpacing:"-0.03em", margin:"0 0 4px" }}>Action Plan</h1>
        <p style={{ fontSize:13, color:"var(--z-text2)", margin:0 }}>Your personalized step-by-step roadmap based on completed sections.</p>
      </div>
      <div style={{ padding:"36px 28px" }}>
        <div style={{ textAlign:"center", marginBottom:40 }}>
          <div style={{ width:52, height:52, borderRadius:14, background:"var(--z-raise)", border:"1px solid var(--z-bd)", display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 18px" }}>
            <svg viewBox="0 0 24 24" fill="none" stroke="var(--z-text2)" strokeWidth="1.8" style={{width:24,height:24}}><path d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2"/><rect x="9" y="3" width="6" height="4" rx="1"/><path d="M9 12h6M9 16h4"/></svg>
          </div>
          <h1 style={{ fontSize:24, fontWeight:900, letterSpacing:"-0.03em", color:"var(--z-text)", marginBottom:10 }}>Your {STAGE_NAV_LABELS[stage].plan} isn&apos;t ready yet</h1>
          <p style={{ fontSize:14, color:"var(--z-text2)", lineHeight:1.65, }}>
            Zari needs to see at least one completed section to build a personalized plan.
            {" "}Complete the steps below and come back — your plan will be waiting.
          </p>
        </div>

        <div style={{ display:"flex", flexDirection:"column", gap:12 }}>
          {SECTION_CARDS.map((c, i) => (
            <button key={c.key} onClick={()=>c.done ? undefined : onNavigate(c.key)}
              style={{ background:"var(--z-card)", border:`1px solid ${c.done ? "#2563EB" : "var(--z-bd)"}`, borderRadius:12, padding:"20px 22px", cursor:c.done?"default":"pointer", textAlign:"left", display:"flex", alignItems:"center", gap:16, transition:"all 0.2s", position:"relative", overflow:"hidden" }}>
              {!c.done && <div style={{ position:"absolute", left:0, top:0, bottom:0, width:3, background:"#2563EB", borderRadius:"12px 0 0 12px" }}/>}
              <div style={{ width:44, height:44, borderRadius:12, background:c.done ? "#EFF6FF" : "var(--z-raise)", border:"1px solid var(--z-bd)", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                {c.done
                  ? <svg viewBox="0 0 20 20" fill="none" stroke="#2563EB" strokeWidth="2.4" style={{width:18,height:18}}><path d="M4 10l5 5 7-7"/></svg>
                  : <span style={{ fontSize:15, fontWeight:900, color:"var(--z-text3)" }}>{i+1}</span>
                }
              </div>
              <div style={{ flex:1 }}>
                <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:4 }}>
                  <span style={{ fontSize:15, fontWeight:800, color:"var(--z-text)", letterSpacing:"-0.02em" }}>{c.label}</span>
                  {c.done && <span style={{ fontSize:10.5, fontWeight:700, padding:"2px 9px", borderRadius:99, background:"#EFF6FF", color:"#2563EB", border:"1px solid #BFDBFE" }}>✓ Complete</span>}
                </div>
                <div style={{ fontSize:12.5, color:"var(--z-text2)", lineHeight:1.5 }}>{c.desc}</div>
              </div>
              {!c.done && (
                <div style={{ flexShrink:0, width:32, height:32, borderRadius:8, background:"var(--z-raise)", display:"flex", alignItems:"center", justifyContent:"center", color:"#2563EB", border:"1px solid var(--z-bd)" }}>
                  <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2.2" style={{width:14,height:14}}><path d="M4 8h8M9 4l4 4-4 4"/></svg>
                </div>
              )}
            </button>
          ))}
        </div>

        <div style={{ marginTop:28, background:"var(--z-card)", border:"1px solid var(--z-bd)", borderRadius:14, padding:"16px 20px", display:"flex", gap:12, alignItems:"flex-start" }}>
          <div style={{ width:34, height:34, borderRadius:9, background:"#2563EB", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, fontSize:13, fontWeight:800, color:"white" }}>Z</div>
          <p style={{ fontSize:13, color:"var(--z-text2)", lineHeight:1.65 }}>
            The more sections you complete, the more specific your action plan gets. After your resume review Zari already knows what to fix — after LinkedIn it can sequence the work. Give it both and the plan is surgical.
          </p>
        </div>
      </div>
    </div>
  );

  const TASKS = aiTasks ?? STAGE_TASKS[stage];
  const pct   = TASKS.length ? Math.round((done.size / TASKS.length) * 100) : 0;

  const CAT_COLORS: Record<string, { color: string; bg: string; border: string }> = {
    Resume:          { color:"#64748B",  bg:"rgba(100,116,139,0.12)", border:"rgba(100,116,139,0.3)" },
    LinkedIn:        { color:"#0A66C2",  bg:"rgba(10,102,194,0.12)",  border:"rgba(10,102,194,0.3)"  },
    Interview:       { color:"#D97706",  bg:"rgba(217,119,6,0.12)",   border:"rgba(217,119,6,0.3)"   },
    "Job Search":    { color:"#2563EB",  bg:"rgba(37,99,235,0.12)",   border:"rgba(37,99,235,0.3)"   },
    "Cover Letter":  { color:"#059669",  bg:"rgba(5,150,105,0.12)",   border:"rgba(5,150,105,0.3)"   },
    Session:         { color:"#3B82F6",  bg:"rgba(59,130,246,0.12)",  border:"rgba(59,130,246,0.3)"  },
    Network:         { color:"#0891B2",  bg:"rgba(8,145,178,0.12)",   border:"rgba(8,145,178,0.3)"   },
    Research:        { color:"#BE185D",  bg:"rgba(190,24,93,0.12)",   border:"rgba(190,24,93,0.3)"   },
    Case:            { color:"#64748B",  bg:"rgba(100,116,139,0.12)", border:"rgba(100,116,139,0.3)" },
    Docs:            { color:"#059669",  bg:"rgba(5,150,105,0.12)",   border:"rgba(5,150,105,0.3)"   },
    Feedback:        { color:"#DC2626",  bg:"rgba(220,38,38,0.12)",   border:"rgba(220,38,38,0.3)"   },
    Sponsorship:     { color:"#0284C7",  bg:"rgba(2,132,199,0.12)",   border:"rgba(2,132,199,0.3)"   },
    Visibility:      { color:"#0A66C2",  bg:"rgba(10,102,194,0.12)",  border:"rgba(10,102,194,0.3)"  },
    Planning:        { color:"#3B82F6",  bg:"rgba(59,130,246,0.12)",  border:"rgba(59,130,246,0.3)"  },
    Milestone:       { color:"#D97706",  bg:"rgba(217,119,6,0.12)",   border:"rgba(217,119,6,0.3)"   },
  };

  const TIMELINE_GROUPS = [
    {
      id: "high",
      label: "This Week",
      sublabel: "High-impact moves — start here",
      accent: "#DC2626",
      accentBg: "linear-gradient(135deg, #FEF2F2, #FFF1F2)",
      accentBorder: "#FECACA",
      icon: (
        <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="2" style={{width:16,height:16}}>
          <circle cx="10" cy="10" r="8"/><path d="M10 6v4l3 3"/>
        </svg>
      ),
    },
    {
      id: "med",
      label: "This Month",
      sublabel: "Build momentum over the next few weeks",
      accent: "#D97706",
      accentBg: "linear-gradient(135deg, #FFFBEB, #FFF7ED)",
      accentBorder: "#FDE68A",
      icon: (
        <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="2" style={{width:16,height:16}}>
          <rect x="3" y="4" width="14" height="13" rx="2"/><path d="M3 8h14M8 4V2M12 4V2"/>
        </svg>
      ),
    },
    {
      id: "low",
      label: "On the Horizon",
      sublabel: "Worth doing when you have bandwidth",
      accent: "#2563EB",
      accentBg: "linear-gradient(135deg, #EFF6FF, #CCFBF1)",
      accentBorder: "#BFDBFE",
      icon: (
        <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="2" style={{width:16,height:16}}>
          <path d="M2 14c3-4 6-6 8-6s5 2 8 6"/><path d="M10 8V5M4 11l-2-1M16 11l2-1"/>
        </svg>
      ),
    },
  ];

  return (
    <div style={{ height:"100%", overflow:"auto", background:"var(--z-raise)" }}>
      {/* Page header */}
      <div style={{ background:"var(--z-card)", borderBottom:"1px solid var(--z-bd)", padding:"16px 28px" }}>
        <div>
          <h1 style={{ fontSize:22, fontWeight:800, color:"var(--z-text)", letterSpacing:"-0.03em", margin:"0 0 4px" }}>Action Plan</h1>
          <p style={{ fontSize:13, color:"var(--z-text2)", margin:0 }}>Your personalized step-by-step roadmap based on completed sections.</p>
        </div>
      </div>
      <div style={{ padding:"20px 28px 40px" }}>

        {/* ── Header ── */}
        <div style={{ marginBottom:28 }}>
          <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", gap:16, flexWrap:"wrap" }}>
            <div>
              <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:6 }}>
                <h1 style={{ fontSize:26, fontWeight:900, letterSpacing:"-0.04em", color:"var(--z-text)", margin:0 }}>Your {STAGE_NAV_LABELS[stage].plan}</h1>
                {aiTasks && (
                  <span style={{ fontSize:10.5, fontWeight:800, padding:"3px 9px", borderRadius:99, background:"var(--z-raise)", color:"var(--z-text3)", border:"1px solid var(--z-bd)", letterSpacing:"0.02em" }}>
                    AI · PERSONALIZED
                  </span>
                )}
              </div>
              <p style={{ fontSize:13.5, color:"var(--z-text2)", lineHeight:1.5 }}>
                Based on your {[
                  hasResume && "resume",
                  hasLI && "LinkedIn",
                  hasCL && "cover letter",
                ].filter(Boolean).join(", ")} · {readyCount}/3 sections complete
              </p>
            </div>

            {/* Stats pill */}
            <div style={{ display:"flex", gap:0, background:"var(--z-raise)", border:"1px solid var(--z-bd)", borderRadius:14, overflow:"hidden", boxShadow:"0 2px 12px rgba(0,0,0,0.07)" }}>
              {[
                { label:"Done", value:done.size, color:"#059669" },
                { label:"Remaining", value:TASKS.length - done.size, color:"#2563EB" },
                { label:"Total", value:TASKS.length, color:"var(--z-text2)" },
              ].map((s, i) => (
                <div key={s.label} style={{ padding:"12px 20px", textAlign:"center", borderLeft: i ? "1px solid var(--z-bd)" : "none" }}>
                  <div style={{ fontSize:22, fontWeight:900, color:s.color, lineHeight:1 }}>{s.value}</div>
                  <div style={{ fontSize:10.5, color:"var(--z-text3)", marginTop:3, fontWeight:600, textTransform:"uppercase", letterSpacing:"0.04em" }}>{s.label}</div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {planLoading && (
          <div style={{ display:"flex", alignItems:"center", gap:12, background:"var(--z-card)", border:"1px solid var(--z-bd)", borderRadius:14, padding:"14px 18px", marginBottom:22, boxShadow:"0 2px 12px rgba(37,99,235,0.06)" }}>
            <span style={{ width:16,height:16,borderRadius:"50%",border:"2.5px solid rgba(37,99,235,0.25)",borderTopColor:"#2563EB",animation:"spin-slow 0.7s linear infinite",display:"block",flexShrink:0 }}/>
            <span style={{ fontSize:13.5, color:"#2563EB", fontWeight:600 }}>Zari is analyzing your sections and building a personalized plan…</span>
          </div>
        )}

        {/* ── Progress bar ── */}
        <div style={{ background:"var(--z-card)", border:"1px solid var(--z-bd)", borderRadius:16, padding:"18px 22px", marginBottom:24, boxShadow:"0 2px 12px rgba(0,0,0,0.07)" }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10 }}>
            <span style={{ fontSize:13, fontWeight:700, color:"var(--z-text)" }}>Overall Progress</span>
            <span style={{ fontSize:18, fontWeight:900, color:"#2563EB" }}>{pct}%</span>
          </div>
          <div style={{ height:8, background:"var(--z-raise)", borderRadius:99, overflow:"hidden" }}>
            <div style={{ height:"100%", width:`${pct}%`, background:"#2563EB", borderRadius:99, transition:"width 0.5s ease" }}/>
          </div>
          <div style={{ display:"flex", gap:16, marginTop:12 }}>
            {TIMELINE_GROUPS.map(g => {
              const total = TASKS.filter(t=>t.pri===g.id).length;
              const doneC = TASKS.filter((t,i)=>t.pri===g.id&&done.has(i)).length;
              return (
                <div key={g.id} style={{ display:"flex", alignItems:"center", gap:6 }}>
                  <div style={{ width:8, height:8, borderRadius:99, background:g.accent }}/>
                  <span style={{ fontSize:12, color:"var(--z-text2)" }}>
                    <strong style={{ color:g.accent, fontWeight:700 }}>{doneC}/{total}</strong> {g.label}
                  </span>
                </div>
              );
            })}
          </div>
        </div>

        {/* ── Context chips ── */}
        <div style={{ display:"flex", gap:8, marginBottom:28, flexWrap:"wrap", alignItems:"center" }}>
          <span style={{ fontSize:12, color:"var(--z-text3)", fontWeight:600 }}>Sections:</span>
          {SECTION_CARDS.map(c => (
            <button key={c.key} onClick={()=>onNavigate(c.key)}
              style={{ display:"flex", alignItems:"center", gap:5, padding:"5px 12px", borderRadius:99, border:"1px solid var(--z-bd)", background:"var(--z-card)", cursor:"pointer", fontSize:12, fontWeight:600, color:"var(--z-text2)", transition:"all 0.15s" }}>
              {c.done
                ? <svg viewBox="0 0 12 12" fill="none" stroke="currentColor" strokeWidth="2.2" style={{width:10,height:10}}><path d="M1.5 6l3 3 6-6"/></svg>
                : <svg viewBox="0 0 12 12" fill="none" stroke="currentColor" strokeWidth="2" style={{width:10,height:10}}><circle cx="6" cy="6" r="4.5"/></svg>
              }
              {c.label}
            </button>
          ))}
          {!SECTION_CARDS.every(c=>c.done) && (
            <span style={{ fontSize:12, color:"var(--z-text3)", fontStyle:"italic" }}>Complete more for a sharper plan</span>
          )}
        </div>

        {/* ── Zari's coaching note (prominent) ── */}
        <div style={{ marginBottom:28, background:"var(--z-card)", borderRadius:14, padding:"20px 24px", border:"1px solid var(--z-bd)" }}>
          <div style={{ display:"flex", gap:14, alignItems:"flex-start" }}>
            <div style={{ width:36, height:36, borderRadius:10, background:"#2563EB", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, fontSize:14, fontWeight:900, color:"white" }}>Z</div>
            <div>
              <p style={{ fontSize:11, fontWeight:700, color:"var(--z-text3)", marginBottom:6, textTransform:"uppercase", letterSpacing:"0.08em" }}>Zari&apos;s Coaching Note</p>
              <p style={{ fontSize:14, color:"var(--z-text)", lineHeight:1.7, margin:0 }}>
                {aiCoachNote ?? "Start with the high-priority tasks — they have the highest leverage right now. Each one you check off makes your search sharper. Come back as you complete sections and your plan will automatically get more specific."}
              </p>
            </div>
          </div>
        </div>

        {/* ── Tasks by timeline group ── */}
        <div style={{ display:"flex", flexDirection:"column", gap:24 }}>
          {TIMELINE_GROUPS.map(group => {
            const groupTasks = TASKS.map((t,i)=>({...t,idx:i})).filter(t=>t.pri===group.id);
            if (!groupTasks.length) return null;
            const groupDone  = groupTasks.filter(t=>done.has(t.idx)).length;
            const groupTotal = groupTasks.length;
            const groupPct   = groupTotal ? Math.round((groupDone/groupTotal)*100) : 0;

            return (
              <div key={group.id}>
                {/* Group header */}
                <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:12 }}>
                  <div style={{ width:30, height:30, borderRadius:8, background:"var(--z-raise)", border:"1px solid var(--z-bd)", display:"flex", alignItems:"center", justifyContent:"center", color:"var(--z-text2)" }}>
                    {group.icon}
                  </div>
                  <div style={{ flex:1 }}>
                    <div style={{ display:"flex", alignItems:"baseline", gap:8 }}>
                      <span style={{ fontSize:15, fontWeight:800, color:"var(--z-text)", letterSpacing:"-0.02em" }}>{group.label}</span>
                      <span style={{ fontSize:12, color:group.accent, fontWeight:700 }}>{groupDone}/{groupTotal}</span>
                    </div>
                    <div style={{ fontSize:12, color:"var(--z-text3)", marginTop:1 }}>{group.sublabel}</div>
                  </div>
                  <div style={{ width:60, height:5, background:"var(--z-bd)", borderRadius:99, overflow:"hidden" }}>
                    <div style={{ height:"100%", width:`${groupPct}%`, background:group.accent, borderRadius:99, transition:"width 0.4s ease" }}/>
                  </div>
                </div>

                {/* Task cards */}
                <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
                  {groupTasks.map(task => {
                    const isDone = done.has(task.idx);
                    const cc = CAT_COLORS[task.cat] ?? { color:"var(--z-text2)", bg:"#F5F7FF", border:"#E4E8F5" };
                    return (
                      <button key={task.idx}
                        onClick={()=>setDone(d=>{const n=new Set(d);n.has(task.idx)?n.delete(task.idx):n.add(task.idx);return n;})}
                        style={{ display:"flex", alignItems:"flex-start", gap:12, background:"var(--z-raise)", border:`1px solid ${isDone?"rgba(74,222,128,0.25)":"var(--z-bd)"}`, borderLeft:`3.5px solid ${isDone?"#16A34A":group.accent}`, borderRadius:"0 14px 14px 0", padding:"13px 16px", cursor:"pointer", textAlign:"left", transition:"all 0.15s", boxShadow:`0 1px 6px rgba(0,0,0,0.04)` }}>
                        <div style={{ width:22, height:22, borderRadius:6, border:`2px solid ${isDone?"#16A34A":"var(--z-bd)"}`, background:isDone?"rgba(22,163,74,0.15)":"var(--z-card)", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, marginTop:1 }}>
                          {isDone && <svg viewBox="0 0 12 12" fill="none" style={{width:10,height:10}}><path d="M1.5 6l3 3 6-6" stroke="#16A34A" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                        </div>
                        <div style={{ flex:1 }}>
                          <p style={{ fontSize:13.5, color:isDone?"var(--z-text3)":"var(--z-text)", textDecoration:isDone?"line-through":"none", lineHeight:1.5, margin:0 }}>{task.text}</p>
                        </div>
                        <span style={{ flexShrink:0, fontSize:11, fontWeight:700, padding:"3px 9px", borderRadius:99, background:cc.bg, color:cc.color, border:`1px solid ${cc.border}`, whiteSpace:"nowrap", alignSelf:"center" }}>{task.cat}</span>
                      </button>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}


/* ═══════════════════════════════════════════════════
   SCREEN: ACCOUNT
═══════════════════════════════════════════════════ */
function ScreenAccount({ viewer, onNavigate, onBuyCredits, onComparePlans }: { viewer: PortalViewer; onNavigate: (s: Screen) => void; onBuyCredits: () => void; onComparePlans: () => void }) {
  const isOperator = viewer.role === "admin" || viewer.role === "support";
  const used = viewer.usedMonthlyCredits ?? 0;
  const limit = viewer.creditLimit ?? viewer.includedMonthlyCredits ?? 0;
  const remaining = viewer.remainingMonthlyCredits ?? Math.max(0, limit - used);
  const pct = limit > 0 ? Math.min(100, Math.round((used / limit) * 100)) : 0;
  const initials = (viewer.name?.trim() || viewer.email)
    .split(/\s+/)
    .slice(0, 2)
    .map(p => p[0]?.toUpperCase() ?? "")
    .join("") || "?";

  const planColor = viewer.planId === "executive" ? "#F59E0B" : "#2563EB";
  const barColor = pct >= 90 ? "#EF4444" : pct >= 70 ? "#F59E0B" : "#22C55E";

  const fmtNum = (v?: number | null) =>
    new Intl.NumberFormat("en-US", { minimumFractionDigits: 0, maximumFractionDigits: 0 }).format(Number(v ?? 0));

  const priceLine = viewer.monthlyPriceCents
    ? `$${(viewer.monthlyPriceCents / 100).toFixed(2)} / month`
    : null;

  const statusLabel = viewer.subscriptionStatus
    ? viewer.subscriptionStatus.replace(/_/g, " ").replace(/\b\w/g, c => c.toUpperCase())
    : viewer.isPaid ? "Active" : "Free";

  const statusColor = (viewer.subscriptionStatus === "active" || !viewer.subscriptionStatus)
    ? "#22C55E" : viewer.subscriptionStatus === "canceled" ? "#EF4444" : "#F59E0B";

  const [showDangerZone, setShowDangerZone] = useState(false);
  const [cancelConfirm, setCancelConfirm] = useState(false);

  // Support ticket modal
  const [showSupportModal, setShowSupportModal] = useState(false);
  const [supportForm, setSupportForm] = useState({ subject: "", description: "", category: "other" });
  const [supportSubmitting, setSupportSubmitting] = useState(false);
  const [supportError, setSupportError] = useState("");
  const [supportSuccess, setSupportSuccess] = useState(false);

  async function submitSupportTicket() {
    if (!supportForm.subject.trim() || !supportForm.description.trim()) {
      setSupportError("Subject and description are required.");
      return;
    }
    setSupportSubmitting(true);
    setSupportError("");
    try {
      const res = await fetch("/api/support/ticket", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(supportForm),
      });
      const data = await res.json().catch(() => ({})) as { ok?: boolean; error?: string };
      if (!res.ok || !data.ok) {
        setSupportError(data.error ?? "Failed to submit — please try again.");
      } else {
        setSupportSuccess(true);
        setSupportForm({ subject: "", description: "", category: "other" });
      }
    } catch {
      setSupportError("Connection error — please try again.");
    }
    setSupportSubmitting(false);
  }

  function closeSupportModal() {
    setShowSupportModal(false);
    setSupportError("");
    setSupportSuccess(false);
    setSupportForm({ subject: "", description: "", category: "other" });
  }

  const sectionStyle: React.CSSProperties = {
    background: "var(--z-card)",
    borderRadius: 14,
    border: "1px solid var(--z-bd)",
    padding: "20px 22px",
    marginBottom: 14,
  };
  const labelStyle: React.CSSProperties = { fontSize: 11, fontWeight: 700, letterSpacing: "0.08em", textTransform: "uppercase", color: "var(--z-text3)", marginBottom: 14 };
  const rowStyle: React.CSSProperties = { display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 10 };
  const keyStyle: React.CSSProperties = { fontSize: 13, color: "var(--z-text2)" };
  const valStyle: React.CSSProperties = { fontSize: 13, fontWeight: 600, color: "var(--z-text)" };

  const nextPlanName = viewer.planId === "search" ? "Growth" : viewer.planId === "growth" ? "Executive" : null;
  const nextPlanHref = viewer.planId === "search" ? "/onboarding/plan?upgrade=growth" : "/onboarding/plan?upgrade=executive";

  return (
    <div style={{ height: "100%", overflowY: "auto", padding: "28px 32px", maxWidth: 700, margin: "0 auto" }}>

      {/* Support ticket modal */}
      {showSupportModal && (
        <div style={{ position: "fixed", inset: 0, zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 24 }}>
          <div style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,0.55)" }} onClick={closeSupportModal} />
          <div style={{ position: "relative", background: "var(--z-card)", borderRadius: 20, padding: "32px 32px 28px", maxWidth: 500, width: "100%", boxShadow: "0 24px 80px rgba(0,0,0,0.3)" }}>
            {/* Close */}
            <button onClick={closeSupportModal} style={{ position: "absolute", top: 16, right: 16, width: 30, height: 30, borderRadius: 8, border: "1px solid var(--z-bd)", background: "var(--z-raise)", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", color: "var(--z-text2)" }}>
              <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" style={{ width: 12, height: 12 }}><path d="M3 3l10 10M13 3L3 13" strokeLinecap="round"/></svg>
            </button>

            {supportSuccess ? (
              <div style={{ textAlign: "center", padding: "8px 0 4px" }}>
                <div style={{ width: 52, height: 52, borderRadius: 14, background: "rgba(5,150,105,0.1)", border: "1px solid rgba(5,150,105,0.25)", display: "inline-flex", alignItems: "center", justifyContent: "center", marginBottom: 16 }}>
                  <svg viewBox="0 0 20 20" fill="none" stroke="#059669" strokeWidth="1.8" style={{ width: 22, height: 22 }}><path d="M4 10l4 4 8-8" strokeLinecap="round" strokeLinejoin="round"/></svg>
                </div>
                <h3 style={{ fontSize: 18, fontWeight: 800, color: "var(--z-text)", margin: "0 0 8px" }}>Ticket submitted</h3>
                <p style={{ fontSize: 14, color: "var(--z-text2)", lineHeight: 1.65, margin: "0 0 24px" }}>Your support request has been received. Our team will respond to <strong>{viewer.email}</strong> shortly.</p>
                <button onClick={closeSupportModal} style={{ fontSize: 14, fontWeight: 700, padding: "10px 28px", borderRadius: 11, border: "none", background: "#2563EB", color: "white", cursor: "pointer" }}>Done</button>
              </div>
            ) : (
              <>
                <h3 style={{ fontSize: 18, fontWeight: 800, color: "var(--z-text)", margin: "0 0 4px" }}>Contact support</h3>
                <p style={{ fontSize: 13, color: "var(--z-text2)", margin: "0 0 22px", lineHeight: 1.5 }}>Describe your issue and we'll get back to you at <strong>{viewer.email}</strong>.</p>

                <div style={{ display: "grid", gap: 14 }}>
                  <div>
                    <label style={{ fontSize: 11.5, fontWeight: 700, color: "var(--z-text2)", textTransform: "uppercase", letterSpacing: "0.08em", display: "block", marginBottom: 6 }}>Category</label>
                    <select
                      value={supportForm.category}
                      onChange={e => setSupportForm(f => ({ ...f, category: e.target.value }))}
                      style={{ width: "100%", fontSize: 13.5, padding: "9px 12px", borderRadius: 10, border: "1.5px solid var(--z-bd)", background: "var(--z-raise)", color: "var(--z-text)", outline: "none", fontFamily: "inherit" }}
                    >
                      <option value="billing">Billing</option>
                      <option value="technical">Technical issue</option>
                      <option value="product">Product feedback</option>
                      <option value="account">Account</option>
                      <option value="other">Other</option>
                    </select>
                  </div>

                  <div>
                    <label style={{ fontSize: 11.5, fontWeight: 700, color: "var(--z-text2)", textTransform: "uppercase", letterSpacing: "0.08em", display: "block", marginBottom: 6 }}>Subject</label>
                    <input
                      type="text"
                      placeholder="Brief summary of the issue"
                      value={supportForm.subject}
                      onChange={e => setSupportForm(f => ({ ...f, subject: e.target.value }))}
                      style={{ width: "100%", fontSize: 13.5, padding: "9px 12px", borderRadius: 10, border: "1.5px solid var(--z-bd)", background: "var(--z-raise)", color: "var(--z-text)", outline: "none", fontFamily: "inherit", boxSizing: "border-box" }}
                    />
                  </div>

                  <div>
                    <label style={{ fontSize: 11.5, fontWeight: 700, color: "var(--z-text2)", textTransform: "uppercase", letterSpacing: "0.08em", display: "block", marginBottom: 6 }}>Description</label>
                    <textarea
                      placeholder="What happened? What were you trying to do? Any error messages?"
                      value={supportForm.description}
                      onChange={e => setSupportForm(f => ({ ...f, description: e.target.value }))}
                      rows={5}
                      style={{ width: "100%", fontSize: 13.5, padding: "9px 12px", borderRadius: 10, border: "1.5px solid var(--z-bd)", background: "var(--z-raise)", color: "var(--z-text)", outline: "none", fontFamily: "inherit", resize: "vertical", boxSizing: "border-box", lineHeight: 1.65 }}
                    />
                  </div>

                  {supportError && (
                    <div style={{ fontSize: 13, color: "#EF4444", background: "rgba(239,68,68,0.08)", border: "1px solid rgba(239,68,68,0.2)", borderRadius: 9, padding: "9px 12px" }}>
                      {supportError}
                    </div>
                  )}

                  <div style={{ display: "flex", gap: 10, justifyContent: "flex-end", marginTop: 4 }}>
                    <button onClick={closeSupportModal} style={{ fontSize: 13.5, fontWeight: 600, padding: "10px 20px", borderRadius: 10, border: "1px solid var(--z-bd)", background: "transparent", color: "var(--z-text2)", cursor: "pointer" }}>Cancel</button>
                    <button
                      onClick={() => void submitSupportTicket()}
                      disabled={supportSubmitting || !supportForm.subject.trim() || !supportForm.description.trim()}
                      style={{ fontSize: 13.5, fontWeight: 700, padding: "10px 24px", borderRadius: 10, border: "none", background: "#2563EB", color: "white", cursor: supportSubmitting ? "default" : "pointer", opacity: (supportSubmitting || !supportForm.subject.trim() || !supportForm.description.trim()) ? 0.65 : 1 }}
                    >
                      {supportSubmitting ? "Submitting…" : "Submit ticket"}
                    </button>
                  </div>
                </div>
              </>
            )}
          </div>
        </div>
      )}

      {/* Header */}
      <div style={{ display: "flex", alignItems: "center", gap: 16, marginBottom: 28 }}>
        <div style={{ width: 58, height: 58, borderRadius: 18, background: `linear-gradient(135deg, ${planColor} 0%, ${planColor}cc 100%)`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22, fontWeight: 800, color: "white", letterSpacing: "-0.02em", flexShrink: 0, boxShadow: `0 6px 20px ${planColor}40` }}>
          {initials}
        </div>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 19, fontWeight: 800, color: "var(--z-text)", letterSpacing: "-0.03em", lineHeight: 1.2 }}>{viewer.name?.trim() || viewer.email.split("@")[0]}</div>
          <div style={{ fontSize: 13, color: "var(--z-text2)", marginTop: 3 }}>{viewer.email}</div>
        </div>
        {!isOperator && nextPlanName && (
          <Link href={nextPlanHref} style={{ fontSize: 12.5, fontWeight: 700, padding: "8px 16px", borderRadius: 9, background: "linear-gradient(135deg, #3B82F6 0%, #2563EB 100%)", color: "white", textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 6, boxShadow: "0 3px 12px rgba(37,99,235,0.35)", flexShrink: 0 }}>
            <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width: 12, height: 12 }}><path d="M8 2l1.6 3.2L13 5.9l-2.5 2.4.6 3.3L8 9.8l-3.1 1.8.6-3.3L3 5.9l3.4-.7z" fill="currentColor" stroke="none"/></svg>
            Upgrade to {nextPlanName}
          </Link>
        )}
      </div>

      {/* Profile */}
      <div style={sectionStyle}>
        <div style={labelStyle}>Profile</div>
        <div style={rowStyle}>
          <span style={keyStyle}>Full name</span>
          <span style={valStyle}>{viewer.name?.trim() || "—"}</span>
        </div>
        <div style={{ ...rowStyle, marginBottom: 0 }}>
          <span style={keyStyle}>Email address</span>
          <span style={valStyle}>{viewer.email}</span>
        </div>
        <div style={{ marginTop: 16, paddingTop: 14, borderTop: "1px solid var(--z-bd)" }}>
          <Link href="/settings/profile" style={{ fontSize: 12.5, fontWeight: 600, color: "#2563EB", textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 5 }}>
            <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width: 13, height: 13 }}><path d="M11.5 2.5a1.5 1.5 0 012.121 2.121l-7.5 7.5-2.828.707.707-2.828 7.5-7.5z"/></svg>
            Edit profile info
          </Link>
        </div>
      </div>

      {/* Subscription */}
      <div style={sectionStyle}>
        <div style={labelStyle}>Subscription</div>
        <div style={rowStyle}>
          <span style={keyStyle}>Plan</span>
          <span style={{ fontSize: 12, fontWeight: 700, padding: "2px 10px", borderRadius: 99, background: `${planColor}18`, color: planColor, border: `1px solid ${planColor}30` }}>
            {viewer.planName}
          </span>
        </div>
        <div style={rowStyle}>
          <span style={keyStyle}>Status</span>
          <span style={{ fontSize: 12, fontWeight: 700, display: "flex", alignItems: "center", gap: 5, color: statusColor }}>
            <span style={{ width: 7, height: 7, borderRadius: "50%", background: statusColor, display: "inline-block" }}/>
            {statusLabel}
          </span>
        </div>
        {priceLine && (
          <div style={rowStyle}>
            <span style={keyStyle}>Billing</span>
            <span style={valStyle}>{priceLine}</span>
          </div>
        )}
        <div style={{ ...rowStyle, marginBottom: 0 }}>
          <span style={keyStyle}>Renewal</span>
          <span style={valStyle}>Monthly · auto-renews</span>
        </div>
        {!isOperator && (
          <div style={{ marginTop: 16, paddingTop: 14, borderTop: "1px solid var(--z-bd)", display: "flex", gap: 10, flexWrap: "wrap" }}>
            {!viewer.isPaid ? (
              <Link href="/onboarding/plan" style={{ fontSize: 12.5, fontWeight: 700, padding: "8px 16px", borderRadius: 9, background: "linear-gradient(135deg, #3B82F6 0%, #2563EB 100%)", color: "white", textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 6, boxShadow: "0 3px 12px rgba(37,99,235,0.35)" }}>
                <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width: 13, height: 13 }}><path d="M8 2l1.6 3.2L13 5.9l-2.5 2.4.6 3.3L8 9.8l-3.1 1.8.6-3.3L3 5.9l3.4-.7z" fill="currentColor" stroke="none"/></svg>
                Choose a plan
              </Link>
            ) : nextPlanName ? (
              <Link href={nextPlanHref} style={{ fontSize: 12.5, fontWeight: 700, padding: "8px 16px", borderRadius: 9, background: "linear-gradient(135deg, #3B82F6 0%, #2563EB 100%)", color: "white", textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 6, boxShadow: "0 3px 12px rgba(37,99,235,0.35)" }}>
                Upgrade to {nextPlanName}
              </Link>
            ) : null}
            <button onClick={onComparePlans} style={{ fontSize: 12.5, fontWeight: 500, padding: "8px 14px", borderRadius: 9, border: "1px solid var(--z-bd)", background: "transparent", color: "var(--z-text2)", cursor: "pointer" }}>
              Compare plans
            </button>
          </div>
        )}
      </div>

      {/* Credits & Usage */}
      <div style={sectionStyle}>
        <div style={labelStyle}>Credits &amp; Usage</div>
        {isOperator ? (
          <div style={{ fontSize: 13, color: "var(--z-text2)", lineHeight: 1.6 }}>Operator accounts have unrestricted access — credit limits are not applied.</div>
        ) : limit > 0 ? (
          <>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 8 }}>
              <span style={{ fontSize: 13, color: "var(--z-text2)" }}>Used this cycle</span>
              <span style={{ fontSize: 22, fontWeight: 800, color: "var(--z-text)", letterSpacing: "-0.04em" }}>
                {fmtNum(used)}<span style={{ fontSize: 13, fontWeight: 500, color: "var(--z-text3)", marginLeft: 4 }}>/ {fmtNum(limit)}</span>
              </span>
            </div>
            <div style={{ height: 8, borderRadius: 99, background: "var(--z-raise)", overflow: "hidden", marginBottom: 8 }}>
              <div style={{ height: "100%", width: `${pct}%`, borderRadius: 99, background: barColor, transition: "width 0.6s cubic-bezier(0.4,0,0.2,1)" }}/>
            </div>
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11.5, color: "var(--z-text3)", marginBottom: 16 }}>
              <span>{pct}% used</span>
              <span style={{ color: pct >= 90 ? "#EF4444" : "var(--z-text3)" }}>{fmtNum(remaining)} remaining</span>
            </div>
            <div style={{ ...rowStyle, marginBottom: 8 }}>
              <span style={keyStyle}>Credits remaining</span>
              <span style={{ ...valStyle, color: pct >= 90 ? "#EF4444" : "var(--z-text)" }}>{fmtNum(remaining)}</span>
            </div>
            <div style={{ ...rowStyle, marginBottom: 0 }}>
              <span style={keyStyle}>Resets</span>
              <span style={valStyle}>Monthly (with billing cycle)</span>
            </div>
            {pct >= 80 && (
              <div style={{ marginTop: 14, padding: "12px 14px", borderRadius: 10, background: pct >= 90 ? "rgba(239,68,68,0.08)" : "rgba(245,158,11,0.08)", border: `1px solid ${pct >= 90 ? "rgba(239,68,68,0.2)" : "rgba(245,158,11,0.2)"}` }}>
                <div style={{ fontSize: 12, fontWeight: 700, color: pct >= 90 ? "#DC2626" : "#D97706", marginBottom: 4 }}>
                  {pct >= 100 ? "No credits remaining" : "Running low on credits"}
                </div>
                <div style={{ fontSize: 12, color: "var(--z-text2)", lineHeight: 1.5 }}>
                  {pct >= 100
                    ? "You've used all credits this cycle. Upgrade your plan or purchase more to continue."
                    : `You've used ${pct}% of your monthly credits. Consider upgrading to avoid interruptions.`}
                </div>
              </div>
            )}
            <div style={{ marginTop: 16, paddingTop: 14, borderTop: "1px solid var(--z-bd)", display: "flex", gap: 10, flexWrap: "wrap" }}>
              <button onClick={onBuyCredits} style={{ fontSize: 12.5, fontWeight: 700, padding: "8px 16px", borderRadius: 9, background: "linear-gradient(135deg, #3B82F6 0%, #2563EB 100%)", color: "white", border: "none", cursor: "pointer", display: "inline-flex", alignItems: "center", gap: 6, boxShadow: "0 3px 12px rgba(37,99,235,0.35)" }}>
                Buy more credits
              </button>
              <button onClick={onComparePlans} style={{ fontSize: 12.5, fontWeight: 500, padding: "8px 14px", borderRadius: 9, border: "1px solid var(--z-bd)", background: "transparent", color: "var(--z-text2)", cursor: "pointer" }}>
                Compare plans
              </button>
            </div>
          </>
        ) : (
          <div style={{ fontSize: 13, color: "var(--z-text2)", lineHeight: 1.6 }}>
            Credit tracking is available on paid plans.{" "}
            <Link href="/onboarding/plan" style={{ color: "#2563EB", fontWeight: 600 }}>Upgrade →</Link>
          </div>
        )}
      </div>

      {/* Security */}
      <div style={sectionStyle}>
        <div style={labelStyle}>Security</div>
        <div style={rowStyle}>
          <div>
            <div style={keyStyle}>Password</div>
            <div style={{ fontSize: 11.5, color: "var(--z-text3)", marginTop: 2 }}>Last changed: never</div>
          </div>
          <Link href="/settings/profile" style={{ fontSize: 12.5, fontWeight: 600, padding: "6px 12px", borderRadius: 8, border: "1px solid var(--z-bd)", background: "transparent", color: "var(--z-text2)", textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 5 }}>
            <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width: 12, height: 12 }}><rect x="3" y="7" width="10" height="7" rx="1.5"/><path d="M5 7V5a3 3 0 016 0v2"/></svg>
            Change
          </Link>
        </div>
        <div style={{ ...rowStyle, marginBottom: 0 }}>
          <div>
            <div style={keyStyle}>Active sessions</div>
            <div style={{ fontSize: 11.5, color: "var(--z-text3)", marginTop: 2 }}>Signed in on this device</div>
          </div>
          <PlatformLogoutButton className="" redirectTo="/login">
            <button style={{ fontSize: 12.5, fontWeight: 600, padding: "6px 12px", borderRadius: 8, border: "1px solid var(--z-bd)", background: "transparent", color: "var(--z-text2)", cursor: "pointer", display: "inline-flex", alignItems: "center", gap: 5 }}>
              <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width: 12, height: 12 }}><path d="M10 11l4-3-4-3M14 8H6M6 3H3a1 1 0 00-1 1v8a1 1 0 001 1h3"/></svg>
              Sign out
            </button>
          </PlatformLogoutButton>
        </div>
      </div>

      {/* Preferences */}
      <div style={sectionStyle}>
        <div style={labelStyle}>Preferences</div>
        <div style={{ ...rowStyle, marginBottom: 0 }}>
          <div>
            <div style={keyStyle}>Email notifications</div>
            <div style={{ fontSize: 11.5, color: "var(--z-text3)", marginTop: 2 }}>Coaching tips, session reminders, product updates</div>
          </div>
          <div style={{ fontSize: 12, fontWeight: 600, padding: "5px 12px", borderRadius: 8, background: "rgba(34,197,94,0.1)", color: "#16A34A", border: "1px solid rgba(34,197,94,0.2)" }}>On</div>
        </div>
      </div>

      {/* Referrals */}
      <div style={sectionStyle}>
        <div style={labelStyle}>Refer &amp; Earn</div>
        <div style={{ fontSize: 13, color: "var(--z-text2)", lineHeight: 1.6, marginBottom: 14 }}>
          Share Zari with a friend and get <strong style={{ color: "var(--z-text)" }}>1 free month</strong> when they subscribe. No limits.
        </div>
        <button
          onClick={() => { try { navigator.clipboard.writeText("https://zari.app?ref=" + encodeURIComponent(viewer.email)); } catch {} }}
          style={{ fontSize: 12.5, fontWeight: 600, padding: "8px 16px", borderRadius: 9, border: "1px solid var(--z-bd)", background: "var(--z-raise)", color: "var(--z-text)", cursor: "pointer", display: "inline-flex", alignItems: "center", gap: 6 }}
        >
          <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width: 12, height: 12 }}><path d="M10 2H6a1 1 0 00-1 1v9a1 1 0 001 1h6a1 1 0 001-1V5l-3-3z"/><path d="M10 2v3h3"/><path d="M4 9H2a1 1 0 01-1-1V3a1 1 0 011-1h4"/></svg>
          Copy referral link
        </button>
      </div>

      {/* Help & Support */}
      <div style={sectionStyle}>
        <div style={labelStyle}>Help &amp; Support</div>
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          <button onClick={() => setShowSupportModal(true)} style={{ fontSize: 13, color: "#2563EB", background: "none", border: "none", fontWeight: 500, display: "inline-flex", alignItems: "center", gap: 6, cursor: "pointer", padding: 0 }}>
            <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width: 13, height: 13 }}><rect x="1" y="3" width="14" height="10" rx="1.5"/><path d="M1 4l7 5 7-5"/></svg>
            Contact support
          </button>
          <a href="/terms" style={{ fontSize: 13, color: "var(--z-text2)", textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 6 }}>
            <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width: 13, height: 13 }}><path d="M10 2H4a1 1 0 00-1 1v10a1 1 0 001 1h8a1 1 0 001-1V5l-3-3z"/><path d="M10 2v3h3"/></svg>
            Terms of Service
          </a>
          <a href="/privacy" style={{ fontSize: 13, color: "var(--z-text2)", textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 6 }}>
            <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width: 13, height: 13 }}><path d="M8 2L3 4v4c0 3 2.5 5.5 5 6.5C11 13.5 13 11 13 8V4L8 2z"/></svg>
            Privacy Policy
          </a>
        </div>
      </div>

      {/* Advanced / Danger zone — buried */}
      {viewer.isPaid && !isOperator && (
        <div style={{ marginBottom: 14 }}>
          <button
            onClick={() => setShowDangerZone(d => !d)}
            style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between", padding: "12px 16px", borderRadius: 10, border: "1px solid var(--z-bd)", background: "transparent", cursor: "pointer", color: "var(--z-text3)", fontSize: 12.5, fontWeight: 600 }}
          >
            <span>Advanced settings</span>
            <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" style={{ width: 12, height: 12, transform: showDangerZone ? "rotate(90deg)" : "none", transition: "transform 0.2s" }}><path d="M6 4l4 4-4 4"/></svg>
          </button>
          {showDangerZone && (
            <div style={{ marginTop: 8, padding: "16px 20px", borderRadius: 10, border: "1px solid rgba(239,68,68,0.2)", background: "rgba(239,68,68,0.03)" }}>
              <div style={{ fontSize: 12, fontWeight: 700, color: "#DC2626", marginBottom: 8, textTransform: "uppercase" as const, letterSpacing: "0.06em" }}>Danger zone</div>
              <div style={{ fontSize: 13, color: "var(--z-text2)", lineHeight: 1.6, marginBottom: 14 }}>
                Canceling will immediately end your access to Growth features. Your data is preserved and you can resubscribe at any time.
              </div>
              {!cancelConfirm ? (
                <button
                  onClick={() => setCancelConfirm(true)}
                  style={{ fontSize: 12.5, fontWeight: 600, padding: "8px 14px", borderRadius: 8, border: "1px solid rgba(239,68,68,0.3)", background: "transparent", color: "#DC2626", cursor: "pointer" }}
                >
                  Cancel subscription
                </button>
              ) : (
                <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                  <span style={{ fontSize: 12.5, color: "var(--z-text2)" }}>Are you sure?</span>
                  <Link href="/settings/subscription/cancel" style={{ fontSize: 12.5, fontWeight: 700, padding: "7px 14px", borderRadius: 8, background: "#DC2626", color: "white", textDecoration: "none" }}>
                    Yes, cancel
                  </Link>
                  <button onClick={() => setCancelConfirm(false)} style={{ fontSize: 12.5, fontWeight: 600, padding: "7px 12px", borderRadius: 8, border: "1px solid var(--z-bd)", background: "transparent", color: "var(--z-text2)", cursor: "pointer" }}>
                    Never mind
                  </button>
                </div>
              )}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

/* ═══════════════════════════════════════════════════
   MAIN PORTAL SHELL
═══════════════════════════════════════════════════ */
export function ZariPortal({ viewer }: { viewer: PortalViewer }) {
  const [screen, setScreen] = useState<Screen>(() => {
    try { return (localStorage.getItem("zari_screen") as Screen) || "session"; } catch { return "session"; }
  });
  const [stage, setStage] = useState<CareerStage>("job-search");
  const [stageOpen, setStageOpen] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [hydrated,    setHydrated]    = useState(false);
  const [isDark, setIsDark] = useState(() => {
    try { return localStorage.getItem("zari_dark") === "1"; } catch { return false; }
  });
  const themeVars = (isDark ? DARK_THEME : LIGHT_THEME) as React.CSSProperties;
  const toggleDark = () => setIsDark(d => { const v = !d; try { localStorage.setItem("zari_dark", v?"1":"0"); } catch {} return v; });
  const isOperatorViewer = viewer.role === "admin" || viewer.role === "support";
  const userDisplayName = viewer.name?.trim() || viewer.email.split("@")[0] || "Your account";
  const userEmail = viewer.email?.trim() || "—";
  const [upgradeNotice, setUpgradeNotice] = useState<null | {
    requiredPlanId: string;
    title: string;
    body: string;
  }>(null);
  const [creditLimitNotice, setCreditLimitNotice] = useState<null | {
    used: number;
    limit: number;
    proactive?: boolean;
  }>(null);
  const [topupOpen, setTopupOpen] = useState(false);
  const [topupLoading, setTopupLoading] = useState<string | null>(null);
  const [topupErr, setTopupErr] = useState<string | null>(null);
  const [topupCustom, setTopupCustom] = useState("");
  const [comparePlansOpen, setComparePlansOpen] = useState(false);
  const [billingPortalLoading, setBillingPortalLoading] = useState(false);
  const formatCredits = (value?: number | null) =>
    new Intl.NumberFormat("en-US", {
      minimumFractionDigits: value && value % 1 !== 0 ? 2 : 0,
      maximumFractionDigits: 2,
    }).format(Number(value || 0));
  const sidebarPlanTitle = isOperatorViewer ? "Internal operator" : viewer.planName;
  const sidebarPlanCopy = isOperatorViewer
    ? "Operator workspace with full internal access."
    : viewer.isPaid
      ? `${formatCredits(viewer.remainingMonthlyCredits ?? viewer.creditLimit ?? viewer.includedMonthlyCredits)} of ${formatCredits(viewer.creditLimit ?? viewer.includedMonthlyCredits)} credits left this cycle · ${viewer.subscriptionStatus || "active"}`
      : "Upgrade for unlimited sessions, downloads, and priority coaching.";
  const showUpgradeCta = !isOperatorViewer && (!viewer.isPaid || Boolean(upgradeNotice));

  const promptUpgrade = useCallback((requiredPlanId: string, reason: string) => {
    const requiredPlanName = getPlanDisplayName(requiredPlanId);
    setCreditLimitNotice(null);
    setUpgradeNotice({
      requiredPlanId,
      title: `Upgrade to ${requiredPlanName}`,
      body: reason,
    });
  }, []);

  const promptCreditLimit = useCallback((used: number, limit: number) => {
    setUpgradeNotice(null);
    setCreditLimitNotice({ used, limit });
  }, []);

  const billingCtx: BillingCtx = { planId: viewer.planId, role: viewer.role ?? null, onPlanBlock: promptUpgrade, onCreditLimit: promptCreditLimit };

  // Hydrate localStorage from server on first load — server is source of truth
  useEffect(() => {
    fetch("/api/portal/state")
      .then(r => r.ok ? r.json() : null)
      .then((serverState: Record<string, unknown> | null) => {
        if (!serverState || typeof localStorage === "undefined") return;
        for (const [key, data] of Object.entries(serverState)) {
          if (data !== null && data !== undefined) {
            try { localStorage.setItem(key, JSON.stringify(data)); } catch { /* noop */ }
          }
        }
        // Signal screens to re-read their data now that localStorage is populated
        window.dispatchEvent(new CustomEvent("vault-updated"));
        window.dispatchEvent(new CustomEvent("zari-state-synced"));
      })
      .catch(() => { /* best-effort */ })
      .finally(() => setHydrated(true));
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Show credit-limit paywall immediately on load if the account is already over-limit
  useEffect(() => {
    const isOperatorViewer = viewer.role === "admin" || viewer.role === "support";
    if (!isOperatorViewer && viewer.isPaid && viewer.remainingMonthlyCredits !== null && viewer.remainingMonthlyCredits <= 0) {
      const used  = viewer.usedMonthlyCredits  ?? viewer.creditLimit ?? 0;
      const limit = viewer.creditLimit ?? viewer.includedMonthlyCredits ?? 0;
      setCreditLimitNotice({ used, limit });
    }
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => {
    const decision = canAccessStage({ planId: viewer.planId, role: viewer.role, stage });
    if (!decision.ok) {
      setStage("job-search");
      setScreen("session");
      setUpgradeNotice({
        requiredPlanId: decision.requiredPlanId || "growth",
        title: `Upgrade to ${getPlanDisplayName(decision.requiredPlanId)}`,
        body: `Your current plan does not include the ${STAGE_META[stage].label} stage.`,
      });
    }
  }, [stage, viewer.planId, viewer.role]);

  // Persist active screen so refresh lands back on the same section
  const navigate = (s: Screen) => {
    setScreen(s);
    setUpgradeNotice(null);
    // Never clear the credit limit paywall — user must upgrade or buy credits to proceed
    setSidebarOpen(false);
    try { localStorage.setItem("zari_screen", s); } catch { /* ignore */ }
  };

  const selectStage = (nextStage: CareerStage) => {
    const decision = canAccessStage({ planId: viewer.planId, role: viewer.role, stage: nextStage });
    if (!decision.ok) {
      const requiredPlanId = decision.requiredPlanId || getRequiredPlanForStage(nextStage) || "growth";
      promptUpgrade(requiredPlanId, `${STAGE_META[nextStage].label} is available on ${getPlanDisplayName(requiredPlanId)} and above.`);
      setStageOpen(false);
      return;
    }

    setUpgradeNotice(null);
    setStage(nextStage);
    setStageOpen(false);
    navigate("session");
  };

  // Section accent colors for topbar context
  const SCREEN_ACCENTS: Record<string, { color: string; gradient: string }> = {
    session:       { color:"#2563EB", gradient:"linear-gradient(135deg,#2563EB,#60A5FA)" },
    resume:        { color:"#2563EB", gradient:"linear-gradient(135deg,#2563EB,#60A5FA)" },
    interview:     { color:"#D97706", gradient:"linear-gradient(135deg,#D97706,#FBBF24)" },
    "cover-letter":{ color:"#059669", gradient:"linear-gradient(135deg,#059669,#34D399)" },
    linkedin:      { color:"#0A66C2", gradient:"linear-gradient(135deg,#0A66C2,#38BDF8)" },
    documents:     { color:"#64748B", gradient:"linear-gradient(135deg,#334155,#64748B)" },
    plan:          { color:"#2563EB", gradient:"linear-gradient(135deg,#2563EB,#60A5FA)" },
  };
  const accentInfo = SCREEN_ACCENTS[screen] ?? SCREEN_ACCENTS["session"];
  const paymentIssueStatuses = ["past_due", "unpaid", "incomplete", "incomplete_expired"];
  const hasPaymentIssue = !isOperatorViewer && viewer.subscriptionStatus != null && paymentIssueStatuses.includes(viewer.subscriptionStatus);

  return (
    <BillingContext.Provider value={billingCtx}>
    <div className={isDark?"zari-dark":""} style={{ display:"flex", flexDirection:"column", height:"100vh", overflow:"hidden", background:"var(--z-bg)", fontFamily:"var(--font-geist-sans,Inter,system-ui,sans-serif)", WebkitFontSmoothing:"antialiased", MozOsxFontSmoothing:"grayscale", ...themeVars, backgroundImage: isDark ? "radial-gradient(ellipse 80% 60% at 50% -20%, rgba(37,99,235,0.07) 0%, transparent 100%)" : "none" }}>
      {/* Upgrade notice modal — shown when user clicks a stage/feature they can't access */}
      {upgradeNotice && (() => {
        const reqPlan = upgradeNotice.requiredPlanId ?? "growth";
        const planColor = reqPlan === "executive" ? "#F59E0B" : "#2563EB";
        const planColorDark = reqPlan === "executive" ? "#D97706" : "#1D4ED8";
        const planFeatures: Record<string, string[]> = {
          growth: ["Mock interviews & coaching", "Promotion & salary tools", "Unlimited AI rewrites"],
          executive: ["Executive positioning tools", "Career pivot coaching", "Priority AI queue"],
        };
        const bullets = planFeatures[reqPlan] ?? planFeatures.growth;
        return (
          <div style={{ position:"fixed", inset:0, zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:24 }}>
            <div style={{ position:"absolute", inset:0, background:"rgba(0,0,0,0.65)", backdropFilter:"blur(4px)" }} onClick={() => setUpgradeNotice(null)} />
            <div style={{ position:"relative", background:"var(--z-card)", borderRadius:24, maxWidth:420, width:"100%", textAlign:"center", boxShadow:`0 32px 80px rgba(0,0,0,0.4), 0 0 0 1px ${planColor}20`, animation:"bubble-appear 0.2s ease", overflow:"hidden" }}>
              {/* Top gradient accent bar */}
              <div style={{ height:4, background:`linear-gradient(90deg, ${planColor}, ${planColorDark})`, width:"100%" }}/>
              {/* Dismiss button */}
              <button onClick={() => setUpgradeNotice(null)} style={{ position:"absolute", top:16, right:16, width:28, height:28, borderRadius:8, border:"1px solid var(--z-bd)", background:"var(--z-raise)", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", color:"var(--z-text2)" }}>
                <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" style={{ width:11, height:11 }}><path d="M3 3l10 10M13 3L3 13" strokeLinecap="round"/></svg>
              </button>
              <div style={{ padding:"32px 36px 28px" }}>
                {/* Icon */}
                <div style={{ width:56, height:56, borderRadius:16, background:`linear-gradient(135deg, ${planColor}20, ${planColor}10)`, border:`1px solid ${planColor}30`, display:"inline-flex", alignItems:"center", justifyContent:"center", marginBottom:18, boxShadow:`0 8px 24px ${planColor}20` }}>
                  <svg viewBox="0 0 24 24" fill="none" stroke={planColor} strokeWidth="2" style={{ width:26, height:26 }}>
                    <rect x="3" y="11" width="18" height="11" rx="2" ry="2"/>
                    <path d="M7 11V7a5 5 0 0 1 10 0v4"/>
                  </svg>
                </div>
                {/* Plan badge */}
                <div style={{ fontSize:10.5, fontWeight:800, color:planColor, textTransform:"uppercase", letterSpacing:"0.12em", marginBottom:8 }}>
                  {upgradeNotice.requiredPlanId === "executive" ? "Executive" : "Growth"} Plan
                </div>
                <h3 style={{ fontSize:20, fontWeight:900, color:"var(--z-text)", margin:"0 0 8px", letterSpacing:"-0.03em", lineHeight:1.2 }}>{upgradeNotice.title}</h3>
                <p style={{ fontSize:13.5, color:"var(--z-text2)", lineHeight:1.65, margin:"0 0 20px" }}>{upgradeNotice.body}</p>
                {/* Feature bullets */}
                <div style={{ background:"var(--z-raise)", borderRadius:12, padding:"14px 16px", marginBottom:22, textAlign:"left" }}>
                  {bullets.map((b, i) => (
                    <div key={i} style={{ display:"flex", alignItems:"center", gap:10, marginBottom:i < bullets.length-1 ? 10 : 0 }}>
                      <div style={{ width:18, height:18, borderRadius:99, background:`${planColor}18`, border:`1px solid ${planColor}30`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                        <svg viewBox="0 0 12 12" fill="none" stroke={planColor} strokeWidth="2" style={{ width:8, height:8 }}><path d="M2 6l3 3 5-5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                      </div>
                      <span style={{ fontSize:13, color:"var(--z-text)", fontWeight:500 }}>{b}</span>
                    </div>
                  ))}
                </div>
                {/* CTA */}
                <button
                  onClick={() => { setUpgradeNotice(null); window.location.href = `/onboarding/plan?upgrade=${encodeURIComponent(reqPlan)}`; }}
                  style={{ display:"inline-flex", alignItems:"center", gap:8, fontSize:14.5, fontWeight:800, padding:"14px 32px", borderRadius:13, border:"none", background:`linear-gradient(135deg, ${planColor} 0%, ${planColorDark} 100%)`, color:"white", cursor:"pointer", boxShadow:`0 6px 24px ${planColor}45`, letterSpacing:"-0.01em", width:"100%" }}
                >
                  <svg viewBox="0 0 20 20" fill="none" stroke="white" strokeWidth="2" style={{ width:15, height:15 }}>
                    <path d="M10 2l2.4 6.6H19l-5.7 4.1 2.2 6.7L10 15.4 4.5 19.4l2.2-6.7L1 8.6h6.6L10 2z" fill="white" stroke="none"/>
                  </svg>
                  {upgradeNotice.title} →
                </button>
                <div style={{ marginTop:12 }}>
                  <button onClick={() => setUpgradeNotice(null)} style={{ fontSize:12.5, color:"var(--z-text3)", background:"none", border:"none", cursor:"pointer", fontWeight:500 }}>Not now</button>
                </div>
              </div>
            </div>
          </div>
        );
      })()}

      {/* ── Compare Plans Modal ── */}
      {comparePlansOpen && (() => {
        const PLANS = [
          {
            id: "search",
            name: "Search",
            price: "Free",
            credits: "50 credits / mo",
            color: "#64748B",
            features: ["Resume review & scoring", "Cover letter generator", "Job search tools", "Basic AI rewrites"],
          },
          {
            id: "growth",
            name: "Growth",
            price: "$49/mo",
            credits: "300 credits / mo",
            color: "#2563EB",
            features: ["Everything in Search", "Mock interviews & coaching", "LinkedIn profile review", "Unlimited section rewrites", "Power Optimized resume"],
          },
          {
            id: "executive",
            name: "Executive",
            price: "$99/mo",
            credits: "800 credits / mo",
            color: "#F59E0B",
            features: ["Everything in Growth", "Executive positioning tools", "Salary negotiation coaching", "Career pivot blueprint", "Priority AI queue"],
          },
        ] as const;

        const planOrder = ["search", "growth", "executive"];
        const currentIdx = planOrder.indexOf(viewer.planId ?? "search");

        async function openBillingPortal() {
          setBillingPortalLoading(true);
          try {
            const res = await fetch("/api/billing/portal", { method: "POST", headers: { "Content-Type": "application/json" } });
            const data = await res.json().catch(() => ({})) as { url?: string; error?: string };
            if (data.url) window.location.href = data.url;
          } catch { /* ignore */ }
          setBillingPortalLoading(false);
        }

        return (
          <div style={{ position:"fixed", inset:0, zIndex:9998, display:"flex", alignItems:"center", justifyContent:"center", padding:"24px 16px", overflow:"auto" }}>
            <div style={{ position:"absolute", inset:0, background:"rgba(0,0,0,0.65)", backdropFilter:"blur(4px)" }} onClick={() => setComparePlansOpen(false)} />
            <div style={{ position:"relative", background:"var(--z-card)", borderRadius:24, maxWidth:720, width:"100%", boxShadow:"0 32px 80px rgba(0,0,0,0.4)", animation:"bubble-appear 0.2s ease", overflow:"hidden" }}>
              {/* header */}
              <div style={{ padding:"24px 28px 20px", borderBottom:"1px solid var(--z-bd)", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
                <div>
                  <div style={{ fontSize:18, fontWeight:800, color:"var(--z-text)", letterSpacing:"-0.03em" }}>Compare plans</div>
                  <div style={{ fontSize:12.5, color:"var(--z-text2)", marginTop:2 }}>
                    Your current plan: <span style={{ fontWeight:700, color:"var(--z-text)" }}>{PLANS.find(p => p.id === viewer.planId)?.name ?? "Free"}</span>
                  </div>
                </div>
                <button onClick={() => setComparePlansOpen(false)} style={{ width:30, height:30, borderRadius:8, border:"1px solid var(--z-bd)", background:"var(--z-raise)", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", color:"var(--z-text2)" }}>
                  <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" style={{ width:11, height:11 }}><path d="M3 3l10 10M13 3L3 13" strokeLinecap="round"/></svg>
                </button>
              </div>

              {/* plan cards */}
              <div style={{ padding:"20px 24px 28px", display:"grid", gridTemplateColumns:"repeat(3, 1fr)", gap:12 }}>
                {PLANS.map(plan => {
                  const isCurrent = plan.id === viewer.planId;
                  const planIdx = planOrder.indexOf(plan.id);
                  const isUpgrade = planIdx > currentIdx;
                  const isDowngrade = planIdx < currentIdx;

                  return (
                    <div key={plan.id} style={{ borderRadius:16, border:`2px solid ${isCurrent ? plan.color + "50" : "var(--z-bd)"}`, background: isCurrent ? `${plan.color}08` : "var(--z-raise)", padding:"20px 18px", display:"flex", flexDirection:"column", gap:14, position:"relative", opacity: isCurrent ? 0.75 : 1, transition:"all 0.15s" }}>
                      {isCurrent && (
                        <div style={{ position:"absolute", top:-1, right:14, fontSize:10, fontWeight:800, textTransform:"uppercase", letterSpacing:"0.1em", color:plan.color, background:"var(--z-card)", padding:"3px 10px", borderRadius:"0 0 8px 8px", border:`1px solid ${plan.color}40`, borderTop:"none" }}>
                          Your plan
                        </div>
                      )}
                      {/* plan header */}
                      <div>
                        <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:6 }}>
                          <div style={{ width:10, height:10, borderRadius:"50%", background:plan.color, flexShrink:0 }}/>
                          <div style={{ fontSize:15, fontWeight:800, color:"var(--z-text)", letterSpacing:"-0.02em" }}>{plan.name}</div>
                        </div>
                        <div style={{ fontSize:20, fontWeight:900, color:plan.color, letterSpacing:"-0.04em", lineHeight:1 }}>{plan.price}</div>
                        <div style={{ fontSize:11, color:"var(--z-text3)", marginTop:3 }}>{plan.credits}</div>
                      </div>
                      {/* features */}
                      <div style={{ flex:1, display:"flex", flexDirection:"column", gap:7 }}>
                        {plan.features.map((f, i) => (
                          <div key={i} style={{ display:"flex", alignItems:"flex-start", gap:8 }}>
                            <svg viewBox="0 0 12 12" fill="none" stroke={isCurrent ? plan.color : "var(--z-text3)"} strokeWidth="2" style={{ width:10, height:10, flexShrink:0, marginTop:2 }}><path d="M2 6l3 3 5-5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                            <span style={{ fontSize:11.5, color:"var(--z-text2)", lineHeight:1.4 }}>{f}</span>
                          </div>
                        ))}
                      </div>
                      {/* CTA */}
                      {isCurrent ? (
                        <div style={{ fontSize:12, fontWeight:700, textAlign:"center", color:plan.color, padding:"8px 0", borderRadius:9, border:`1px solid ${plan.color}30`, background:`${plan.color}08` }}>
                          Current plan
                        </div>
                      ) : isUpgrade ? (
                        <button onClick={() => { setComparePlansOpen(false); window.location.href = `/onboarding/plan?upgrade=${encodeURIComponent(plan.id)}`; }} style={{ fontSize:12.5, fontWeight:700, padding:"9px 14px", borderRadius:9, border:"none", background:`linear-gradient(135deg, ${plan.color} 0%, ${plan.color}cc 100%)`, color:"white", cursor:"pointer", boxShadow:`0 4px 14px ${plan.color}35` }}>
                          Upgrade to {plan.name} →
                        </button>
                      ) : isDowngrade ? (
                        <button onClick={() => { setComparePlansOpen(false); void openBillingPortal(); }} disabled={billingPortalLoading} style={{ fontSize:12.5, fontWeight:600, padding:"9px 14px", borderRadius:9, border:"1px solid var(--z-bd)", background:"transparent", color:"var(--z-text2)", cursor:billingPortalLoading ? "default" : "pointer" }}>
                          {billingPortalLoading ? "Loading…" : `Downgrade to ${plan.name}`}
                        </button>
                      ) : null}
                    </div>
                  );
                })}
              </div>

              <div style={{ padding:"0 28px 20px", textAlign:"center" }}>
                <div style={{ fontSize:11.5, color:"var(--z-text3)" }}>
                  Questions about plans?{" "}
                  <button onClick={() => { setComparePlansOpen(false); navigate("account"); }} style={{ background:"none", border:"none", cursor:"pointer", color:"#2563EB", fontWeight:600, fontSize:11.5, padding:0 }}>
                    Contact support
                  </button>
                </div>
              </div>
            </div>
          </div>
        );
      })()}

      {/* ── Credit Limit Paywall — always dark, non-dismissable full-screen gate ── */}
      {creditLimitNotice && (() => {
        const { proactive } = creditLimitNotice;
        const usedPct    = creditLimitNotice.limit > 0 ? Math.min(100, Math.round((creditLimitNotice.used / creditLimitNotice.limit) * 100)) : 100;
        const nextPlanId   = viewer.planId === "search" ? "growth" : viewer.planId === "growth" ? "executive" : null;
        const nextPlanName = nextPlanId === "growth" ? "Growth" : nextPlanId === "executive" ? "Executive" : null;
        const upgradeHref  = nextPlanId ? `/onboarding/plan?upgrade=${encodeURIComponent(nextPlanId)}` : "/onboarding/plan";
        return (
          <div style={{ position:"fixed", inset:0, zIndex:10000, display:"flex", alignItems:"flex-start", justifyContent:"center", overflowY:"auto", padding:"24px 20px",
            background:"radial-gradient(ellipse 140% 80% at 50% -5%, rgba(37,99,235,0.28) 0%, rgba(3,5,15,1) 55%)",
            fontFamily:"var(--font-geist-sans,Inter,system-ui,sans-serif)", WebkitFontSmoothing:"antialiased" }}>

            {/* Portal blur — always applied regardless of theme */}
            <div style={{ position:"absolute", inset:0, backdropFilter:"blur(24px) brightness(0.3) saturate(0.5)", pointerEvents:"none" }} />

            {/* Aurora depth blobs */}
            <div style={{ position:"absolute", top:"6%",   left:"15%",  width:540, height:540, borderRadius:"50%", background:"radial-gradient(circle, rgba(37,99,235,0.22) 0%, transparent 62%)",  pointerEvents:"none", animation:"aurora-slow 12s ease-in-out infinite" }}/>
            <div style={{ position:"absolute", bottom:"4%", right:"10%", width:420, height:420, borderRadius:"50%", background:"radial-gradient(circle, rgba(99,102,241,0.18) 0%, transparent 62%)", pointerEvents:"none", animation:"aurora-slow 16s 3s ease-in-out infinite" }}/>
            <div style={{ position:"absolute", top:"42%",  right:"22%", width:280, height:280, borderRadius:"50%", background:"radial-gradient(circle, rgba(139,92,246,0.14) 0%, transparent 62%)", pointerEvents:"none", animation:"aurora-slow 9s 1.5s ease-in-out infinite" }}/>

            {/* Card */}
            <div style={{ position:"relative", width:"100%", maxWidth:440, margin:"auto", animation:"bubble-appear 0.35s cubic-bezier(0.34,1.56,0.64,1)" }}>
              {/* Outer glow ring */}
              <div style={{ position:"absolute", inset:-1, borderRadius:26, background:"linear-gradient(135deg, rgba(37,99,235,0.55), rgba(99,102,241,0.35), rgba(139,92,246,0.28))", filter:"blur(22px)", opacity:0.55, pointerEvents:"none" }}/>

              <div style={{ position:"relative", background:"linear-gradient(160deg, #09102a 0%, #060a1c 100%)", border:"1px solid rgba(99,102,241,0.28)", borderRadius:24, overflow:"hidden", boxShadow:"0 48px 120px rgba(0,0,0,0.75), inset 0 1px 0 rgba(255,255,255,0.07)" }}>

                {/* Rainbow top bar */}
                <div style={{ height:3, background:"linear-gradient(90deg, #1D4ED8 0%, #4F46E5 40%, #7C3AED 75%, #6366F1 100%)", width:"100%" }}/>

                {/* Close button — always visible in proactive mode, shown as X in corner */}
                {proactive && (
                  <button onClick={() => { setCreditLimitNotice(null); setTopupOpen(false); setTopupErr(null); }} style={{ position:"absolute", top:16, right:16, width:28, height:28, borderRadius:8, background:"rgba(255,255,255,0.07)", border:"1px solid rgba(255,255,255,0.1)", display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", color:"rgba(255,255,255,0.5)", zIndex:2 }}>
                    <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" style={{ width:11, height:11 }}><path d="M3 3l10 10M13 3L3 13"/></svg>
                  </button>
                )}

                <div style={{ padding:"28px 28px 24px", textAlign:"center" }}>

                  {/* Icon */}
                  <div style={{ width:52, height:52, borderRadius:16, background:"linear-gradient(135deg, rgba(37,99,235,0.28) 0%, rgba(99,102,241,0.20) 100%)", border:"1px solid rgba(99,102,241,0.38)", display:"inline-flex", alignItems:"center", justifyContent:"center", marginBottom:14, boxShadow:"0 0 36px rgba(37,99,235,0.35), inset 0 1px 0 rgba(255,255,255,0.08)" }}>
                    <svg viewBox="0 0 24 24" fill="none" strokeLinecap="round" strokeLinejoin="round" style={{ width:24, height:24 }}>
                      <path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z" fill="rgba(99,102,241,0.28)" stroke="#818CF8" strokeWidth="1.5"/>
                    </svg>
                  </div>

                  {/* Eyebrow */}
                  <div style={{ fontSize:10, fontWeight:900, color:"#818CF8", textTransform:"uppercase", letterSpacing:"0.22em", marginBottom:7 }}>{proactive ? "Add Credits" : "Credits Exhausted"}</div>

                  {/* Headline */}
                  <h2 style={{ fontSize:23, fontWeight:900, color:"rgba(255,255,255,0.95)", margin:"0 0 8px", letterSpacing:"-0.04em", lineHeight:1.15 }}>
                    {proactive ? "Add credits to your account" : "You've used all your credits"}
                  </h2>

                  {/* Sub */}
                  <p style={{ fontSize:12.5, color:"rgba(255,255,255,0.45)", lineHeight:1.65, margin:"0 auto 16px", maxWidth:320 }}>
                    {proactive
                      ? "Pick a credit pack and it's added to your account instantly. Your current access continues uninterrupted."
                      : "Your monthly balance is empty. Upgrade your plan, buy a top-up pack, or wait for your next billing cycle to continue."}
                  </p>

                  {/* Credit bar */}
                  <div style={{ background:"rgba(255,255,255,0.04)", border:"1px solid rgba(255,255,255,0.09)", borderRadius:12, padding:"12px 16px", marginBottom:16 }}>
                    <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:8 }}>
                      <span style={{ fontSize:10.5, fontWeight:700, color:"rgba(255,255,255,0.4)", textTransform:"uppercase", letterSpacing:"0.09em" }}>Monthly Credits</span>
                      <span style={{ fontSize:12.5, fontWeight:800, color: proactive ? "#818CF8" : "#F87171", letterSpacing:"-0.02em" }}>{creditLimitNotice.used.toFixed(0)} / {creditLimitNotice.limit.toFixed(0)} used</span>
                    </div>
                    <div style={{ height:5, borderRadius:99, background:"rgba(255,255,255,0.07)", overflow:"hidden" }}>
                      <div style={{ height:"100%", width:`${usedPct}%`, borderRadius:99, background: proactive ? "linear-gradient(90deg, #2563EB 0%, #4F46E5 60%, #818CF8 100%)" : "linear-gradient(90deg, #B91C1C 0%, #EF4444 60%, #F87171 100%)", boxShadow: proactive ? "0 0 10px rgba(99,102,241,0.55)" : "0 0 10px rgba(239,68,68,0.65)" }}/>
                    </div>
                    <div style={{ marginTop:7, fontSize:10.5, color:"rgba(255,255,255,0.28)", textAlign:"center" }}>Resets automatically on your next billing date</div>
                  </div>

                  {/* Options */}
                  <div style={{ display:"flex", flexDirection:"column", gap:7, marginBottom:16 }}>

                    {/* Upgrade — primary CTA */}
                    {nextPlanName && (
                      <button onClick={() => { window.location.href = upgradeHref; }}
                        style={{ display:"flex", alignItems:"center", gap:12, padding:"12px 14px", borderRadius:12, border:"1.5px solid rgba(99,102,241,0.5)", background:"linear-gradient(135deg, rgba(37,99,235,0.24) 0%, rgba(79,70,229,0.20) 100%)", cursor:"pointer", textAlign:"left", boxShadow:"0 4px 20px rgba(37,99,235,0.22), inset 0 1px 0 rgba(255,255,255,0.07)" }}>
                        <div style={{ width:38, height:38, borderRadius:11, background:"linear-gradient(135deg, #2563EB 0%, #4F46E5 100%)", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, boxShadow:"0 4px 14px rgba(37,99,235,0.55)" }}>
                          <svg viewBox="0 0 20 20" fill="white" style={{ width:17, height:17 }}><path d="M10 2l2.4 6.6H19l-5.7 4.1 2.2 6.7L10 15.4 4.5 19.4l2.2-6.7L1 8.6h6.6L10 2z"/></svg>
                        </div>
                        <div style={{ flex:1, textAlign:"left" }}>
                          <div style={{ fontSize:14, fontWeight:800, color:"rgba(255,255,255,0.92)", marginBottom:2 }}>Upgrade to {nextPlanName}</div>
                          <div style={{ fontSize:11.5, color:"#818CF8" }}>More monthly credits + all premium features</div>
                        </div>
                        <svg viewBox="0 0 16 16" fill="none" stroke="rgba(129,140,248,0.7)" strokeWidth="2.2" style={{ width:14, height:14, flexShrink:0 }}><path d="M6 3l5 5-5 5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                      </button>
                    )}

                    {/* Buy top-up */}
                    <div style={{ borderRadius:14, border:`1px solid ${topupOpen ? "rgba(99,102,241,0.35)" : "rgba(255,255,255,0.09)"}`, background:topupOpen ? "rgba(79,70,229,0.08)" : "rgba(255,255,255,0.03)", overflow:"hidden", transition:"border-color 0.2s, background 0.2s" }}>
                      <button
                        onClick={() => { setTopupOpen(o => !o); setTopupErr(null); }}
                        style={{ display:"flex", alignItems:"center", gap:12, padding:"12px 14px", width:"100%", border:"none", background:"transparent", cursor:"pointer", textAlign:"left" }}>
                        <div style={{ width:38, height:38, borderRadius:11, background:"rgba(99,102,241,0.15)", border:"1px solid rgba(99,102,241,0.25)", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                          <svg viewBox="0 0 24 24" fill="none" stroke="#818CF8" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" style={{ width:16, height:16 }}>
                            <line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/>
                          </svg>
                        </div>
                        <div style={{ flex:1 }}>
                          <div style={{ fontSize:14, fontWeight:800, color:"rgba(255,255,255,0.88)", marginBottom:2 }}>Buy a credit top-up</div>
                          <div style={{ fontSize:11.5, color:"#818CF8" }}>Add 40, 120, or 300 credits instantly</div>
                        </div>
                        <svg viewBox="0 0 16 16" fill="none" stroke="rgba(129,140,248,0.6)" strokeWidth="2.2" style={{ width:14, height:14, flexShrink:0, transform:topupOpen ? "rotate(90deg)" : "none", transition:"transform 0.2s" }}><path d="M6 3l5 5-5 5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                      </button>

                      {topupOpen && (
                        <div style={{ padding:"0 14px 14px", display:"flex", flexDirection:"column", gap:7 }}>
                          {topupErr && (
                            <div style={{ fontSize:11.5, color:"#F87171", background:"rgba(239,68,68,0.1)", border:"1px solid rgba(239,68,68,0.2)", borderRadius:8, padding:"8px 12px", marginBottom:2 }}>{topupErr}</div>
                          )}
                          {([
                            { packId:"40",  credits:40,  price:"$20",  label:"Starter", desc:"Perfect for one-time needs" },
                            { packId:"120", credits:120, price:"$50",  label:"Pro",      desc:"Best value for regular users" },
                            { packId:"300", credits:300, price:"$120", label:"Power",    desc:"Maximum credits at once" },
                          ] as const).map(pack => {
                            const isLoading = topupLoading === pack.packId;
                            return (
                              <button key={pack.packId}
                                disabled={topupLoading !== null}
                                onClick={() => {
                                  setTopupLoading(pack.packId);
                                  setTopupErr(null);
                                  const win = window.open("", "_blank");
                                  if (!win) { setTopupLoading(null); setTopupErr("Popups are blocked — please allow them and try again."); return; }
                                  win.document.write('<html><body style="margin:0;background:#060a1c;display:flex;align-items:center;justify-content:center;height:100vh;font-family:system-ui,sans-serif;color:rgba(255,255,255,0.7);font-size:15px">Preparing your checkout…</body></html>');
                                  fetch("/api/billing/topup", { method:"POST", headers:{"Content-Type":"application/json"}, body: JSON.stringify({ packId: pack.packId }) })
                                    .then(r => r.json())
                                    .then(data => {
                                      if (data.url) { win.location.href = data.url; }
                                      else { win.close(); setTopupErr(data.error || "Something went wrong. Please try again."); }
                                    })
                                    .catch(() => { win.close(); setTopupErr("Network error. Please try again."); })
                                    .finally(() => setTopupLoading(null));
                                }}
                                style={{ display:"flex", alignItems:"center", gap:12, padding:"11px 14px", borderRadius:10, border:`1px solid ${isLoading ? "rgba(99,102,241,0.5)" : "rgba(255,255,255,0.08)"}`, background:isLoading ? "rgba(79,70,229,0.15)" : "rgba(255,255,255,0.03)", cursor: topupLoading !== null ? "default" : "pointer", opacity: topupLoading !== null && !isLoading ? 0.45 : 1, transition:"all 0.15s", width:"100%", textAlign:"left" }}>
                                <div style={{ flex:1 }}>
                                  <div style={{ fontSize:13, fontWeight:800, color:"rgba(255,255,255,0.88)" }}>{pack.label} — {pack.credits} credits</div>
                                  <div style={{ fontSize:11, color:"rgba(255,255,255,0.38)", marginTop:1 }}>{pack.desc}</div>
                                </div>
                                {isLoading
                                  ? <div style={{ width:16, height:16, border:"2px solid rgba(129,140,248,0.3)", borderTopColor:"#818CF8", borderRadius:"50%", animation:"spin-slow 0.7s linear infinite", flexShrink:0 }}/>
                                  : <span style={{ fontSize:14, fontWeight:900, color:"#818CF8", flexShrink:0 }}>{pack.price}</span>
                                }
                              </button>
                            );
                          })}

                          {/* Custom amount */}
                          {(() => {
                            const rawDollars = parseInt(topupCustom, 10);
                            const validDollars = Number.isFinite(rawDollars) && rawDollars >= 5 ? rawDollars : null;
                            const customCredits = validDollars ? validDollars * 2 : null;
                            const isCustomLoading = topupLoading === "custom";
                            return (
                              <div style={{ borderTop:"1px solid rgba(255,255,255,0.06)", paddingTop:8, marginTop:2 }}>
                                <div style={{ fontSize:10.5, fontWeight:700, color:"rgba(255,255,255,0.3)", textTransform:"uppercase", letterSpacing:"0.1em", marginBottom:7 }}>Or enter a custom amount</div>
                                <div style={{ display:"flex", gap:7 }}>
                                  <div style={{ position:"relative", flex:1 }}>
                                    <span style={{ position:"absolute", left:11, top:"50%", transform:"translateY(-50%)", fontSize:14, fontWeight:700, color:"rgba(255,255,255,0.45)", pointerEvents:"none" }}>$</span>
                                    <input
                                      type="number"
                                      min={5}
                                      step={1}
                                      placeholder="5"
                                      value={topupCustom}
                                      onChange={e => setTopupCustom(e.target.value.replace(/[^0-9]/g, ""))}
                                      disabled={topupLoading !== null}
                                      style={{ width:"100%", padding:"10px 10px 10px 26px", borderRadius:9, border:"1px solid rgba(255,255,255,0.1)", background:"rgba(255,255,255,0.04)", color:"rgba(255,255,255,0.88)", fontSize:14, fontWeight:700, outline:"none", boxSizing:"border-box", appearance:"textfield", MozAppearance:"textfield" }}
                                    />
                                  </div>
                                  <button
                                    disabled={!validDollars || topupLoading !== null}
                                    onClick={() => {
                                      if (!validDollars) return;
                                      setTopupLoading("custom");
                                      setTopupErr(null);
                                      const win = window.open("", "_blank");
                                      if (!win) { setTopupLoading(null); setTopupErr("Popups are blocked — please allow them and try again."); return; }
                                      win.document.write('<html><body style="margin:0;background:#060a1c;display:flex;align-items:center;justify-content:center;height:100vh;font-family:system-ui,sans-serif;color:rgba(255,255,255,0.7);font-size:15px">Preparing your checkout…</body></html>');
                                      fetch("/api/billing/topup", { method:"POST", headers:{"Content-Type":"application/json"}, body: JSON.stringify({ customDollars: validDollars }) })
                                        .then(r => r.json())
                                        .then(data => {
                                          if (data.url) { win.location.href = data.url; }
                                          else { win.close(); setTopupErr(data.error || "Something went wrong. Please try again."); }
                                        })
                                        .catch(() => { win.close(); setTopupErr("Network error. Please try again."); })
                                        .finally(() => setTopupLoading(null));
                                    }}
                                    style={{ padding:"10px 14px", borderRadius:9, border:"1px solid rgba(99,102,241,0.4)", background: validDollars ? "linear-gradient(135deg, rgba(37,99,235,0.3) 0%, rgba(79,70,229,0.25) 100%)" : "rgba(255,255,255,0.04)", cursor: validDollars && topupLoading === null ? "pointer" : "default", opacity: validDollars && topupLoading === null ? 1 : 0.4, transition:"all 0.15s", flexShrink:0, display:"flex", alignItems:"center", gap:6 }}>
                                    {isCustomLoading
                                      ? <div style={{ width:14, height:14, border:"2px solid rgba(129,140,248,0.3)", borderTopColor:"#818CF8", borderRadius:"50%", animation:"spin-slow 0.7s linear infinite" }}/>
                                      : <svg viewBox="0 0 16 16" fill="none" stroke="#818CF8" strokeWidth="2" style={{ width:14, height:14 }}><path d="M3 8h10M9 4l4 4-4 4" strokeLinecap="round" strokeLinejoin="round"/></svg>
                                    }
                                    <span style={{ fontSize:12, fontWeight:800, color:"#818CF8", whiteSpace:"nowrap" }}>
                                      {customCredits ? `${customCredits} cr` : "Buy"}
                                    </span>
                                  </button>
                                </div>
                                {validDollars && (
                                  <div style={{ fontSize:10.5, color:"rgba(255,255,255,0.28)", marginTop:5, textAlign:"center" }}>
                                    ${validDollars} → {customCredits} credits added to your account
                                  </div>
                                )}
                              </div>
                            );
                          })()}
                        </div>
                      )}
                    </div>

                    {/* Wait — informational (hidden in proactive mode) */}
                    {!proactive && <div style={{ display:"flex", alignItems:"center", gap:12, padding:"12px 14px", borderRadius:12, border:"1px solid rgba(255,255,255,0.1)", background:"rgba(255,255,255,0.04)", textAlign:"left" }}>
                      <div style={{ width:34, height:34, borderRadius:10, background:"rgba(255,255,255,0.07)", border:"1px solid rgba(255,255,255,0.11)", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                        <svg viewBox="0 0 24 24" fill="none" stroke="rgba(255,255,255,0.55)" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" style={{ width:15, height:15 }}>
                          <circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/>
                        </svg>
                      </div>
                      <div style={{ flex:1 }}>
                        <div style={{ fontSize:13, fontWeight:600, color:"rgba(255,255,255,0.65)", marginBottom:1 }}>Wait for next billing cycle</div>
                        <div style={{ fontSize:11, color:"rgba(255,255,255,0.42)" }}>Credits reset automatically — access resumes then</div>
                      </div>
                    </div>}

                  </div>

                  {/* Footer */}
                  <div style={{ fontSize:11, color:"rgba(255,255,255,0.3)", lineHeight:1.6, marginTop:14 }}>
                    Questions?{" "}
                    <a href="/settings/subscription" target="_blank" rel="noopener noreferrer" style={{ color:"rgba(129,140,248,0.7)", fontWeight:600, textDecoration:"none" }}>Manage subscription ↗</a>
                  </div>

                </div>
              </div>
            </div>
          </div>
        );
      })()}

      {hasPaymentIssue && (
        <div style={{ flexShrink:0, background:"linear-gradient(90deg, #DC2626 0%, #B91C1C 100%)", color:"white", padding:"8px 20px", display:"flex", alignItems:"center", gap:10, fontSize:13, fontWeight:500, zIndex:100 }}>
          <svg viewBox="0 0 16 16" fill="none" stroke="white" strokeWidth="1.8" style={{width:14,height:14,flexShrink:0}}><circle cx="8" cy="8" r="7"/><path d="M8 5v3M8 10.5v.5"/></svg>
          <span>
            <strong>Payment issue — </strong>
            {viewer.subscriptionStatus === "past_due" ? "Your last payment failed." : viewer.subscriptionStatus === "unpaid" ? "Your subscription is unpaid." : "Your payment is being processed."}
            {" "}
            <a href="/settings/subscription" style={{color:"white", fontWeight:700, textDecoration:"underline"}}>Manage billing →</a>
          </span>
        </div>
      )}
    <div style={{ display:"flex", flex:1, overflow:"hidden" }}>
      <style>{`
        @keyframes blink { 0%,100%{opacity:1} 50%{opacity:0.15} }
        @keyframes bubble-appear { from{opacity:0;transform:translateY(8px)} to{opacity:1;transform:translateY(0)} }
        @keyframes dot-bounce { 0%,80%,100%{transform:translateY(0)} 40%{transform:translateY(-6px)} }
        @keyframes voice-wave { from{height:3px} to{height:100%} }
        @keyframes sphere-breathe { 0%,100%{transform:scale(1)} 50%{transform:scale(1.04)} }
        @keyframes spin-slow { from{transform:rotate(0deg)} to{transform:rotate(360deg)} }
        @keyframes spin-arc { from{transform:translate(-50%,-50%) rotate(0deg)} to{transform:translate(-50%,-50%) rotate(360deg)} }
        @keyframes aurora-pulse { 0%,100%{opacity:0.8} 50%{opacity:1} }
        @keyframes neural-orbit-a { from{transform:rotate(0deg) translate(28px)} to{transform:rotate(360deg) translate(28px)} }
        @keyframes neural-orbit-b { from{transform:rotate(0deg) translate(20px)} to{transform:rotate(360deg) translate(20px)} }
        @keyframes ring-pulse { 0%{transform:translate(-50%,-50%) scale(1);opacity:0.6} 100%{transform:translate(-50%,-50%) scale(1.5);opacity:0} }
        @keyframes listen-ripple { 0%{transform:scale(1);opacity:0.5} 100%{transform:scale(1.8);opacity:0} }
        @keyframes listen-ripple-v2 { 0%{transform:translate(-50%,-50%) scale(1);opacity:0.65} 100%{transform:translate(-50%,-50%) scale(1.7);opacity:0} }
        @keyframes bar-eq { 0%,100%{height:3px} 50%{height:22px} }
        @keyframes eye-glow { 0%,100%{opacity:0.9} 50%{opacity:0.6} }
        @keyframes aurora-a { 0%,100%{transform:translate(-50%,0) scale(1)} 50%{transform:translate(-50%,10px) scale(1.05)} }
        @keyframes aurora-b { 0%,100%{transform:translate(0,0) scale(1)} 60%{transform:translate(-20px,15px) scale(1.04)} }
        @keyframes aurora-c { 0%,100%{transform:translate(0,0) scale(1)} 40%{transform:translate(10px,-10px) scale(1.03)} }
        @keyframes nav-glow { 0%,100%{box-shadow:0 0 12px rgba(255,255,255,0.04)} 50%{box-shadow:0 0 20px rgba(255,255,255,0.08)} }
        @keyframes sidebar-shimmer { 0%{opacity:0.4} 50%{opacity:0.7} 100%{opacity:0.4} }
        @keyframes live-ring-out { 0%{transform:translate(-50%,-50%) scale(1);opacity:0.6} 100%{transform:translate(-50%,-50%) scale(2.2);opacity:0} }
        @keyframes live-msg-in { from{opacity:0;transform:translateY(10px)} to{opacity:1;transform:translateY(0)} }
        @keyframes screen-slide-in { from{opacity:0;transform:translateY(10px)} to{opacity:1;transform:translateY(0)} }
        @keyframes fade-up { from{opacity:0;transform:translateY(12px)} to{opacity:1;transform:translateY(0)} }
        @keyframes card-in { from{opacity:0;transform:translateY(8px) scale(0.99)} to{opacity:1;transform:translateY(0) scale(1)} }
        @keyframes shimmer-sweep { 0%{background-position:-400px 0} 100%{background-position:400px 0} }
        @keyframes upgrade-pulse { 0%,100%{box-shadow:0 0 0 0 rgba(37,99,235,0)} 50%{box-shadow:0 0 0 3px rgba(37,99,235,0.15)} }
        * { -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; text-rendering: optimizeLegibility; }
        textarea::placeholder, input::placeholder { color: var(--z-text3); opacity: 1; }
        .zari-nav-btn { position: relative; overflow: hidden; }
        .zari-nav-btn:hover { background: rgba(37,99,235,0.06) !important; color: var(--z-text) !important; }
        .zari-nav-btn.active { color: #2563EB !important; }
        .zari-dark .zari-nav-btn:hover { background: rgba(255,255,255,0.05) !important; color: rgba(255,255,255,0.85) !important; }
        .zari-dark .zari-nav-btn.active { background: transparent !important; }
        .zari-card-lift { transition: transform 0.18s cubic-bezier(0.4,0,0.2,1), box-shadow 0.18s cubic-bezier(0.4,0,0.2,1) !important; cursor: pointer; }
        .zari-card-lift:hover { transform: translateY(-2px) !important; box-shadow: 0 10px 28px var(--z-sh) !important; }
        .zari-btn-scale { transition: transform 0.15s ease, box-shadow 0.15s ease !important; }
        .zari-btn-scale:hover { transform: scale(1.02) !important; }
        .zari-btn-scale:active { transform: scale(0.98) !important; }
        .zari-screen-active { animation: screen-slide-in 0.32s cubic-bezier(0.4,0,0.2,1); }
        .zari-stage-opt:hover { background: rgba(37,99,235,0.07) !important; }
        .zari-dark .zari-stage-opt:hover { background: rgba(255,255,255,0.06) !important; }
        ::-webkit-scrollbar { width: 4px; height: 4px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: var(--z-bd); border-radius: 99px; }
        ::-webkit-scrollbar-thumb:hover { background: var(--z-text3); }
        @media (max-width: 767px) {
          .zari-sidebar { position:fixed !important; left:0; top:0; bottom:0; z-index:200; transform:translateX(-100%); transition:transform 0.28s cubic-bezier(0.4,0,0.2,1); box-shadow:4px 0 32px rgba(0,0,0,0.18) !important; }
          .zari-sidebar.open { transform:translateX(0) !important; }
          .zari-mobile-overlay { display:flex !important; }
          .zari-bottom-nav { display:flex !important; }
          .zari-topbar-hamburger { display:flex !important; }
          .zari-main { padding-bottom:60px !important; }
        }
        .zari-mobile-overlay { display:none; position:fixed; inset:0; background:rgba(0,0,0,0.45); z-index:199; backdrop-filter:blur(2px); }
        .zari-bottom-nav { display:none; position:fixed; bottom:0; left:0; right:0; height:58px; background:var(--z-card); border-top:1px solid var(--z-bd); z-index:100; align-items:stretch; }
        .zari-bottom-nav-btn { flex:1; display:flex; flex-direction:column; align-items:center; justify-content:center; gap:3px; background:none; border:none; cursor:pointer; font-size:10px; font-weight:600; color:var(--z-text3); transition:color 0.14s; padding:0; }
        .zari-bottom-nav-btn.active { color:#2563EB; }
        .zari-topbar-hamburger { display:none; align-items:center; justify-content:center; width:34px; height:34px; border-radius:9px; border:1px solid var(--z-bd); background:transparent; cursor:pointer; color:var(--z-text2); margin-right:4px; }
      `}</style>

      {/* Mobile sidebar overlay */}
      {sidebarOpen && <div className="zari-mobile-overlay" onClick={() => setSidebarOpen(false)} />}

      {/* ── SIDEBAR ── */}
      <aside className={`zari-sidebar${sidebarOpen ? " open" : ""}`} style={{ width:244, flexShrink:0, background:"var(--z-card)", display:"flex", flexDirection:"column", padding:"0 0 16px", position:"relative", borderRight:"1px solid var(--z-bd)", overflow:"hidden" }}>
        {/* Dark mode ambient glow */}
        {isDark && <div style={{ position:"absolute", top:-40, left:-20, width:180, height:180, borderRadius:"50%", background:"radial-gradient(circle, rgba(37,99,235,0.12) 0%, transparent 70%)", pointerEvents:"none" }}/>}

        {/* Logo + user */}
        <div style={{ padding:"18px 16px 14px", display:"flex", alignItems:"center", gap:10, position:"relative" }}>
          <Link href="/" style={{ display:"flex", alignItems:"center", gap:9, textDecoration:"none", flex:1 }}>
            <div style={{ width:34, height:34, borderRadius:10, background:"linear-gradient(135deg, #3B82F6 0%, #2563EB 100%)", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, boxShadow: isDark ? "0 0 18px rgba(37,99,235,0.5), 0 2px 8px rgba(0,0,0,0.4)" : "0 2px 10px rgba(37,99,235,0.35)" }}>
              <ZariLogo size={16}/>
            </div>
            <span style={{ fontSize:17, fontWeight:800, color:"var(--z-text)", letterSpacing:"-0.04em", lineHeight:1 }}>Zari</span>
          </Link>
          <button onClick={toggleDark} title={isDark?"Light mode":"Dark mode"} style={{ width:30, height:30, borderRadius:8, border:"1px solid var(--z-bd)", background: isDark ? "rgba(255,255,255,0.04)" : "var(--z-raise)", color:"var(--z-text3)", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, transition:"all 0.18s" }}>
            {isDark ? (
              <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.8" style={{width:14,height:14}}><circle cx="10" cy="10" r="4"/><path d="M10 2v2M10 16v2M2 10h2M16 10h2M4.93 4.93l1.41 1.41M13.66 13.66l1.41 1.41M4.93 15.07l1.41-1.41M13.66 6.34l1.41-1.41"/></svg>
            ) : (
              <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.8" style={{width:14,height:14}}><path d="M17.5 12.5A7.5 7.5 0 1 1 7.5 2.5a5.83 5.83 0 0 0 10 10z"/></svg>
            )}
          </button>
        </div>

        {/* Career Stage Selector */}
        <div style={{ margin:"0 10px 10px", position:"relative" }}>
          <div style={{ padding:"0 2px 5px", fontSize:10.5, color:"var(--z-text3)", fontWeight:500, letterSpacing:"0.01em" }}>
            Your stage customizes every Zari tool for your specific goal.
          </div>
          <button
            onClick={() => setStageOpen(o => !o)}
            style={{ width:"100%", display:"flex", alignItems:"center", gap:8, padding:"9px 12px", borderRadius:10, border:"1px solid var(--z-bd)", background: isDark ? "rgba(255,255,255,0.03)" : "var(--z-raise)", cursor:"pointer", fontSize:12.5, fontWeight:600, color:"var(--z-text2)", transition:"all 0.18s", backdropFilter: isDark ? "blur(8px)" : "none" }}
          >
            <span style={{ display:"flex", alignItems:"center", color: STAGE_META[stage].color }}>{STAGE_ICONS[stage]}</span>
            <span style={{ flex:1, textAlign:"left", color:"var(--z-text)", fontWeight:700 }}>{STAGE_META[stage].label}</span>
            <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" style={{ width:11,height:11, transition:"transform 0.22s cubic-bezier(0.4,0,0.2,1)", transform:stageOpen?"rotate(180deg)":"rotate(0)", opacity:0.35 }}><path d="M4 6l4 4 4-4"/></svg>
          </button>
          {stageOpen && (
            <div style={{ position:"absolute", top:"calc(100% + 6px)", left:0, right:0, zIndex:50, background: isDark ? "rgba(8,14,28,0.96)" : "var(--z-card)", borderRadius:12, border:"1px solid var(--z-bd)", boxShadow: isDark ? "0 20px 60px rgba(0,0,0,0.7), 0 0 0 1px rgba(255,255,255,0.05)" : "0 16px 48px rgba(0,0,0,0.13)", overflow:"hidden", animation:"bubble-appear 0.2s ease", backdropFilter:"blur(16px)" }}>
              {(Object.entries(STAGE_META) as [CareerStage, typeof STAGE_META[CareerStage]][]).map(([key, meta]) => (
                <button key={key} onClick={() => selectStage(key)}
                  className="zari-stage-opt"
                  style={{ width:"100%", display:"flex", alignItems:"center", gap:9, padding:"10px 13px", border:"none", cursor:"pointer", textAlign:"left", background:stage===key ? (isDark ? "rgba(37,99,235,0.12)" : "rgba(37,99,235,0.06)") :"transparent", fontSize:13, fontWeight:stage===key?700:500, color:stage===key ? meta.color : "var(--z-text2)", transition:"background 0.12s", borderBottom:"1px solid var(--z-bd2)", borderLeft: stage===key ? `3px solid ${meta.color}` : "3px solid transparent" }}>
                  <span style={{ display:"flex", alignItems:"center", color: meta.color, opacity: stage===key ? 1 : 0.7 }}>{STAGE_ICONS[key]}</span>
                  {meta.label}
                  {stage===key && <svg viewBox="0 0 16 16" style={{ width:11,height:11,marginLeft:"auto", flexShrink:0 }}><path d="M3 8l4 4 6-6" stroke={meta.color} strokeWidth="2.2" fill="none"/></svg>}
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Chat CTA */}
        <div style={{ padding:"0 10px 10px" }}>
          <button onClick={()=>navigate("session")} className="zari-btn-scale"
            style={{ width:"100%", display:"flex", alignItems:"center", gap:9, padding:"10px 14px", borderRadius:10, border:"none", background: screen==="session" ? "linear-gradient(135deg, #3B82F6 0%, #2563EB 100%)" : isDark ? "rgba(37,99,235,0.14)" : "#EFF6FF", color:screen==="session"?"white":"#2563EB", fontWeight:700, fontSize:13.5, cursor:"pointer", letterSpacing:"-0.01em", boxShadow: screen==="session" ? "0 4px 16px rgba(37,99,235,0.45)" : "none" }}>
            <svg viewBox="0 0 18 18" fill="none" stroke="currentColor" strokeWidth="1.9" style={{width:15,height:15,flexShrink:0}}><path d="M3 3h12a1 1 0 011 1v7a1 1 0 01-1 1H6l-4 3V4a1 1 0 011-1z"/></svg>
            Chat with Zari
          </button>
        </div>

        <div style={{ height:1, margin:"0 10px 10px", background: isDark ? "linear-gradient(90deg, transparent, var(--z-bd), transparent)" : "var(--z-bd)" }}/>

        {/* Nav — grouped like Kleo */}
        <nav style={{ flex:1, padding:"0 8px", display:"flex", flexDirection:"column", gap:1, overflowY:"auto" }}>
          {(() => {
            const nav = getNav(stage).filter(n => n.id !== "session");
            const groups: { label: string; ids: string[] }[] = [
              { label:"Tools", ids:["resume","interview","cover-letter","linkedin"] },
              { label:"Workspace", ids:["documents","plan"] },
            ];
            return groups.map(g => {
              const items = nav.filter(n => g.ids.includes(n.id));
              if (!items.length) return null;
              return (
                <div key={g.label}>
                  <div style={{ padding:"8px 8px 4px", fontSize:10, fontWeight:700, color:"var(--z-text3)", letterSpacing:"0.1em", textTransform:"uppercase" }}>{g.label}</div>
                  {items.map(n => {
                    const isActive = screen === n.id;
                    const itemColor = SCREEN_ACCENTS[n.id]?.color ?? "#2563EB";
                    const activeBg = isDark
                      ? `linear-gradient(90deg, ${itemColor}22 0%, transparent 100%)`
                      : `linear-gradient(90deg, ${itemColor}12 0%, transparent 100%)`;
                    return (
                      <button key={n.id} onClick={()=>navigate(n.id as Screen)} className={`zari-nav-btn${isActive?" active":""}`}
                        style={{ width:"100%", display:"flex", alignItems:"center", gap:9, padding:"8px 10px", borderRadius:8, border:"none", cursor:"pointer", textAlign:"left", background:isActive ? activeBg : "transparent", color:isActive ? itemColor : "var(--z-text2)", fontWeight:isActive?600:400, fontSize:13.5, transition:"all 0.14s", boxShadow: isActive ? `inset 3px 0 0 ${itemColor}` : "inset 3px 0 0 transparent" }}>
                        <span style={{ display:"flex", alignItems:"center", color: isActive ? itemColor : "var(--z-text3)", transition:"color 0.14s" }}>{n.icon}</span>
                        {n.label}
                      </button>
                    );
                  })}
                </div>
              );
            });
          })()}
        </nav>

        {/* Bottom: account nav button + sign out */}
        <div style={{ margin:"8px 10px 0", display:"flex", flexDirection:"column", gap:4 }}>
          {(() => {
            const isAcct = screen === "account";
            const acctInitials = (viewer.name?.trim() || viewer.email).split(/\s+/).slice(0,2).map(p=>p[0]?.toUpperCase()??"").join("") || "?";
            return (
              <button
                onClick={() => navigate("account")}
                style={{ width:"100%", display:"flex", alignItems:"center", gap:10, padding:"10px 11px", borderRadius:10, border: isAcct ? "1px solid rgba(37,99,235,0.3)" : "1px solid var(--z-bd)", background: isAcct ? (isDark ? "rgba(37,99,235,0.14)" : "#EFF6FF") : (isDark ? "rgba(255,255,255,0.03)" : "var(--z-raise)"), cursor:"pointer", textAlign:"left", transition:"all 0.15s", boxShadow: isAcct ? "inset 3px 0 0 #2563EB" : "inset 3px 0 0 transparent" }}
              >
                <div style={{ width:32, height:32, borderRadius:9, background:"linear-gradient(135deg, #3B82F6, #2563EB)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:12, fontWeight:800, color:"white", flexShrink:0 }}>
                  {acctInitials}
                </div>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontSize:12.5, fontWeight:700, color: isAcct ? "#2563EB" : "var(--z-text)", lineHeight:1.2, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{userDisplayName}</div>
                  <div style={{ fontSize:11, color:"var(--z-text3)", lineHeight:1.3, marginTop:1, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                    {isOperatorViewer ? "Operator · full access" : sidebarPlanTitle}
                  </div>
                </div>
                <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" style={{ width:10, height:10, flexShrink:0, opacity:0.3 }}><path d="M6 4l4 4-4 4"/></svg>
              </button>
            );
          })()}
          <PlatformLogoutButton className="" redirectTo="/login">
            <button style={{ width:"100%", display:"flex", alignItems:"center", gap:7, padding:"7px 11px", borderRadius:9, border:"1px solid var(--z-bd)", background:"transparent", cursor:"pointer", color:"var(--z-text3)", fontSize:12, fontWeight:500, transition:"all 0.14s" }}>
              <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.8" style={{ width:12, height:12, flexShrink:0 }}><path d="M10 11l4-3-4-3M14 8H6M6 3H3a1 1 0 00-1 1v8a1 1 0 001 1h3" strokeLinecap="round" strokeLinejoin="round"/></svg>
              Sign out
            </button>
          </PlatformLogoutButton>
        </div>
      </aside>

      {/* ── MAIN CONTENT ── */}
      <main className="zari-main" style={{ flex:1, overflow:"hidden", display:"flex", flexDirection:"column" }}>
        {/* Top bar */}
        <div style={{ flexShrink:0, height:54, background:"var(--z-card)", borderBottom:"1px solid var(--z-bd)", display:"flex", alignItems:"center", padding:"0 16px 0 12px", gap:8, position:"relative" }}>
          {/* Accent line */}
          <div style={{ position:"absolute", bottom:0, left:0, height:2, width:"100%", background:`linear-gradient(90deg, ${accentInfo.color}70 0%, ${accentInfo.color}20 40%, transparent 100%)`, pointerEvents:"none" }}/>
          {/* Hamburger — mobile only */}
          <button className="zari-topbar-hamburger" onClick={() => setSidebarOpen(o => !o)}>
            <svg viewBox="0 0 18 18" fill="none" stroke="currentColor" strokeWidth="1.8" style={{width:16,height:16}}><path d="M2 4h14M2 9h14M2 14h14"/></svg>
          </button>
          <h2 style={{ fontSize:15, fontWeight:700, color:"var(--z-text)", letterSpacing:"-0.02em", margin:0, flex:1 }}>
            {STAGE_NAV_LABELS[stage][screen]}
          </h2>
          <div style={{ marginLeft:"auto", display:"flex", gap:8, alignItems:"center" }}>
            <div style={{ display:"flex", alignItems:"center", gap:6, padding:"4px 11px 4px 9px", borderRadius:99, background: isDark ? `${accentInfo.color}18` : `${accentInfo.color}10`, border:`1px solid ${accentInfo.color}30` }}>
              <span style={{ display:"inline-flex", alignItems:"center", color: accentInfo.color }}>{STAGE_ICONS[stage]}</span>
              <span style={{ fontSize:11.5, fontWeight:600, color: accentInfo.color }}>{STAGE_META[stage].label}</span>
            </div>
            <button onClick={()=>navigate("account")} style={{ minWidth:0, maxWidth:240, display:"flex", flexDirection:"column", alignItems:"flex-end", padding:"6px 10px", borderRadius:10, border: screen==="account" ? "1px solid rgba(37,99,235,0.3)" : "1px solid var(--z-bd)", background:isDark ? "rgba(255,255,255,0.03)" : "var(--z-raise)", cursor:"pointer", transition:"all 0.15s" }}>
              <div style={{ fontSize:12.5, fontWeight:700, color: screen==="account" ? "#2563EB" : "var(--z-text)", lineHeight:1.2, maxWidth:"100%", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{userDisplayName}</div>
              <div style={{ fontSize:11, color:"var(--z-text2)", lineHeight:1.2, maxWidth:"100%", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{userEmail}</div>
            </button>
          </div>
        </div>

        {/* Screen — all kept mounted, hidden when inactive to preserve state */}
        <div style={{ flex:1, overflow:"hidden", position:"relative" }}>
          {!hydrated ? (
            <div style={{ height:"100%", display:"flex", flexDirection:"column", gap:14, padding:"32px 40px" }}>
              {[0.85, 0.5, 0.65, 0.4, 0.55].map((w, i) => (
                <div key={i} style={{ height: i===0 ? 72 : 20, borderRadius:10, background:"var(--z-raise)", opacity:0.6, maxWidth:`${w*100}%`, animation:`pulse 1.4s ${i*0.12}s ease-in-out infinite` }} />
              ))}
            </div>
          ) : (
            <>
              <div className={screen==="session"      ? "zari-screen-active" : ""} style={{ display:screen==="session"      ? "block" : "none", height:"100%" }}><FeatureGate featureName="zari_chat"><ScreenSession stage={stage} onNavigate={navigate}/></FeatureGate></div>
              <div className={screen==="resume"       ? "zari-screen-active" : ""} style={{ display:screen==="resume"       ? "block" : "none", height:"100%" }}><ScreenResume       stage={stage} onNavigate={s=>navigate(s as Screen)}/></div>
              <div className={screen==="interview"    ? "zari-screen-active" : ""} style={{ display:screen==="interview"    ? "block" : "none", height:"100%" }}>{stage==="career-change" ? <FeatureGate featureName="zari_pivot_story"><ScreenPivotStoryBuilder active={screen==="interview"}/></FeatureGate> : <ScreenInterview    stage={stage} active={screen==="interview"} onNavigate={s=>navigate(s as Screen)}/>}</div>
              <div className={screen==="cover-letter" ? "zari-screen-active" : ""} style={{ display:screen==="cover-letter" ? "block" : "none", height:"100%" }}>{stage==="career-change" ? <FeatureGate featureName="zari_credibility_sprint"><ScreenCredibilitySprint active={screen==="cover-letter"}/></FeatureGate> : <ScreenCoverLetter stage={stage} active={screen==="cover-letter"} onNavigate={s=>navigate(s as Screen)}/>}</div>
              <div className={screen==="linkedin"     ? "zari-screen-active" : ""} style={{ display:screen==="linkedin"     ? "block" : "none", height:"100%" }}>{stage==="career-change" ? <FeatureGate featureName="zari_bridge_network"><ScreenBridgeNetwork active={screen==="linkedin"}/></FeatureGate> : <ScreenLinkedIn     stage={stage} active={screen==="linkedin"} onNavigate={s=>navigate(s as Screen)}/>}</div>
              <div className={screen==="documents"    ? "zari-screen-active" : ""} style={{ display:screen==="documents"    ? "block" : "none", height:"100%" }}><ScreenDocuments stage={stage} onNavigate={s=>navigate(s as Screen)}/></div>
              <div className={screen==="plan"         ? "zari-screen-active" : ""} style={{ display:screen==="plan"         ? "block" : "none", height:"100%" }}><ScreenPlan stage={stage} onNavigate={s=>navigate(s as Screen)} active={screen==="plan"}/></div>
              <div className={screen==="account"      ? "zari-screen-active" : ""} style={{ display:screen==="account"      ? "block" : "none", height:"100%" }}><ScreenAccount viewer={viewer} onNavigate={navigate} onBuyCredits={() => { const used = viewer.usedMonthlyCredits ?? 0; const limit = viewer.creditLimit ?? viewer.includedMonthlyCredits ?? 0; setCreditLimitNotice({ used, limit, proactive: true }); setTopupOpen(true); }} onComparePlans={() => setComparePlansOpen(true)}/></div>
            </>
          )}
        </div>

        {/* Mobile bottom nav */}
        <nav className="zari-bottom-nav">
          {([
            { id:"session",      icon:<svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.7" style={{width:20,height:20}}><path d="M10 2a3 3 0 00-3 3v4a3 3 0 006 0V5a3 3 0 00-3-3z"/><path d="M4 9v1a6 6 0 0012 0V9"/><line x1="10" y1="15" x2="10" y2="18"/></svg>, label:"Chat" },
            { id:"resume",       icon:<svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.7" style={{width:20,height:20}}><rect x="3" y="2" width="14" height="16" rx="2"/><path d="M7 7h6M7 10h6M7 13h4"/></svg>, label:"Resume" },
            { id:"interview",    icon:<svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.7" style={{width:20,height:20}}><circle cx="10" cy="6" r="3"/><path d="M3 17c0-3.866 3.134-6 7-6s7 2.134 7 6"/></svg>, label:"Interview" },
            { id:"documents",    icon:<svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.7" style={{width:20,height:20}}><path d="M5 2h7l4 4v12a1 1 0 01-1 1H5a1 1 0 01-1-1V3a1 1 0 011-1z"/><path d="M12 2v4h4"/></svg>, label:"Docs" },
            { id:"account",      icon:<svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.7" style={{width:20,height:20}}><circle cx="10" cy="7" r="3.5"/><path d="M3 17c0-3.314 3.134-5.5 7-5.5s7 2.186 7 5.5"/></svg>, label:"Account" },
          ] as { id: Screen; icon: React.ReactNode; label: string }[]).map(item => (
            <button key={item.id} className={`zari-bottom-nav-btn${screen===item.id?" active":""}`} onClick={()=>navigate(item.id)}>
              {item.icon}
              <span>{item.label}</span>
            </button>
          ))}
        </nav>
      </main>
    </div>
    </div>
    </BillingContext.Provider>
  );
}
